-- Poems batch 116
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('b3e55ebe-1b41-4e37-8e2a-67332e1149e9','軍中雜歌八首  其八','陸游','宋','宋诗','song-poetry','','[]','北庭茫茫秋草枯，正東萬里是皇都。',32,'全唐诗/poet.song.129000.json','["北庭茫茫秋草枯，正東萬里是皇都。", "征人樓上看太白，思婦城南迎紫姑。"]'),
('88aa41d1-bbcd-4f87-804c-7d842842e43c','夏夜舟中聞水鳥聲甚哀若曰姑惡感而作詩','陸游','宋','宋诗','song-poetry','','[]','女生藏深閨，未省窺牆藩。',144,'全唐诗/poet.song.129000.json','["女生藏深閨，未省窺牆藩。", "上車移所天，父母爲它門。", "妾身雖甚愚，亦知君姑尊。", "下床頭雞鳴，梳髻著襦裙。", "堂上奉灑掃，厨中具盤飱。", "青青摘葵莧，恨不美熊蹯。", "姑色少不怡，衣袂濕泪痕。", "所冀妾生男，庶幾姑弄孫。", "此志竟蹉跎，薄命来讒言。", "放棄不敢怨，所悲孤大恩。", "古路傍陂澤，微雨鬼火昏。", "君聽姑惡聲，無乃譴婦魂。"]'),
('3dc131ca-0cc2-4055-a260-f93b11629946','暮歸舟中二首  其一','陸游','宋','宋诗','song-poetry','','[]','五月未劇暑，暮從城市還。',48,'全唐诗/poet.song.129000.json','["五月未劇暑，暮從城市還。", "斷虹低飲澗，落日遠衘山。", "蠏舍叢蘆外，菱舟薄靄間。", "詩情終草草，虛遣鬢毛斑。"]'),
('c5957331-4766-458c-ac63-306012b6af77','暮歸舟中二首  其二','陸游','宋','宋诗','song-poetry','','[]','湖水綠可愛，弄橈衝夕霏。',48,'全唐诗/poet.song.129000.json','["湖水綠可愛，弄橈衝夕霏。", "林昏漁火壯，山轉寺鐘微。", "老嘆世情惡，窮知心事違。", "回頭語孤鶴，伴我莫先飛。"]'),
('02d90354-961b-4488-82a2-bb8d9d8bf032','夏夜四首  其一','陸游','宋','宋诗','song-poetry','','[]','夏夜忽已半，東岡月初生。',48,'全唐诗/poet.song.129000.json','["夏夜忽已半，東岡月初生。", "起行遶庭樹，愛此露滴聲。", "漂流憶安臥，局促念遐征。", "幽懷誰晤語，華觴還自傾。"]'),
('35d95114-5d82-4399-9b3c-c7c03682355c','夏夜四首  其二','陸游','宋','宋诗','song-poetry','','[]','螢火喜暗庭，桐葉矜冷雨。',48,'全唐诗/poet.song.129000.json','["螢火喜暗庭，桐葉矜冷雨。", "幽人悄不寐，獨夜誰與處。", "乾坤信無情，歲月遽如許。", "明發視鏡中，鬢絲添幾縷。"]'),
('fb96e04a-9a99-4aea-bcc4-de0db8f7d593','夏夜四首  其三','陸游','宋','宋诗','song-poetry','','[]','庭荒蔓草長，堂豁爽氣入。',48,'全唐诗/poet.song.129000.json','["庭荒蔓草長，堂豁爽氣入。", "悠然推枕起，聊作倚杖立。", "飛螢亦避雨，黏棟光熠熠。", "南鄰輸税歸，小婦愁夜汲。"]'),
('5d8ba195-372e-4627-b0af-2b2f2d8a5c81','夏夜四首  其四','陸游','宋','宋诗','song-poetry','','[]','結屋在郊墟，翛然謝炎熾。',48,'全唐诗/poet.song.129000.json','["結屋在郊墟，翛然謝炎熾。", "窗扉故闃寂，水竹亦幽邃。", "飛蟲望燈集，栖燕衝雨至。", "石枕與葛幮，美哉今夕睡。"]'),
('795fefee-8609-4f9d-9bc9-f092e295df43','北渚','陸游','宋','宋诗','song-poetry','','[]','北渚露濃蘋葉老，南塘雨過藕花稀。',64,'全唐诗/poet.song.129000.json','["北渚露濃蘋葉老，南塘雨過藕花稀。", "新秋漸近蟬更急，殘日已沉鴉未歸。", "銅鏡面顔無藥駐，玉關勲業與心違。", "一蓑一笠生涯在，且醉蒼苔舊釣磯。"]'),
('d278aee5-c6c6-4ebf-bc90-d0f59a7095af','夏日五鼓起戲書','陸游','宋','宋诗','song-poetry','','[]','老雞喔喔桑樹顛，明星磊磊茅屋邊。',64,'全唐诗/poet.song.129000.json','["老雞喔喔桑樹顛，明星磊磊茅屋邊。", "我興視夜不復眠，坐看朝暾浴虞淵。", "開窗清風来穆然，拂几洗研整蠧編。", "火雲崔嵬忽滿天，安得羲和徐著鞭。"]'),
('65601ef5-8f5e-4763-b534-0a82b8a33758','雨夜','陸游','宋','宋诗','song-poetry','','[]','急雨如河瀉瓦溝，空堂臥對一燈幽。',64,'全唐诗/poet.song.129000.json','["急雨如河瀉瓦溝，空堂臥對一燈幽。", "老雞多事彊知曉，落葉無情先報秋。", "身未蓋棺誰可料，尊常有酒莫閑愁。", "功名老大從来事，且復長歌起飯牛。"]'),
('5125dc83-fcfe-4497-a713-0fca90f75523','小立','陸游','宋','宋诗','song-poetry','','[]','曠懷塵事外，小立緑陰間。',48,'全唐诗/poet.song.129000.json','["曠懷塵事外，小立緑陰間。", "舉世皆嫌拙，平生剩得閑。", "江郊雲易暗，旱歲雨終慳。", "欲醉尊無酒，悠然對暮山。"]'),
('c184902f-c7a8-4cfc-b76d-3ee2d7b122be','徙倚','陸游','宋','宋诗','song-poetry','','[]','漁扉夕不掩，徙倚欲三更。',48,'全唐诗/poet.song.129000.json','["漁扉夕不掩，徙倚欲三更。", "月正樹無影，露濃荷有聲。", "崢嶸歲將晚，悄愴恨難平。", "坐念中原沒，男兒恐浪生。"]'),
('1f683f3d-5bdc-495a-9a4a-899e17afa303','居山','陸游','宋','宋诗','song-poetry','','[]','涉世緣雖薄，居山味自長。',48,'全唐诗/poet.song.129000.json','["涉世緣雖薄，居山味自長。", "穿雲雙履濕，洗藥一溪香。", "有酒作臉纈，無愁供鬢霜。", "遼天渺歸鶴，千載付茫茫。"]'),
('c0740a23-47d0-4be2-8562-54b8f0d73330','秋興二首  其一','陸游','宋','宋诗','song-poetry','','[]','白髮蕭蕭欲滿頭，歸来三見故山秋。',64,'全唐诗/poet.song.129000.json','["白髮蕭蕭欲滿頭，歸来三見故山秋。", "醉憑高閣乾坤大，病入中年日月遒。", "百戰鐵衣空許國，五更畫角只生愁。", "明朝烟雨桐江岸，且占丹楓繫釣舟。"]'),
('3cd104d6-3aa2-4728-b89c-e18525502b4f','秋興二首  其二','陸游','宋','宋诗','song-poetry','','[]','暮境何堪與病遭，西風落葉擁亭皋。',64,'全唐诗/poet.song.129000.json','["暮境何堪與病遭，西風落葉擁亭皋。", "極知世上人情惡，且放江邊醉眼高。", "應俗紛紛何日了，詠詩混混寄吾豪。", "碧油金鎖平生意，未許人言學楚騷。"]'),
('abaeb3ca-5a57-45c3-a8af-743178924954','八月五日夜半起飲酒作草書數紙','陸游','宋','宋诗','song-poetry','','[]','有漏神仙有髮僧，碧幮欹枕對秋燈。',32,'全唐诗/poet.song.129000.json','["有漏神仙有髮僧，碧幮欹枕對秋燈。", "忽然起索三升酒，颯颯蛟龍入剡藤。"]'),
('e33056cf-0e52-4499-832b-704abd1a6e11','秋雨漸涼有懷興元三首  其一','陸游','宋','宋诗','song-poetry','','[]','八月山中夜漸長，雨聲燈影共凄涼。',32,'全唐诗/poet.song.129000.json','["八月山中夜漸長，雨聲燈影共凄涼。", "遥知南鄭風霜早，已有寒熊犯獵塲。"]'),
('ca690602-b694-411e-8336-c3353cb68909','秋雨漸涼有懷興元三首  其二','陸游','宋','宋诗','song-poetry','','[]','十年前在古梁州，痛飲無時不慣愁。',32,'全唐诗/poet.song.129000.json','["十年前在古梁州，痛飲無時不慣愁。", "最憶夜分歌舞歇，臥聽秦女擘箜篌。"]'),
('a13fe2cd-0862-4003-b563-36b0569c0613','秋雨漸涼有懷興元三首  其三','陸游','宋','宋诗','song-poetry','','[]','清夢初回秋夜闌，床前耿耿一燈殘。',32,'全唐诗/poet.song.129000.json','["清夢初回秋夜闌，床前耿耿一燈殘。", "忽聞雨掠蓬窗過，猶作當時鐵馬看。"]'),
('6f26560f-f50c-4bd1-b65e-4b36bf97f066','秋風曲','陸游','宋','宋诗','song-poetry','','[]','秋風吹雨鳴窗紙，壯士不眠推枕起。',128,'全唐诗/poet.song.129000.json','["秋風吹雨鳴窗紙，壯士不眠推枕起。", "床頭金盡酒尊空，櫪馬相看涙如洗。", "鴻門覇上百萬師，安西北庭九千里。", "帳前畫角聲入雲，隴上鐵衣光照水。", "横飛渡遼健如鶻，談笑不勞投馬箠。", "堂堂羽檄從天下，夜半斫營孱可鄙。", "拾螢讀書定何益，投筆取封當努力。", "百斤長刀兩石弓，飽將兩耳聽秋風。"]'),
('0fc2fdc9-1ca0-4823-b0f9-96633ea9419d','送宣書記并寄其兄曇才二公','陸游','宋','宋诗','song-poetry','','[]','在吳識曇公，至蜀識才公。',144,'全唐诗/poet.song.129000.json','["在吳識曇公，至蜀識才公。", "彌天宣書記，晚乃得從容。", "是家固多賢，天遣慰我窮。", "初秋夏末時，衲子各西東。", "子獨惜此别，共語夜燭紅。", "怪我耐逆境，萬事一笑空。", "子顧知我否，視身如枯蓬。", "枯蓬未變滅，姑當付之風。", "家世無高年，我今六十翁。", "俯仰幾時客，結束已匆匆。", "那將須臾景，更受憂患攻。", "願言早来歸，相就煮晚菘。"]'),
('35087a6e-8c25-46f5-aa34-b6095b2a59d0','起晚戲作','陸游','宋','宋诗','song-poetry','','[]','地偏身飽閑，秋爽睡殊美。',72,'全唐诗/poet.song.129000.json','["地偏身飽閑，秋爽睡殊美。", "老雞每愧渠，三唱呼未起。", "厨人罷晨汲，童子愁屣履。", "惰慵雖可嘲，安靜良足喜。", "心空夢亦少，酣枕甘若醴。", "不學多事人，南柯豪衆蟻。"]'),
('dd402b29-87a0-4416-be89-7ec9d94d4daa','飲村店夜歸二首  其一','陸游','宋','宋诗','song-poetry','','[]','致主初心陋漢唐，暮年身世落農桑。',32,'全唐诗/poet.song.129000.json','["致主初心陋漢唐，暮年身世落農桑。", "草烟牛跡西山外，又臥旗亭送夕陽。"]'),
('41fc7c94-e5c8-4342-a4dc-0f70aec7f472','飲村店夜歸二首  其二','陸游','宋','宋诗','song-poetry','','[]','灧灧村醪君勿辭，橙椒香美白鵝肥。',32,'全唐诗/poet.song.129000.json','["灧灧村醪君勿辭，橙椒香美白鵝肥。", "醉中忘却身今老，戲逐螢光蹋雨歸。"]'),
('b61656bf-8c89-487a-8e49-a90949871541','雨夜感懷','陸游','宋','宋诗','song-poetry','','[]','點滴空堦雨送涼，青燈對影獨凄傷。',64,'全唐诗/poet.song.129000.json','["點滴空堦雨送涼，青燈對影獨凄傷。", "身如病木驚秋早，心似鰥魚怯夜長。", "鑄得黄金猶有術，掃空白髮定無方。", "蕭然禪榻君休笑，一卷殘書伴枕傍。"]'),
('5e2ee8d3-3f7a-4a9f-bf16-798dedad9bdd','寄葉道人','陸游','宋','宋诗','song-poetry','','[]','白首不堪憂患纏，要將樂事餞流年。',64,'全唐诗/poet.song.129000.json','["白首不堪憂患纏，要將樂事餞流年。", "尋山猶費幾兩屐，貯酒真須百斛舩。", "若信王侯等螻蟻，可因富貴失神仙。", "驚人亦莫摩銅狄，泰華松風足晝眠。"]'),
('70fb18ef-f36e-4b1f-bb50-28504a3f019b','月下小酌','陸游','宋','宋诗','song-poetry','','[]','昨日雨遶簷，孤燈對搔首。',96,'全唐诗/poet.song.129000.json','["昨日雨遶簷，孤燈對搔首。", "今夜月滿庭，長歌倚衰柳。", "世變浩無窮，成敗翻覆手。", "人生最樂事，臥聽壓新酒。", "我歸自梁益，零落愴親友。", "紛紛墮鬼録，何人得長久。", "後生多不識，詎肯顧衰朽。", "一杯無與同，敲門喚鄰叟。"]'),
('2e3b5c77-4f0c-424e-aa2d-e7d359d6bdde','讀袁公路傳','陸游','宋','宋诗','song-poetry','','[]','成敗相尋豈有常，英雄最忌數悲傷。',32,'全唐诗/poet.song.129000.json','["成敗相尋豈有常，英雄最忌數悲傷。", "蕪蔞豆粥從来事，何恨郵亭坐簀床。"]'),
('cc94a215-4b9c-4ab8-9f10-1f7dc0bdd774','鄰曲小飲','陸游','宋','宋诗','song-poetry','','[]','早稻喜登塲，相呼集野堂。',48,'全唐诗/poet.song.129000.json','["早稻喜登塲，相呼集野堂。", "迎霜新兔美，近社濁醪香。", "茆屋滴殘雨，竹籬圍夕陽。", "新豐不須作，真箇是吾鄉。"]'),
('97c1fbe9-55eb-4284-8a84-55d9d191adbe','秋夜觀月二首  其一','陸游','宋','宋诗','song-poetry','','[]','夢回殘燭耿房櫳，杳杳江天叫斷鴻。',32,'全唐诗/poet.song.129000.json','["夢回殘燭耿房櫳，杳杳江天叫斷鴻。", "病骨不禁風露重，披衣小立月明中。"]'),
('aadb4db6-b959-4ea3-b165-6ff8bfa2b011','秋夜觀月二首  其二','陸游','宋','宋诗','song-poetry','','[]','誰琢天邊白玉盤，亭亭破霧上高寒。',32,'全唐诗/poet.song.129000.json','["誰琢天邊白玉盤，亭亭破霧上高寒。", "山房無客兒貪睡，常恨清光獨自看。"]'),
('ae670d8e-ac32-4760-af3e-5b7d16529a3e','枕上','陸游','宋','宋诗','song-poetry','','[]','香冷燈昏夢自驚，清愁冉冉带餘酲。',32,'全唐诗/poet.song.129000.json','["香冷燈昏夢自驚，清愁冉冉带餘酲。", "夜長誰作幽人伴，惟是蛩聲與月明。"]'),
('58559d1a-52dc-430a-b7d3-2bf36e6e629a','秋夕大風松聲甚壯戲作短歌','陸游','宋','宋诗','song-poetry','','[]','人生不自憐，坐受外物械。',120,'全唐诗/poet.song.129000.json','["人生不自憐，坐受外物械。", "榮華難把玩，俄頃皆變壞。", "山棲亦何有，耳目差曠快。", "秋郊多烈風，夜壑起松籟。", "初聞尚蕭瑟，髣髴聽嚴瀨。", "忽如倒巨浸，便欲翻大塊。", "又疑楚漢戰，澒洞更勝敗。", "不然六月雨，雷電奔百怪。", "三更勢稍斂，鐵馬歸入塞。", "孰能從吾遊，洗汝胸次隘。"]'),
('0a400499-feae-4752-afb6-80a410c811e4','明河篇','陸游','宋','宋诗','song-poetry','','[]','明河八月轉分明，炯如素練西南傾。',130,'全唐诗/poet.song.129000.json','["明河八月轉分明，炯如素練西南傾。", "年年歲歲見河漢，坊坊曲曲聞碪聲。", "良人萬里事征行，碪聲中有玉關情。", "遥知鐵衣冷如水，指點明河白髮生。", "磧中草死駱駝鳴，萬里却望長安城。", "兒生總角爺未見，歸心頓覺封侯輕。", "漢家自古有夷狄，付與窮荒何足惜。", "只願天狼無光太白低，還家爲婦說安西。"]'),
('0538aa2e-81f7-423b-b1a6-f7ddd4f67725','夜聞鄰家治稻','陸游','宋','宋诗','song-poetry','','[]','二頃春蕪廢不耕，半生名宦竟何成。',32,'全唐诗/poet.song.129000.json','["二頃春蕪廢不耕，半生名宦竟何成。", "歸来每羨農家樂，月下風傳打稻聲。"]'),
('f093018f-0e38-41af-bef2-7392a1f49536','浪迹','陸游','宋','宋诗','song-poetry','','[]','浪迹人間四十年，鏡中不覺已華顛。',64,'全唐诗/poet.song.129000.json','["浪迹人間四十年，鏡中不覺已華顛。", "山川慘澹秋多感，燈火青熒夜少眠。", "壯志已忘榆塞外，高情正在酒壚邊。", "扁舟不恨無人識，且復長歌入暮烟。"]'),
('51e94e77-9d0c-40d6-8f57-3e3d1fa939eb','夜步庭下有感','陸游','宋','宋诗','song-poetry','','[]','夜遶中庭百匝行，秋風傳漏忽三更。',64,'全唐诗/poet.song.129000.json','["夜遶中庭百匝行，秋風傳漏忽三更。", "星辰北拱疏還密，河漢西流縱復横。", "驚鵲遶枝棲不穩，冷螢穿竹遠猶明。", "書生老抱平戎志，有泪如江未敢傾。"]'),
('221424a7-9516-4235-8381-db6ad9287fdc','題酒家壁','陸游','宋','宋诗','song-poetry','','[]','明主何曾棄不才，書生飄泊自堪哀。',64,'全唐诗/poet.song.129000.json','["明主何曾棄不才，書生飄泊自堪哀。", "烟波東盡江湖遠，雲棧西從隴蜀回。", "宿雨送寒秋欲晚，積衰成病老初来。", "酒香菰脆丹楓岸，強遣樽前笑口開。"]'),
('a61720b6-e799-41f7-bf1f-a49a50346c7c','題書齋壁','陸游','宋','宋诗','song-poetry','','[]','隨分琴書適性情，乍寒偏愛小窗明。',64,'全唐诗/poet.song.129000.json','["隨分琴書適性情，乍寒偏愛小窗明。", "旋煎甖粟留僧話，故種芭蕉待雨聲。", "丹藥驗方非畏死，文章排悶不求名。", "是間幽事君知否，莫怪經秋少入城。"]'),
('09a70aba-aeb1-49bb-927a-6ac4a7970332','贈猫','陸游','宋','宋诗','song-poetry','','[]','裹鹽迎得小貍奴，盡護山房萬卷書。',32,'全唐诗/poet.song.129000.json','["裹鹽迎得小貍奴，盡護山房萬卷書。", "慚愧家貧策勲薄，寒無氊坐食無魚。"]'),
('ad95953d-c43a-4b0c-b0e9-55d5f019e882','秋夕','陸游','宋','宋诗','song-poetry','','[]','羈魂虚仗些詞招，病骨那禁積毁消。',64,'全唐诗/poet.song.129000.json','["羈魂虚仗些詞招，病骨那禁積毁消。", "亂葉打窗寒有信，昏燈照幔夢無聊。", "棧邊老驥心空在，爨下殘桐尾半焦。", "百感忽生推枕起，碧霄銀漢正迢迢。"]'),
('c329b319-dbab-4ac3-ae42-34baf49f05b7','秋雨排悶十韵','陸游','宋','宋诗','song-poetry','','[]','今夏久無雨，從秋却少晴。',120,'全唐诗/poet.song.129000.json','["今夏久無雨，從秋却少晴。", "空濛迷遠望，蕭瑟送寒聲。", "衣潤香偏著，書蒸蠧欲生。", "壞簷聞瓦墮，漲水見堤平。", "溝溢池魚出，天低塞雁征。", "螢飛明闇廡，蛙閙雜疏更。", "藥醭時須焙，舟閑任自横。", "未憂荒楚菊，直恐敗吳秔。", "夜永燈相守，愁深酒細傾。", "浮雲會消散，鼓笛賽西成。"]'),
('b157fb81-c77a-403d-a0cb-4057cdfd86e2','小舟航湖夜歸書觸目三首  其一','陸游','宋','宋诗','song-poetry','','[]','雲黑風號不見星，古丘樷木聚精靈。',32,'全唐诗/poet.song.129000.json','["雲黑風號不見星，古丘樷木聚精靈。", "舟人已過微相語，兩兩三三鬼火青。"]'),
('f93d6821-6112-44a9-bef4-9dcc7568cc1f','小舟航湖夜歸書觸目三首  其二','陸游','宋','宋诗','song-poetry','','[]','電掣半空雲黯黮，舩浮積水浪憑陵。',32,'全唐诗/poet.song.129000.json','["電掣半空雲黯黮，舩浮積水浪憑陵。", "茫然不辯身何處，猶喜東南見塔燈。"]'),
('041738a1-0d3e-48c1-87fe-78b6dddf66e3','小舟航湖夜歸書觸目三首  其三','陸游','宋','宋诗','song-poetry','','[]','遥望湖塘炬火迎，纔歸村舍雨如傾。',32,'全唐诗/poet.song.129000.json','["遥望湖塘炬火迎，纔歸村舍雨如傾。", "畏途回首知安在，催喚兒童暖酒鐺。"]'),
('1c6a652b-8879-4ef3-8131-b0a01e643609','幽居書事二首  其一','陸游','宋','宋诗','song-poetry','','[]','莫嘆澗谷本卷七作恨人間苦不諧，清時有味是歸来。',71,'全唐诗/poet.song.129000.json','["莫嘆澗谷本卷七作恨人間苦不諧，清時有味是歸来。", "己因積毁成高臥，更借陽狂護散才。", "正欲清言聞客至，偶思小飲報花開。", "紛紛爭奪成何事，白骨生苔但可哀。"]'),
('79a841b0-ec27-411f-b46f-2b7200a6cc95','幽居書事二首  其二','陸游','宋','宋诗','song-poetry','','[]','安命知天更不疑，幽居最愛早寒時。',64,'全唐诗/poet.song.129000.json','["安命知天更不疑，幽居最愛早寒時。", "手中書墮初酣枕，窗下燈殘正劇碁。", "鮮鯽每從溪女買，香菰時就釣舩炊。", "山陰清絕君須記，雪裏騎驢未辦詩。"]'),
('232861c3-1a2c-498c-883c-7b032b91a8d9','晚霽二首  其一','陸游','宋','宋诗','song-poetry','','[]','雨斷簷餘滴，雲疏日漏明。',48,'全唐诗/poet.song.129000.json','["雨斷簷餘滴，雲疏日漏明。", "人其如積潦，天自活疲氓。", "溪碓舂香稻，霜叢剪綠橙。", "書生久愁臥，作意賦新晴。"]'),
('23f06d70-f66f-4c97-97c4-2d8417c3f767','晚霽二首  其二','陸游','宋','宋诗','song-poetry','','[]','漲水返舊壑，浮雲歸故山。',48,'全唐诗/poet.song.129000.json','["漲水返舊壑，浮雲歸故山。", "園丁藝蔬去，鄰婦賃舂還。", "喬木蒼烟外，孤村落照間。", "莫嫌樽酒薄，且用破愁顔。"]'),
('28901929-8146-498e-86c9-10fea6a10211','雨後散步後園二首  其一','陸游','宋','宋诗','song-poetry','','[]','淡日輕雲未快晴，涓涓溝水去無聲。',32,'全唐诗/poet.song.129000.json','["淡日輕雲未快晴，涓涓溝水去無聲。", "爲憐一徑新苔綠，别就牆陰取路行。"]'),
('2fb160fc-04ca-44ab-b955-2fcdc1365116','雨後散步後園二首  其二','陸游','宋','宋诗','song-poetry','','[]','澤國霜遲木未疏，秋来更覺愛吾廬。',32,'全唐诗/poet.song.129000.json','["澤國霜遲木未疏，秋来更覺愛吾廬。", "芭蕉緑潤偏宜墨，戲就明窗學草書。"]'),
('9aee5023-096e-433f-8d82-cd67cf2128b0','示客','陸游','宋','宋诗','song-poetry','','[]','十年奔走每思歸，剩喜湖邊晝掩扉。',64,'全唐诗/poet.song.129000.json','["十年奔走每思歸，剩喜湖邊晝掩扉。", "社燕免教嘲作客，海鷗曾是信忘機。", "暉暉晚日收新稻，漠漠新寒試夾衣。", "留客盤飱君勿笑，一畦蔬甲摘初稀。"]'),
('da4db155-3512-4ffc-bb3d-09908ba0079e','甲子晴','陸游','宋','宋诗','song-poetry','','[]','今日甲子晴，秋稼始可言。',72,'全唐诗/poet.song.129000.json','["今日甲子晴，秋稼始可言。", "老農喜相覓，隨事具雞豚。", "掃地設菅席，酌酒老瓦盆。", "耳熱仰視天，何異傾金尊。", "牛羊散墟落，霽色滿衡門。", "起舞屬父老，勿恨此酒渾。"]'),
('af971758-c662-4757-afd2-38c0619c1ab4','後一日復雨','陸游','宋','宋诗','song-poetry','','[]','一雨三日水抹隄，南村北村雲凄凄。',96,'全唐诗/poet.song.129000.json','["一雨三日水抹隄，南村北村雲凄凄。", "天公約束龍返穴，不忍嘉穀沈塗泥。", "日光清薄潦未縮，起視又嘆行雲西。", "初纔淅瀝灑窗户，俄已湍瀉鳴溝溪。", "豐凶相乘若翻手，振救小緩輒噬臍。", "窮閻腐儒不預此，且收芋栗寛兒啼。"]'),
('d24f0e12-0b36-4264-a62e-e022213a20f7','紹興庚辰余遊謝康樂石門與老洪道士痛飲賦詩既還山陰王仲信爲予作石門瀑布圖今二十有四年開圖感嘆作二首  其一','陸游','宋','宋诗','song-poetry','','[]','二十餘年别石門，燈前感舊欲消魂。',32,'全唐诗/poet.song.129000.json','["二十餘年别石門，燈前感舊欲消魂。", "人生萬事皆如夢，自笑區區記劍痕。"]'),
('2cce612a-3ffa-4a37-88fd-eccb853affff','紹興庚辰余遊謝康樂石門與老洪道士痛飲賦詩既還山陰王仲信爲予作石門瀑布圖今二十有四年開圖感嘆作二首  其二','陸游','宋','宋诗','song-poetry','','[]','愛酒黄冠鬢如雪，石門邂逅一樽同。',32,'全唐诗/poet.song.129000.json','["愛酒黄冠鬢如雪，石門邂逅一樽同。", "懸知久作此山土，愁對畫圖秋雨中。"]'),
('9cef816c-3d22-45d7-8f65-03a2408ee955','雨中遣懷','陸游','宋','宋诗','song-poetry','','[]','秋稼連雲飽不疑，寧期一敗莫支持。',64,'全唐诗/poet.song.129000.json','["秋稼連雲飽不疑，寧期一敗莫支持。", "雨如梅子初黄日，水似桃花欲動時。", "正晝螡蟲驅不去，終宵鼃黽怒何爲。", "凶年氣象堪流涕，禾把紛紛滿竹籬。"]'),
('e68ea5c0-6c10-481d-aed2-e16061c22379','秋思','陸游','宋','宋诗','song-poetry','','[]','秋来情味更堪論，身寄城南五畝園。',64,'全唐诗/poet.song.129000.json','["秋来情味更堪論，身寄城南五畝園。", "委轡看山無鐵獺，拾樵煎茗有青猿。", "陂塘夜雨添新漲，原野烟蕪減舊痕。", "豈是平生少親友，略無人肯訪孤村。"]'),
('ca1ec070-68e5-468c-8bac-8fb66b8fbf75','秋雨嘆','陸游','宋','宋诗','song-poetry','','[]','點點滴滴雨到明，悽悽惻惻夢不成。',128,'全唐诗/poet.song.129000.json','["點點滴滴雨到明，悽悽惻惻夢不成。", "窗間殘燈暗欲滅，匣中孤劍鏗有聲。", "少年讀書忽頭白，一字不試空虚名。", "公車自薦心實恥，新豐獨飲人所驚。", "太行千仞插雲立，黄流萬里從天傾。", "遺民久憤世多故，孱冦何足煩長纓。", "霜風初高鷹隼擊，天河下洗烟塵清。", "投筆急裝須快士，令人絕憶獨孤生。"]'),
('f6059d73-a6ec-4d1a-ae13-f228acae2d8a','雨中小酌','陸游','宋','宋诗','song-poetry','','[]','晨起占雲日日西，吾廬烟雨正凄迷。',64,'全唐诗/poet.song.129000.json','["晨起占雲日日西，吾廬烟雨正凄迷。", "愁看場上禾生耳，且泥杯中酒到臍。", "窗日幾時飛野馬，甕天惟是舞醯鷄。", "前村著屐猶通路，自摘金橙擣鱠齏。"]'),
('0d0d0b1b-9c50-46f4-8759-fe3ee19afb10','衰病有感三首  其一','陸游','宋','宋诗','song-poetry','','[]','衰與病相乘，山房冷欲冰。',48,'全唐诗/poet.song.129000.json','["衰與病相乘，山房冷欲冰。", "在家元是客，有髮亦如僧。", "愁絕窮秋雨，情親獨夜燈。", "西鄰有甘井，聊得曲吾肱。"]'),
('831001cb-2db4-4192-a1d2-dea821b55e43','衰病有感三首  其二','陸游','宋','宋诗','song-poetry','','[]','倦枕先雞覺，寒汀伴雁孤。',48,'全唐诗/poet.song.129000.json','["倦枕先雞覺，寒汀伴雁孤。", "寂寥誰省録，衰疾且枝梧。", "鶴骨秋添瘦，龜腸夜自呼。", "蓋棺吾事定，未敢泣窮途。"]'),
('dfabf104-8632-4a52-aa4a-f9e6fb8b7c9d','衰病有感三首  其三','陸游','宋','宋诗','song-poetry','','[]','羈宦一周星，歸如化鶴丁。',48,'全唐诗/poet.song.129000.json','["羈宦一周星，歸如化鶴丁。", "灰心成寂寂，霜鬢失青青。", "小智空自貴，大愚元不靈。", "客来應絕倒，扶病講丹經。"]'),
('83bfc9c3-a7ef-4322-9f1f-8f75f2a8b697','雨止頓寒遂有晴意','陸游','宋','宋诗','song-poetry','','[]','霧雨昏昏地氣騰，盤中朝暮厭驅蠅。',64,'全唐诗/poet.song.129000.json','["霧雨昏昏地氣騰，盤中朝暮厭驅蠅。", "未看霽色排陰翳，先覺清寒洗鬱蒸。", "喚客喜傾新熟酒，讀書貪趁欲殘燈。", "明朝樂事真當賀，山北山南曵瘦藤。"]'),
('9a494550-3222-48fd-b791-c28dcddc8fe1','秋晴出遊','陸游','宋','宋诗','song-poetry','','[]','雨餘清冷近霜天，拄杖閑拖不挂錢。',64,'全唐诗/poet.song.129000.json','["雨餘清冷近霜天，拄杖閑拖不挂錢。", "黄葉舞風初簌簌，碧渠通溜正濺濺。", "無情日馭工催老，耐事天公聽放顛。", "薄暮行歌竝湖去，有人偷様畫癯僊。"]'),
('56807ce3-71f0-4df8-8964-ebd42c2e1da9','悲秋四首  其一','陸游','宋','宋诗','song-poetry','','[]','形骸枯槁病侵陵，少睡長饑一老僧。',32,'全唐诗/poet.song.129000.json','["形骸枯槁病侵陵，少睡長饑一老僧。", "霜夜羈愁更無賴，莫收書策且留燈。"]'),
('48953548-e870-46d2-a36d-15da88728644','悲秋四首  其二','陸游','宋','宋诗','song-poetry','','[]','蕭蕭衰鬢點新霜，人靜房櫳易斷腸。',32,'全唐诗/poet.song.129000.json','["蕭蕭衰鬢點新霜，人靜房櫳易斷腸。", "等是閉門愁裏過，任敎風雨壞重陽。"]'),
('79048074-909d-4839-a3a7-60c88621f86e','悲秋四首  其三','陸游','宋','宋诗','song-poetry','','[]','殘年孤寂不禁秋，醉自凄凉醒更愁。',32,'全唐诗/poet.song.129000.json','["殘年孤寂不禁秋，醉自凄凉醒更愁。", "冨貴空成守錢虜，吾今何止百宜休。"]'),
('5157e4fc-bb81-4445-bb76-0f0c337b4a35','悲秋四首  其四','陸游','宋','宋诗','song-poetry','','[]','小雨簾櫳慘淡天，醉中偏藉亂書眠。',32,'全唐诗/poet.song.129000.json','["小雨簾櫳慘淡天，醉中偏藉亂書眠。", "夢回有恨無人會，枕畔橙香似昔年。"]'),
('0b8b75bb-8eee-4fd2-8e3c-44511a885592','久雨道懷','陸游','宋','宋诗','song-poetry','','[]','暮年惜日月，木落輒動心。',72,'全唐诗/poet.song.129000.json','["暮年惜日月，木落輒動心。", "閑居念親友，所願聞足音。", "風雨斷官道，吾廬況幽深。", "渺渺雲水鄉，蕭蕭蘆荻林。", "草茂豪鳴蛙，天闊無来禽。", "四顧此何處，悠悠付孤斟。"]'),
('ee5c0ade-e9cf-466b-acc1-66687092a4e1','野步書觸目','陸游','宋','宋诗','song-poetry','','[]','村落初過雨，園林殊未霜。',48,'全唐诗/poet.song.129000.json','["村落初過雨，園林殊未霜。", "幽花雜紅碧，野橘半青黄。", "飛鷺横秋浦，啼鴉滿夕陽。", "最憐山脚水，撩亂入陂塘。"]'),
('917ac3df-0846-4c9f-8697-19e2492e2209','月下','陸游','宋','宋诗','song-poetry','','[]','月白庭空樹影稀，鵲棲不穩繞枝飛。',32,'全唐诗/poet.song.129000.json','["月白庭空樹影稀，鵲棲不穩繞枝飛。", "老翁也學癡兒女，撲得流螢露濕衣。"]'),
('7518d0fb-e365-4b2f-b94c-87a6274dd15e','九月十日','陸游','宋','宋诗','song-poetry','','[]','不須扇障庾公塵，散地翛然學隱淪。',64,'全唐诗/poet.song.129000.json','["不須扇障庾公塵，散地翛然學隱淪。", "風帽可憐成昨夢，菊花已覺是陳人。", "昏昏但苦餘酲在，草草久無佳句新。", "嘆息吾生行已矣，老来歲月似奔輪。"]'),
('26fee698-e5fa-43d0-9ff5-eae6c9d67162','秋晴園中山禽絕多有感而賦','陸游','宋','宋诗','song-poetry','','[]','九日秋陰一日晴，山禽應喜我閑行。',64,'全唐诗/poet.song.129000.json','["九日秋陰一日晴，山禽應喜我閑行。", "幽吭弄暖閑相命，勁翮凌風遠有聲。", "熟果啄餘看核墮，細枝衘得欲巢成。", "名園美蔭不飛去，似比交朋猶有情。"]'),
('7757b656-0636-4b95-997f-33a1e4f80e38','燈籠','陸游','宋','宋诗','song-poetry','','[]','我年十六遊名場，靈芝借榻棲僧廊。',160,'全唐诗/poet.song.129000.json','["我年十六遊名場，靈芝借榻棲僧廊。", "鐘聲纔定履聲集，弟子堂上分兩廂。", "燈籠一様薄臘紙，瑩如雲母含清光。", "還家欲學竟未暇，歲月已似奔車忙。", "書生白首故習在，顛倒簡牘紛朱黄。", "短檠雖復作老伴，目力眩晃不可常。", "平生所好忽入手，摩挲把挈喜欲狂。", "蘭膏瀲灔支達旦，秋雨蕭瑟輸新涼。", "討論廢忘正塗乙，遂欲盡發萬卷藏。", "所嗟衰病終難勉，非復當年下五行。"]'),
('11a52d4a-feae-4311-8448-04b305d9a129','舟過南莊呼村老與飲示以詩二首  其一','陸游','宋','宋诗','song-poetry','','[]','昔我過此時，荷花粲雲錦。',72,'全唐诗/poet.song.129000.json','["昔我過此時，荷花粲雲錦。", "今我復来遊，霜露已凄凛。", "鄉鄰福苦薄，積雨敗垂稔。", "禾頭耳𧥄𧥄，熟計難高枕。", "所懼憂吾君，歲暮詔發廪。", "勿言村醪薄，排悶聊共飲。"]'),
('f597910c-3377-44cc-bba9-a61eebe0051b','舟過南莊呼村老與飲示以詩二首  其二','陸游','宋','宋诗','song-poetry','','[]','玄雲吞落日，大風東北起。',72,'全唐诗/poet.song.129000.json','["玄雲吞落日，大風東北起。", "隔林鳴兩鳩，當道行衆螘。", "晴来未三日，雨候乃復爾。", "我場何時乾，嘉穀在泥滓。", "豐凶歲所有，遊惰古所恥。", "努力敎子孫，天公終可倚。"]'),
('15baedc1-563c-4fe8-9a87-9eb0d56be5cc','秋夜獨過小橋觀月','陸游','宋','宋诗','song-poetry','','[]','湖上蕭蕭葉落頻，小橋東畔岸綸巾。',64,'全唐诗/poet.song.129000.json','["湖上蕭蕭葉落頻，小橋東畔岸綸巾。", "乍圓素月升寒璧，欲散微雲蹙細鱗。", "有酒便應遺世事，得閑隨處勝官身。", "笑談但恨朋遊少，安得幽人與卜鄰。"]'),
('a61f5f1d-6ff4-4c76-8611-8915637ef653','紹興中與陳魯山王季夷從兄仲高以重九日同遊禹廟後三十餘年自三橋泛舟歸山居秋高雨霽望禹廟樓殿重複光景宛如當時而三人者皆下世予亦衰病無聊慨然作此詩','陸游','宋','宋诗','song-poetry','','[]','重樓傑閣倚虚空，紅日蒼烟正鬱葱。',64,'全唐诗/poet.song.129000.json','["重樓傑閣倚虚空，紅日蒼烟正鬱葱。", "鄉國歸来渾似鶴，交朋零落不成龍。", "人生真與夢何校，我輩故應情所鍾。", "泪漬清詩却回棹，不眠一夜聽鳴蛩。"]'),
('69754398-04a1-4349-ad62-45dc71decd14','雜興四首  其一','陸游','宋','宋诗','song-poetry','','[]','風雨雞喔喔，雪霜柏森森。',24,'全唐诗/poet.song.129000.json','["風雨雞喔喔，雪霜柏森森。", "獨居雖無友，二物感我深。"]'),
('252b1086-db1d-4536-9b5e-fc4012506755','雜興四首  其二','陸游','宋','宋诗','song-poetry','','[]','萬物各有時，蟋蟀以秋鳴。',24,'全唐诗/poet.song.129000.json','["萬物各有時，蟋蟀以秋鳴。", "我老自少眠，那得憎此聲。"]'),
('455d8a31-e5f1-4452-a6fc-007c8d035da2','雜興四首  其三','陸游','宋','宋诗','song-poetry','','[]','漲水入我廬，萍葉黏半扉。',24,'全唐诗/poet.song.129000.json','["漲水入我廬，萍葉黏半扉。", "日出水返壑，念汝何由歸。"]'),
('8ba8aff2-d712-4e77-a760-41a02ef0cb43','雜興四首  其四','陸游','宋','宋诗','song-poetry','','[]','清霜染丹葉，秋晚粲如春。',24,'全唐诗/poet.song.129000.json','["清霜染丹葉，秋晚粲如春。", "回首風吹盡，天公解戲人。"]'),
('47434b86-b88f-49de-9a2a-00856d7ca724','予秋夜觀月得瘧疾枕上賦小詩自戲','陸游','宋','宋诗','song-poetry','','[]','貪看霜月步亭皋，不覺寒侵范叔袍。',32,'全唐诗/poet.song.129000.json','["貪看霜月步亭皋，不覺寒侵范叔袍。", "且倚誦詩驅瘧鬼，斷無人寄碧腴膏。"]'),
('3c235fbc-2f63-4f94-85b2-fc82266f09ea','後春愁曲','陸游','宋','宋诗','song-poetry','','[]','六年成都擅豪華，黄金買斷城中花。',96,'全唐诗/poet.song.129000.json','["六年成都擅豪華，黄金買斷城中花。", "醉狂戲作春愁曲，素屏紈扇傳千家。", "當時說愁如夢寐，眼底何曾有愁事。", "朱顔忽去白髮生，真墮愁城出無計。", "世間萬事元悠悠，此身長短歸山丘。", "閉門堅坐愈生愁，未死且復秉燭遊。"]'),
('0a0ec03b-9e11-4a69-a295-151bafd60d21','秋花嘆','陸游','宋','宋诗','song-poetry','','[]','秋花如義士，榮悴相與同。',72,'全唐诗/poet.song.129000.json','["秋花如義士，榮悴相與同。", "豈比輕薄花，四散隨春風。", "黄菊抱殘枝，寂寞臥寒雨。", "拒霜更可憐，和蒂浮烟浦。", "古来結交意，正要共死生。", "讀我秋花詩，可代丹雞盟。"]'),
('884817a1-0c2e-48c0-a43d-f6b65be9a37f','寄題朱元晦武夷精舍五首  其一','陸游','宋','宋诗','song-poetry','','[]','先生結屋綠巖邊，讀易懸知屢絕編。',32,'全唐诗/poet.song.129000.json','["先生結屋綠巖邊，讀易懸知屢絕編。", "不用采芝驚世俗，恐人謗道是神僊。"]'),
('17a242da-fb4d-4c0c-b1bf-7bb7471e259f','寄題朱元晦武夷精舍五首  其二','陸游','宋','宋诗','song-poetry','','[]','蟬蜕巖間果是無，世人妄想可憐渠。',32,'全唐诗/poet.song.129000.json','["蟬蜕巖間果是無，世人妄想可憐渠。", "有方爲子換凡骨，来讀晦庵新著書。"]'),
('9000e612-559c-4605-a96b-178e2e9020ad','寄題朱元晦武夷精舍五首  其三','陸游','宋','宋诗','song-poetry','','[]','身閑剩覺溪山好，心靜尤知日月長。',32,'全唐诗/poet.song.129000.json','["身閑剩覺溪山好，心靜尤知日月長。", "天下蒼生未蘇息，憂公遂與世相忘。"]'),
('d1cbaf57-f4cf-44ba-a958-047712dc5dd0','寄題朱元晦武夷精舍五首  其四','陸游','宋','宋诗','song-poetry','','[]','齊民本自樂衡門，水旱那知不自存。',32,'全唐诗/poet.song.129000.json','["齊民本自樂衡門，水旱那知不自存。", "聖主憂勤常旰食，煩公一一報曾孫。"]'),
('9346053e-2aa6-4f79-9315-001b6330a9a7','寄題朱元晦武夷精舍五首  其五','陸游','宋','宋诗','song-poetry','','[]','山如嵩少三十六，水似卭郲九折途。',32,'全唐诗/poet.song.129000.json','["山如嵩少三十六，水似卭郲九折途。", "我老正須閑處著，白雲一半肻分無。"]'),
('7b0ccef1-556c-4a92-a04c-458876674c0e','病思','陸游','宋','宋诗','song-poetry','','[]','夜窗孤影怯青燈，瘦著秋衣欲不勝。',64,'全唐诗/poet.song.129000.json','["夜窗孤影怯青燈，瘦著秋衣欲不勝。", "光景正如寒圃蝶，情懷却羨病寮僧。", "篝爐冷落燒殘葉，襌榻欹斜倚古藤。", "莫怪頺然遺世事，鬢絲日日鏡中增。"]'),
('53269492-50cf-41d0-b70b-0dc673726d9a','病愈','陸游','宋','宋诗','song-poetry','','[]','秋夕高齋病始輕，物華凋落歲崢嶸。',64,'全唐诗/poet.song.129000.json','["秋夕高齋病始輕，物華凋落歲崢嶸。", "蟹黄旋擘饞涎墮，酒淥初傾老眼明。", "提筆詩情還跌宕，倒床藥褁尚縱横。", "閑愁恰似憎人睡，又起挑燈聽雨聲。"]'),
('1c9f81c6-40a8-45eb-896e-341f87c875b8','病中忽有眉山士人史君見過欣然接之口占絕句','陸游','宋','宋诗','song-poetry','','[]','蜀語初聞喜復驚，依然如有故鄉情。',32,'全唐诗/poet.song.129000.json','["蜀語初聞喜復驚，依然如有故鄉情。", "絳羅餅餤玻璃酒，何日蟆頤伴我行。"]'),
('c7e4fb2d-89bb-4259-b3de-04004771f2f6','初寒','陸游','宋','宋诗','song-poetry','','[]','我窮不自活，萬事付天公。',96,'全唐诗/poet.song.129000.json','["我窮不自活，萬事付天公。", "今年寒苦晚，霧雨常濛濛。", "雖逭裘褐憂，坐念疾病攻。", "清夜喜不寐，萬木號西風。", "新霜纔幾何，瘴癘一掃空。", "曉看烏臼林，已有數葉紅。", "微雲時去来，寒日猶曈曨。", "振衣起出户，一笑尋鄰翁。"]'),
('4be0e9f1-8681-41d4-81fa-e59b5c0b785e','出塞曲','陸游','宋','宋诗','song-poetry','','[]','北風吹急雪，夜半埋氊廬。',56,'全唐诗/poet.song.129000.json','["北風吹急雪，夜半埋氊廬。", "將軍八千騎，萬里逐單于。", "漢家如天臣萬邦，歡呼動地單于降。", "鈴聲南来金閃鑠，赦書已報經沙漠。"]'),
('4f1468de-8415-4ead-a0a4-94ba0f7b3168','無題','陸游','宋','宋诗','song-poetry','','[]','碧玉當年未破瓜，學成歌舞入侯家。',32,'全唐诗/poet.song.129000.json','["碧玉當年未破瓜，學成歌舞入侯家。", "如今憔悴篷窗裏，飛上青天妒落花。"]'),
('63e326b5-3e19-40da-a10a-407b8278e2a0','道室即事','陸游','宋','宋诗','song-poetry','','[]','一簮殘雪寄林亭，手把黄庭兩卷經。',64,'全唐诗/poet.song.129000.json','["一簮殘雪寄林亭，手把黄庭兩卷經。", "琴調養心安澹泊，爐香挽夢上青冥。", "隨緣久已均憂喜，玩世惟須半醉醒。", "溪父園公殊未見，頺然誰與共忘形。"]'),
('66d23883-b1ba-4697-ac7e-7afef4b1ae1a','夙興','陸游','宋','宋诗','song-poetry','','[]','青燈黄卷擁篝爐，殘髮垂蓬未暇梳。',64,'全唐诗/poet.song.129000.json','["青燈黄卷擁篝爐，殘髮垂蓬未暇梳。", "略似諸生勤夜課，絕勝小吏迫晨趨。", "雞聲喔喔寒猶力，月影離離淡欲無。", "幽致滿前君不領，枉因留滯嘆頭顱。"]'),
('6773969e-8e5a-466d-80d4-8c2ade78ea84','長安道','陸游','宋','宋诗','song-poetry','','[]','千夫登登供版築，萬手丁丁供斵木。',115,'全唐诗/poet.song.129000.json','["千夫登登供版築，萬手丁丁供斵木。", "歌樓舞榭高入雲，複幕重簾晝燒燭。", "中使傳宣騎飛鞚，達官候見車擊轂。", "豈惟炎熱可炙手，五月瞿唐誰敢觸。", "人生易盡朝露晞，世事無常壞陂復。", "士師分鹿真是夢，塞翁失馬猶爲福。", "君不見野老八十無完衣，歲晚北風吹破屋。"]'),
('9be67016-c5e2-403c-8c0d-1c183799d00a','記夢','陸游','宋','宋诗','song-poetry','','[]','夜夢有客短褐袍，示我文章雜詩騷。',128,'全唐诗/poet.song.129000.json','["夜夢有客短褐袍，示我文章雜詩騷。", "措辭磊落格力高，浩如怒風駕秋濤。", "起伏奔蹴何其豪，勢盡東注浮千艘。", "李白杜甫生不遭，英氣死豈埋蓬蒿。", "晚唐諸人戰雖鏖，眼暗頭白真徒勞。", "何許老將擁弓刀，遇敵可使空壁逃。", "肅然起敬竪髮毛，伏讀百過聲嘈嘈。", "惜未終卷雞已號，追寫尚足驚兒曹。"]'),
('ba4f59a5-7790-4828-831e-d2ed2acde837','冬夜讀書','陸游','宋','宋诗','song-poetry','','[]','茂陵病後非平昔，瘦骨竛竮短髮疏。',64,'全唐诗/poet.song.129000.json','["茂陵病後非平昔，瘦骨竛竮短髮疏。", "紅燭悔從長夜飲，青燈喜對少年書。", "聖賢親見生非晚，忿慾俱空死有餘。", "破屋頺垣君勿笑，更闌弦誦滿吾廬。"]'),
('b0af9463-65d8-44aa-952d-bbd3272d7d0f','遊僊五首  其一','陸游','宋','宋诗','song-poetry','','[]','飄飄鸞鶴杳難攀，萬里東遊海上山。',32,'全唐诗/poet.song.129000.json','["飄飄鸞鶴杳難攀，萬里東遊海上山。", "應有世人遥稽首，紫簫餘調落雲間。"]'),
('402ac9f5-f04d-4c49-8ba9-9b09984f32f2','遊僊五首  其二','陸游','宋','宋诗','song-poetry','','[]','鳳舞鸞歌宴蘂宮，碧桃花下醉千鍾。',32,'全唐诗/poet.song.129000.json','["鳳舞鸞歌宴蘂宮，碧桃花下醉千鍾。", "紅塵謫滿重歸去，花未開殘宴未終。"]'),
('12ffe2ca-3ef6-42ff-9134-68d63cdec371','遊僊五首  其三','陸游','宋','宋诗','song-poetry','','[]','玄圃春風賜宴時，雙成獨奏玉參差。',32,'全唐诗/poet.song.129000.json','["玄圃春風賜宴時，雙成獨奏玉參差。", "侍晨飲釂虚皇喜，一段龍綃索進詩。"]'),
('d815c728-5d42-4579-ab4c-941635d3b0a6','遊僊五首  其四','陸游','宋','宋诗','song-poetry','','[]','初珥金貂謁紫皇，僊班最近玉爐香。',32,'全唐诗/poet.song.129000.json','["初珥金貂謁紫皇，僊班最近玉爐香。", "爲憐未慣叢霄冷，獨賜流霞九醞觴。"]'),
('6d4b9260-94c6-4cd1-a50e-8393949fc51e','遊僊五首  其五','陸游','宋','宋诗','song-poetry','','[]','玉殿吹笙第一僊，花前奏罷色悽然。',32,'全唐诗/poet.song.129000.json','["玉殿吹笙第一僊，花前奏罷色悽然。", "憶曾偷學春愁曲，謫在人間五百年。"]'),
('433bc80d-4856-448e-99cd-b68efc2679eb','過鄰家','陸游','宋','宋诗','song-poetry','','[]','今日病良已，笻枝發興新。',48,'全唐诗/poet.song.129000.json','["今日病良已，笻枝發興新。", "高居遺世事，一笑過吾鄰。", "夕照明丹葉，秋風老白蘋。", "素衣雖化盡，不爲犯京塵。"]'),
('b801f426-2652-43ae-aee7-0c2c9d5a091a','山園晚興','陸游','宋','宋诗','song-poetry','','[]','傳杯誰與豁幽悰，霜晚黄花未滿叢。',64,'全唐诗/poet.song.129000.json','["傳杯誰與豁幽悰，霜晚黄花未滿叢。", "過雁一聲寒靄外，短籬數掩夕陽中。", "易雖病裏猶能讀，詩到愁邊始欲工。", "惟有功名真已矣，懶將華髮對青銅。"]'),
('ee35933e-07c6-4ae1-a859-d10f84529d3e','初冬出扁門歸湖上','陸游','宋','宋诗','song-poetry','','[]','桑柘枝空葉作堆，斜陽更著角聲催。',64,'全唐诗/poet.song.129000.json','["桑柘枝空葉作堆，斜陽更著角聲催。", "雲歸玉笥茫茫去，水下蘭亭曲曲来。", "稻壟受犂寒欲遍，漁船入市晚爭回。", "貂裘破弊霜風冷，愁對青燈撥瓮醅。"]'),
('c5a7d77b-64b8-44db-896a-fe5d1eef8a5b','新寒小醉睡起日已高戲作','陸游','宋','宋诗','song-poetry','','[]','倦眼矇矓睡易成，華胥税駕不多程。',64,'全唐诗/poet.song.129000.json','["倦眼矇矓睡易成，華胥税駕不多程。", "衾重枕穩當霜夕，氊暖屏深擁宿酲。", "栩栩蝶魂閑自適，緜緜龜息靜無聲。", "幽棲豈是忘微祿，正怕絛鈴擾五更。"]'),
('b8eef435-aac6-47af-991b-c10b1ddc78dc','太息','陸游','宋','宋诗','song-poetry','','[]','閑將白髮照清溝，太息年光逝不留。',32,'全唐诗/poet.song.129000.json','["閑將白髮照清溝，太息年光逝不留。", "勲業無期著書晚，此生與世判悠悠。"]'),
('0ef75980-9e4d-4134-9904-211716a26e31','冬夜讀書','陸游','宋','宋诗','song-poetry','','[]','平生喜藏書，拱璧未爲寶。',72,'全唐诗/poet.song.129000.json','["平生喜藏書，拱璧未爲寶。", "歸来稽山下，爛漫恣探討。", "六經萬世眼，守此可以老。", "多聞竟何用，綺語期一掃。", "幽居出户稀，衰病擁爐早。", "青燈照黄卷，作意勿草草。"]'),
('20d9746b-14f2-4eab-a4c7-28085e93214a','晚步','陸游','宋','宋诗','song-poetry','','[]','地爐附殘火，將夕鳥雀喧。',72,'全唐诗/poet.song.129000.json','["地爐附殘火，將夕鳥雀喧。", "食已了無事，扶杖閑出門。", "披披歸雲陣，淡淡新月痕。", "平生足憂患，歲晚信乾坤。", "緩步牛羊巷，浩歌桑柘村。", "九原不可作，吾意與誰論。"]'),
('92c88a4a-f385-4f07-8e88-5a18e58cece1','村舍','陸游','宋','宋诗','song-poetry','','[]','空谷人稀到，新寒病頓輕。',48,'全唐诗/poet.song.129000.json','["空谷人稀到，新寒病頓輕。", "晨霜催小獵，宿雨潤新耕。", "草莽秦馳道，雲烟越故城。", "千年不磨滅，惟有暮山横。"]'),
('e79f8526-642e-4ee7-b4a8-76185d5f7036','野步至近村','陸游','宋','宋诗','song-poetry','','[]','隨意出柴荆，清寒作晚晴。',48,'全唐诗/poet.song.129000.json','["隨意出柴荆，清寒作晚晴。", "風吹雁北鄉，雲带月東行。", "童稚爭追逐，漁樵習送迎。", "白頭寧復仕，惟此餞餘生。"]'),
('6cc0ed6e-ceca-4f70-8f49-019ffca3449e','夜坐油盡戲作二首  其一','陸游','宋','宋诗','song-poetry','','[]','金樽畫燭少年豪，白首孤燈不厭勞。',32,'全唐诗/poet.song.129000.json','["金樽畫燭少年豪，白首孤燈不厭勞。", "夜漏雖深書未竟，半缸誰與續殘膏。"]'),
('58cd23ac-b7e8-4818-a80e-90ab5aa52bb2','夜坐油盡戲作二首  其二','陸游','宋','宋诗','song-poetry','','[]','欲盡殘燈更有情，可憐剪斷讀書聲。',32,'全唐诗/poet.song.129000.json','["欲盡殘燈更有情，可憐剪斷讀書聲。", "區區紙上太癡計，一笑開門看月朙。"]'),
('6c1b9b96-a18e-4508-9a51-541250719755','歲暮','陸游','宋','宋诗','song-poetry','','[]','離離井上桐，鬱鬱牆下桑。',72,'全唐诗/poet.song.129000.json','["離離井上桐，鬱鬱牆下桑。", "零落豈不悲，無奈中夜霜。", "蟋蟀更可念，歲暮依客床。", "客亦自孤寂，衣篝歇殘香。", "一燈挂西壁，耿耿青無光。", "援筆欲寫愁，三喟不成章。"]'),
('abfa284a-a38f-497e-a301-4e15412bb9e8','幽居感懷','陸游','宋','宋诗','song-poetry','','[]','偶傍楓林結數椽，東歸也復度流年。',64,'全唐诗/poet.song.129000.json','["偶傍楓林結數椽，東歸也復度流年。", "汀洲雁下依殘水，墟里人行破夕烟。", "十月風霜欺客枕，五更鼓角滿江天。", "散關清渭應如昨，回首功名一愴然。"]'),
('66365b72-db9d-41de-b1d3-8a06a4529c8d','山中夜歸戲作短歌','陸游','宋','宋诗','song-poetry','','[]','駿馬不用換美妾，名酒不用博凉州。',96,'全唐诗/poet.song.129000.json','["駿馬不用換美妾，名酒不用博凉州。", "霜天飲酒騎馬出，馳獵蹴蹋川原秋。", "少年意薄萬户侯，白首乃作窮山囚。", "箭鋒豈必盡狐兔，胸次聊欲平山丘。", "夜歸湖上酒初醒，莊舍蕭條燈火冷。", "解刀自笑太麤生，却染松煤飛兔頴。"]'),
('c0ce7a87-2822-4b5e-9ec1-849104e0d7f4','狂歌','陸游','宋','宋诗','song-poetry','','[]','少年雖狂猶有限，遇酒時能傲憂患。',128,'全唐诗/poet.song.129000.json','["少年雖狂猶有限，遇酒時能傲憂患。", "即今狂處不待酒，混混長歌老巖澗。", "拂衣即與世俗辭，掉頭不受朋友諫。", "挂帆直欲截烟海，策馬猶堪度雲棧。", "枵然癡腹肻貯愁，天遣作盎盛藜莧。", "髮垂不櫛性所便，衣垢忘濯心已慣。", "眼前故人死欲無，此生行矣風雨散。", "羞爲塵土伏轅駒，寧作江湖斷行雁。"]'),
('f7fb7838-29eb-4d8d-b42b-55d75315dbe1','遲暮','陸游','宋','宋诗','song-poetry','','[]','遲暮固多感，況此歲崢嶸。',72,'全唐诗/poet.song.129000.json','["遲暮固多感，況此歲崢嶸。", "霜霰忽已集，夜聞絡緯鳴。", "青燈不解語，依依有餘情。", "銅瓶煮寒泉，中作笙簫聲。", "沈憂能傷人，一夕白髮生。", "蓬莱渺雲海，金丹幾時成。"]'),
('d39b0c21-147a-49a0-a389-893b1389a6a2','種秫','陸游','宋','宋诗','song-poetry','','[]','種秫供留客，移花待探春。',48,'全唐诗/poet.song.129000.json','["種秫供留客，移花待探春。", "愁邊開樂國，鬧裏作閑身。", "鬢髮今如此，頭顱莫問人。", "白鷗非避俗，野性自難馴。"]'),
('ca6b008c-81fc-468c-8e3e-08cd795a6652','擁爐','陸游','宋','宋诗','song-poetry','','[]','睡少人人笑老生，擁爐孤坐欲三更。',64,'全唐诗/poet.song.129000.json','["睡少人人笑老生，擁爐孤坐欲三更。", "月移西去失花影，風自北来傳漏聲。", "鳬鼎煎茶非俗物，雁燈開卷愜幽情。", "興来自喜猶彊健，一紙清詩取次成。"]'),
('fc36adba-3491-43e4-a48a-75c968e2b1f0','冬夜吟','陸游','宋','宋诗','song-poetry','','[]','昨夜凝霜皎如月，碧瓦鱗鱗凍將裂。',96,'全唐诗/poet.song.129000.json','["昨夜凝霜皎如月，碧瓦鱗鱗凍將裂。", "今夜朙月却如霜，竹影横窗更清絕。", "造物有意娱詩人，供與詩材次第新。", "饑鴻病鶴自無寐，山窮水絕誰爲鄰。", "西村梅花消息動，唧唧寒醅漸鳴瓮。", "儘將醉帽插幽香，此生莫作長安夢。"]'),
('fbca09e8-f156-4ba2-b9ac-998bce26e220','讀書罷小酌偶賦','陸游','宋','宋诗','song-poetry','','[]','歲晚凄凉冰雪晨，頺垣破屋鏡湖濱。',64,'全唐诗/poet.song.129000.json','["歲晚凄凉冰雪晨，頺垣破屋鏡湖濱。", "浮生亦念古有死，壯氣要使胡無人。", "黄卷展殘三太息，綠尊酌罷一嚬伸。", "躬耕不預差科事，猶向清時作幸民。"]'),
('8ea62a73-4b74-414d-ae73-abbc810ffa87','移花遇小雨喜甚爲賦二十字','陸游','宋','宋诗','song-poetry','','[]','獨坐閑無事，燒香賦小詩。',24,'全唐诗/poet.song.129000.json','["獨坐閑無事，燒香賦小詩。", "可憐清夜雨，及此種花時。"]'),
('6b0f1550-9a07-4d85-bdb4-909ed5d05812','書生嘆','陸游','宋','宋诗','song-poetry','','[]','君不見城中小兒計不疏，賣漿賣餅活有餘。',136,'全唐诗/poet.song.129000.json','["君不見城中小兒計不疏，賣漿賣餅活有餘。", "夜歸無事喚儔侶，醉倒往往眠街衢。", "又不見壟頭男子手把鉏，丁字不識稱農夫。", "筋力雖勞憂患少，春秋社飲常歡娱。", "可憐秀才最誤計，一生衣食囊中書。", "聲名纔出衆毁集，中道不復能他圖。", "抱書餓死在空谷，人雖可罪汝亦愚。", "嗚呼人雖可罪汝亦愚，曼倩豈即賢侏儒。"]'),
('15d8e164-55ce-4bb1-9063-dac63103068e','冬夜醉解殘燈熒然起讀書至明賦詩十韵','陸游','宋','宋诗','song-poetry','','[]','冬夜厭久坐，頗幸一醉眠。',120,'全唐诗/poet.song.129000.json','["冬夜厭久坐，頗幸一醉眠。", "滿酌文舉尊，徑臥子敬氊。", "鼻雷未及作，眼電遽瞭然。", "孤燈如秋螢，喚我開陳編。", "初欲限一卷，隨手紛聨翩。", "歡然不知疲，忽已晨烏遷。", "嗟我行六十，衰病迫殘年。", "仕進今永塞，文章後誰傳。", "飽食而安寢，此計定自賢。", "勿學草玄翁，死爲人所憐。"]'),
('266768db-f824-4771-b91b-221f93eef2d9','夜行','陸游','宋','宋诗','song-poetry','','[]','路長憂炬盡，馬弱畏泥深。',48,'全唐诗/poet.song.129000.json','["路長憂炬盡，馬弱畏泥深。", "腸斷猿啼樹，魂驚鬼嘯林。", "艱危窮自慣，寒苦老難禁。", "回首金牛道，加鞭負壯心。"]'),
('b673fb3c-4464-422a-b58f-29d8ada11e21','遊淳化寺','陸游','宋','宋诗','song-poetry','','[]','蕭寺久不到，偶来幽興長。',48,'全唐诗/poet.song.129000.json','["蕭寺久不到，偶来幽興長。", "螘穿珠九曲，蜂釀蜜千房。", "雨過山横翠，霜新橘弄黄。", "年衰道不進，珍重一爐香。"]'),
('43fdb167-b938-4840-a054-bfe2a097c9fc','餘慶出遊夜歸','陸游','宋','宋诗','song-poetry','','[]','杖藜尋勝愜幽情，芒屨如飛病體輕。',64,'全唐诗/poet.song.129000.json','["杖藜尋勝愜幽情，芒屨如飛病體輕。", "迎客野梅纔半吐，避人山雉尚徐行。", "東谿水落灘聲壯，南嶺雲酣雪意成。", "薄暮歸来僧已定，佛龕獨對一燈明。"]'),
('b95c8c00-9430-4b41-89a4-b036ac844a42','遊前山','陸游','宋','宋诗','song-poetry','','[]','兀兀無歡意，閑遊未擬回。',48,'全唐诗/poet.song.129000.json','["兀兀無歡意，閑遊未擬回。", "屐聲驚雉起，風信報梅開。", "山雪堆僧衲，溪流動蟄雷。", "平生一桐帽，自惜犯塵埃。"]'),
('c0fb9e04-f4ed-4eef-8d49-e3a4956c1d47','齋前獨坐戲作','陸游','宋','宋诗','song-poetry','','[]','閉户學僧坐，頹然遺世情。',48,'全唐诗/poet.song.129000.json','["閉户學僧坐，頹然遺世情。", "虛窗鴿飛影，枯葉犬行聲。", "雪擁杉灰暖，雲垂紙帳明。", "清饞不可耐，一笑聽華鯨。"]'),
('94de7e69-339d-4696-9ab0-a8d4d51ced1e','晚同僧至谿上','陸游','宋','宋诗','song-poetry','','[]','躭躭臥石熊當道，矯矯長松龍上天。',32,'全唐诗/poet.song.129000.json','["躭躭臥石熊當道，矯矯長松龍上天。", "不怕雪雲寒到骨，喚僧扶杖立橋邊。"]'),
('f4773e86-dcbb-479f-8300-704de2c3d78b','僧飯','陸游','宋','宋诗','song-poetry','','[]','雲碓舂秔白，齋厨爨桂香。',48,'全唐诗/poet.song.129000.json','["雲碓舂秔白，齋厨爨桂香。", "百窮慚燕頷，一飽慰龜腸。", "舉世知心少，平生爲口忙。", "何當棄簮笏，終老掩山房。"]'),
('d8c6da6f-ae41-45e9-bb53-66ff267e0207','山店賣石榴取以薦酒','陸游','宋','宋诗','song-poetry','','[]','山色蒼寒雲釀雪，旗亭據榻興悠哉。',32,'全唐诗/poet.song.129000.json','["山色蒼寒雲釀雪，旗亭據榻興悠哉。", "麴生正欲相料理，催喚風流措措来。"]'),
('518acf43-8bb1-49e5-9e9c-983ef010ae30','平水小憇','陸游','宋','宋诗','song-poetry','','[]','蓐食草庵中，肩輿小市東。',48,'全唐诗/poet.song.129000.json','["蓐食草庵中，肩輿小市東。", "霧收山淡碧，雲漏日微紅。", "酒斾村場近，罾船浦溆通。", "平生喜行路，小住莫怱怱。"]'),
('15876923-2d09-49ad-a834-b517dcb5e712','自若耶溪舟行杭鏡湖而歸','陸游','宋','宋诗','song-poetry','','[]','換馬亭前烟火微，鬬牛橋畔行人稀。',64,'全唐诗/poet.song.129000.json','["換馬亭前烟火微，鬬牛橋畔行人稀。", "雲山慘澹少顔色，霜日青薄無光輝。", "新酒篘成桑正落，美人信斷雁空歸。", "高樓何處吹長笛，清涙無端又濕衣。"]'),
('06f7d633-207e-43c8-96d0-5b100a461496','宴坐','陸游','宋','宋诗','song-poetry','','[]','鼓樂弦歌萬二千，天魔剩欲破幽禪。',32,'全唐诗/poet.song.129000.json','["鼓樂弦歌萬二千，天魔剩欲破幽禪。", "道人袖手心如水，一點紗燈夜悄然。"]'),
('0c59fe26-52d4-43ee-9b77-e8394a9a5e4a','遊山歸偶賦','陸游','宋','宋诗','song-poetry','','[]','此生本寄一浮漚，歸臥茅茨又四秋。',64,'全唐诗/poet.song.129000.json','["此生本寄一浮漚，歸臥茅茨又四秋。", "習氣未除惟痛飲，幻軀偶健且閑遊。", "買蓑山縣雲藏市，横笛江城月滿樓。", "與世沈浮最安樂，莫思將相快恩讐。"]'),
('fa0bae1b-02f0-4636-8c2e-d2dbf1094192','六十吟','陸游','宋','宋诗','song-poetry','','[]','人生久矣無百年，六十七十已爲壽。',96,'全唐诗/poet.song.129000.json','["人生久矣無百年，六十七十已爲壽。", "嗟予忽忽蹈此境，衰髮如蓬面枯瘦。", "孤松摧折老澗壑，病馬凄凉依棧豆。", "尚無籌策活目前，豈有功名付身後。", "壁疏風入燈焰揺，地爐火盡寒蕭蕭。", "胸中白虹吐千丈，庭樹葉空衣未纊。"]'),
('96d188ba-64b5-4fc1-b2e0-b760c2ef2eff','舒悲','陸游','宋','宋诗','song-poetry','','[]','嗜酒苦猖狂，畏人還齷齪。',108,'全唐诗/poet.song.129000.json','["嗜酒苦猖狂，畏人還齷齪。", "老病始悔嘆，天下無此錯。", "管葛逝已久，千古困俗學。", "捫蝨論大計，使我思景略。", "中原失枝梧，烟塵暗河洛。", "天道遠莫測，士氣伏不作。", "煌煌東觀書，無乃太寂寞。", "丈夫不徒死，可作一丘壑。", "歲晚計愈疏，撫事涙零落。"]'),
('709d9fc1-5b6e-40fb-bba2-ece9422fc219','山園晚興','陸游','宋','宋诗','song-poetry','','[]','病骨初輕野興濃，閑扶拄杖夕陽中。',64,'全唐诗/poet.song.129000.json','["病骨初輕野興濃，閑扶拄杖夕陽中。", "草枯陂澤涓涓水，木落園林淅淅風。", "楊子凄凉老天祿，馬周憔悴客新豐。", "壯心未與朱顔改，一笑憑高送斷鴻。"]'),
('bedc2287-6279-48d3-96d0-24d99a6e25c2','獨立','陸游','宋','宋诗','song-poetry','','[]','獨立柴荆外，頽然一秃翁。',48,'全唐诗/poet.song.129000.json','["獨立柴荆外，頽然一秃翁。", "亂山吞落日，野水倒寒空。", "憂患工催老，飄零敢諱窮。", "漁歌亦何恨，悽斷滿西風。"]'),
('c0d615af-5448-45e4-ac5d-844d826594b9','探梅二首  其一','陸游','宋','宋诗','song-poetry','','[]','半吐幽香特地奇，正如官柳弄黄時。',32,'全唐诗/poet.song.129000.json','["半吐幽香特地奇，正如官柳弄黄時。", "放翁頗具尋梅眼，可愛南枝愛北枝。"]'),
('e968092c-4358-4799-803a-84a841b27c8a','探梅二首  其二','陸游','宋','宋诗','song-poetry','','[]','江路雲低糝玉塵，暗香初探一枝新。',32,'全唐诗/poet.song.129000.json','["江路雲低糝玉塵，暗香初探一枝新。", "平生不喜凡桃李，看了梅花睡過春。"]'),
('28f223a4-1601-48dc-9b51-641a8936bdfe','遠興','陸游','宋','宋诗','song-poetry','','[]','莫言人事足悲傷，只爲詩情合斷腸。',64,'全唐诗/poet.song.129000.json','["莫言人事足悲傷，只爲詩情合斷腸。", "窗檻雨晴湖灔灔，郊墟烟重月茫茫。", "梅花調苦愁三弄，竹葉香清泥一觴。", "閉户終年嗟局促，不如新雁到衡湘。"]'),
('2d95ddaa-4527-4757-876c-352a395990a1','張功甫許見訪以詩堅其約','陸游','宋','宋诗','song-poetry','','[]','零落汀蘋露氣清，北窗昨夜已秋聲。',64,'全唐诗/poet.song.129000.json','["零落汀蘋露氣清，北窗昨夜已秋聲。", "書来屢有入東約，坐上極思虚左迎。", "激烈哦詩殷金石，縱横落筆走蛟鯨。", "吾曹此事期千載，老眼相逢剩要驚。"]'),
('c8b69be0-f007-4a3b-a6fe-d0566cb1fb8b','夜夢與數客觀畫有八幅龍湫圖特奇客請予作詩其上書數十字而覺不復能記明旦乃追補之亦彷彿夢中意也','陸游','宋','宋诗','song-poetry','','[]','高堂閱畫娱嘉賓，巨幅小卷縱横陳。',192,'全唐诗/poet.song.129000.json','["高堂閱畫娱嘉賓，巨幅小卷縱横陳。", "其間一圖最傑作，命意落筆驚倒人。", "奇峰峭立插地軸，飛瀑崩瀉垂天紳。", "壽藤老木幻荒怪，深潭危棧愁鬼神。", "忽然白晝起雷電，始覺異物蟠奫淪。", "陰雲四興誅老魃，甘澍連夕蘇疲民。", "豈惟陂澤苖盡立，已活億萬介與鱗。", "文章與畫共一法，腕力要可回千鈞。", "錙銖不到便懸隔，用意雖盡終苦辛。", "君看此圖凡幾筆，一一圜勁如秋蓴。", "乃知世間有絕藝，天造草昧參經綸。", "吾言未竟且復止，剩發幽奥天公嗔。"]'),
('442a448d-c258-4858-b365-14489eb3f21f','泛舟','陸游','宋','宋诗','song-poetry','','[]','女牆齾齾带斜暉，短棹還從剡曲歸。',64,'全唐诗/poet.song.129000.json','["女牆齾齾带斜暉，短棹還從剡曲歸。", "木葉經霜渾欲盡，人家近水自相依。", "逢迎俗客言多忤，顛沛窮途計易非。", "雪裏閉門殊不惡，故貂雖弊勝無衣。"]'),
('64b1a67f-1e01-4c4f-9855-50bdbd51a65d','夜聞大風感懷賦吳體','陸游','宋','宋诗','song-poetry','','[]','故都宫闕汙羶腥，原野久稽陳大刑。',64,'全唐诗/poet.song.129000.json','["故都宫闕汙羶腥，原野久稽陳大刑。", "未須校尉戍西域，先要將軍空朔庭。", "意言揮戈可退日，身乃讀書方聚螢。", "病起窗前髮如雪，夜聞風聲孤涕零。"]'),
('1900e577-0881-4279-84d1-020343203c07','骨相','陸游','宋','宋诗','song-poetry','','[]','骨相元知薄，功名敢自期。',48,'全唐诗/poet.song.129000.json','["骨相元知薄，功名敢自期。", "病侵彊健日，閑過聖明時。", "形勝輪臺地，飛騰瀚海師。", "江湖雖萬里，猶擬綴聲詩。"]'),
('93466bfc-9396-4a53-a08e-48277ba02e88','有感二首  其一','陸游','宋','宋诗','song-poetry','','[]','書生事業絕堪悲，横得虛名毁亦隨。',64,'全唐诗/poet.song.129000.json','["書生事業絕堪悲，横得虛名毁亦隨。", "怖懼幾成床下伏，艱難何啻劍頭炊。", "貸監河粟元知誤，乞尉遲錢更覺癡。", "已卜一庵鵝鼻谷，可無芝术療朝饑。"]'),
('cd71a287-7bf9-4033-98ce-425b0978b4d4','有感二首  其二','陸游','宋','宋诗','song-poetry','','[]','讀遍名山萬卷藏，殘年肻受俗低昻。',69,'全唐诗/poet.song.129000.json','["讀遍名山萬卷藏，殘年肻受俗低昻。", "正須嘯詠風濤上，未至悲辛酒{炙火=肉}旁。", "夢裏功名誰復計，閑中日月不勝長。", "虚皇有詔君知否，盡賜江湖作醉鄉。"]'),
('2e8f456f-bbd5-42fd-bb04-b329dfad5aa8','城西晚眺','陸游','宋','宋诗','song-poetry','','[]','嫋嫋城笳咽，熒熒漁火青。',48,'全唐诗/poet.song.129000.json','["嫋嫋城笳咽，熒熒漁火青。", "霜凋兩岸柳，水浸一天星。", "靜看船歸浦，遥聞雁落汀。", "倚闌幽興極，不敢恨飄零。"]'),
('c8f97c27-b841-4b60-8e17-7f905665cc88','苦寒','陸游','宋','宋诗','song-poetry','','[]','凍硯時能出苦吟，濁醪亦復慰孤斟。',64,'全唐诗/poet.song.129000.json','["凍硯時能出苦吟，濁醪亦復慰孤斟。", "誰知冰雪凝嚴候，自是乾坤愛育心。", "癘鬼盡驅人意樂，遺蝗一洗麥根深。", "但嫌景短妨書課，棲鳥紛紛又滿林。"]'),
('e835f07b-7b7f-441c-8020-440001721e7c','夙興','陸游','宋','宋诗','song-poetry','','[]','病後精神殊未减，披衣每起待晨雞。',64,'全唐诗/poet.song.129000.json','["病後精神殊未减，披衣每起待晨雞。", "愛書不厭如平壑，戒酒新嚴似築堤。", "莫嘆茅茨常局促，猶勝簿領苦沈迷。", "迎長漸近丹當熟，已覺溫溫下徹臍。"]'),
('902b5bd3-d090-4e85-aa7a-7061d128de2d','冬夜讀書甚樂偶作短歌','陸游','宋','宋诗','song-poetry','','[]','衰病作書祟，常恨無新功。',120,'全唐诗/poet.song.129000.json','["衰病作書祟，常恨無新功。", "兔甌供茗粥，睡思一洗空。", "郊居近城闉，漏鼓傳鼕鼕。", "緗帙開爛漫，牙籖紛疉重。", "朱黄參筆墨，照映燈花紅。", "魯壁汲冡秘，天遣慰困窮。", "衮衣窺藻火，宗廟聽笙鏞。", "端居得至樂，生世豈不逢。", "藜羮冷未啜，短褐忘嚴冬。", "拜手謝造物，不須黑頭公。"]'),
('61433b2a-fc25-4b49-a9a1-d4bd55ed3534','冬夜月下作','陸游','宋','宋诗','song-poetry','','[]','造物寧能困此翁，浩歌庭下答松風。',64,'全唐诗/poet.song.129000.json','["造物寧能困此翁，浩歌庭下答松風。", "煌煌斗柄插天北，焰焰月輪生海東。", "皂纛黄旗都護府，峨冠長劍大明宮。", "功名晚遂從来事，白首江湖未嘆窮。"]'),
('a882d477-a90b-4284-8028-dddc9ef72db5','感憤','陸游','宋','宋诗','song-poetry','','[]','今皇神武是周宣，誰賦南征北伐篇。',64,'全唐诗/poet.song.129000.json','["今皇神武是周宣，誰賦南征北伐篇。", "四海一家天曆數，兩河百郡宋山川。", "諸公尚守和親策，志士虚捐少壯年。", "京洛雪消春又動，永昌陵上草芊芊。"]'),
('44b08e46-fca2-4a60-9f94-40d5bd4dd3ce','蓬户','陸游','宋','宋诗','song-poetry','','[]','蓬户真堪設爵羅，歲時野老自相過。',64,'全唐诗/poet.song.129000.json','["蓬户真堪設爵羅，歲時野老自相過。", "人情靜處看方見，詩句窮来得最多。", "枕上長歌時激烈，樽前一笑且婆娑。", "白頭萬事都經遍，莫爲悲傷損太和。"]'),
('d4499131-a36a-44a6-aec9-8291ec08efbf','行後園','陸游','宋','宋诗','song-poetry','','[]','霜風吹枯桑，落葉乾有聲。',48,'全唐诗/poet.song.129000.json','["霜風吹枯桑，落葉乾有聲。", "陂池日已涸，沙水見底清。", "人生非金石，歲暮難爲情。", "安得天邊鵠，駕之以遐征。"]'),
('bd896a26-90d4-4f51-bceb-7c620d3ee33e','曉出遇獵徒有作','陸游','宋','宋诗','song-poetry','','[]','出門萬瓦粲晨霜，忽憶行軍起裹創。',64,'全唐诗/poet.song.129000.json','["出門萬瓦粲晨霜，忽憶行軍起裹創。", "賣劍買牛身已老，搴旗斬將夢猶狂。", "奇才古有潛屠肆，豪氣今誰寓獵場。", "狐兔草間何足問，合留長箭射天狼。"]'),
('b7931324-9ee1-4d99-93ff-1cbc58935aa3','贈道侶','陸游','宋','宋诗','song-poetry','','[]','崎嶇世路久知難，凖擬丹成玉鍊顔。',64,'全唐诗/poet.song.129000.json','["崎嶇世路久知難，凖擬丹成玉鍊顔。", "十載尋人遍巖穴，一樽隨處對溪山。", "蘇門晝寂聞舒嘯，函谷秋清候度關。", "剩欲相招同此事，疑君未辦一生閑。"]'),
('3f3606d4-dc46-452d-8b8a-ee6ef0e84a3b','六言四首  其一','陸游','宋','宋诗','song-poetry','','[]','功名正恐不免，冨貴酷非所須。',28,'全唐诗/poet.song.129000.json','["功名正恐不免，冨貴酷非所須。", "鐵馬未平邊徼，釣船且醉江湖。"]'),
('82727656-eac5-4532-99e8-3305eaae51e0','六言四首  其二','陸游','宋','宋诗','song-poetry','','[]','噉飯一簞不盡，結廬環堵猶寛。',28,'全唐诗/poet.song.129000.json','["噉飯一簞不盡，結廬環堵猶寛。", "常得奉祠玉局，不須草詔金鑾。"]'),
('766a8e1a-2f60-4916-ae9e-cd0b33a44514','六言四首  其三','陸游','宋','宋诗','song-poetry','','[]','烏有翁邊貰酒，無何鄉裏尋花。',28,'全唐诗/poet.song.129000.json','["烏有翁邊貰酒，無何鄉裏尋花。", "把定東風一笑，今年别是生涯。"]'),
('4d19aa17-5756-460d-88ea-7de925aa3e51','六言四首  其四','陸游','宋','宋诗','song-poetry','','[]','壯歲京華羈旅，暮年湖海清狂。',28,'全唐诗/poet.song.129000.json','["壯歲京華羈旅，暮年湖海清狂。", "勿倚新知可樂，笑中白刃如霜。"]'),
('9a68f183-c691-4d9b-8bc1-fb1864ad667d','作雪未成自湖中歸寒甚飲酒作短歌','陸游','宋','宋诗','song-poetry','','[]','黑雲垂到地，飛霰如細礫。',96,'全唐诗/poet.song.129000.json','["黑雲垂到地，飛霰如細礫。", "我從湖上歸，散髮醉吹笛。", "少年志功名，目視無堅敵。", "慘淡古戰場，往往身所歴。", "寧知事大繆，白首猶寂寂。", "凄凉武侯表，零落陳琳檄。", "報主知何時，誓死空憤激。", "天高白日遠，有泪無處滴。"]'),
('80ca70d7-cb4e-42c3-8ffb-43017bf1c884','題傳神','陸游','宋','宋诗','song-poetry','','[]','鹽車心愧渥洼姿，邂逅風雲妄自期。',64,'全唐诗/poet.song.129000.json','["鹽車心愧渥洼姿，邂逅風雲妄自期。", "齧雪豈無歸漢日，飯牛猶有相齊時。", "君看短褐琴横膝，誰許峨冠劍拄頤。", "白髮蕭蕭雖憊矣，時来或將渡遼師。"]'),
('ed11f88e-1031-4a0d-9b60-b852d184adf5','閏月三夜舍西觀新月','陸游','宋','宋诗','song-poetry','','[]','平生絕愛初三月，況是平池浸玉鈎。',32,'全唐诗/poet.song.129000.json','["平生絕愛初三月，況是平池浸玉鈎。", "老去人間朋舊少，一樽誰與話清愁。"]'),
('17c5f01f-bf37-464c-8cf0-9754fd6e6a56','獨夜','陸游','宋','宋诗','song-poetry','','[]','城上長更續短更，江平天迥雁方征。',64,'全唐诗/poet.song.129000.json','["城上長更續短更，江平天迥雁方征。", "燈明紙帳雪霜色，火熟銅瓶風雨聲。", "濁酒未傾心已怯，細書時讀眼猶明。", "蕭然一室平生慣，纛下何須擁萬兵。"]'),
('97e5c177-00f3-4c1b-99fc-5d2890bdb1a9','晚出偏門','陸游','宋','宋诗','song-poetry','','[]','一段新愁带宿酲，半欹烏帽策驢行。',64,'全唐诗/poet.song.129000.json','["一段新愁带宿酲，半欹烏帽策驢行。", "村墟香動梅初破，裘褐寒輕雪未成。", "渡口人爭紅日晚，沙邊雁带碧烟横。", "悠然又覓長堤路，腸斷城樓畫角聲。"]'),
('34d8d898-14f0-4146-af6b-0b305ccbae62','薏苡','陸游','宋','宋诗','song-poetry','','[]','初遊唐安飯薏米，炊成不减雕胡美。',82,'全唐诗/poet.song.129000.json','["初遊唐安飯薏米，炊成不减雕胡美。", "大如芡實白如玉，滑欲流匙香滿屋。", "腹腴項臠不入盤，況復飱酪誇甘酸。", "東歸思之未易得，每以問人人不識。", "嗚呼奇材從古棄草菅，君試求之籬落間。"]'),
('a5b8cf1c-12c5-4a0e-aa71-1edbe7e09804','答鄭虞任檢法見贈','陸游','宋','宋诗','song-poetry','','[]','臥龍山前秋雨晴，鄭子過我如夙昔。',96,'全唐诗/poet.song.129000.json','["臥龍山前秋雨晴，鄭子過我如夙昔。", "照人眉宇寒巉巉，懸知筆有千鈞力。", "鏡湖歲暮霜葉空，乃聞載酒同諸公。", "歸来湖山皆動色，新詩一紙吹清風。", "文章要須到屈宋，萬仞青霄下鸞鳳。", "區區圓美非絕倫，彈丸之評方誤人。"]'),
('55b564c7-d19d-4bc6-995b-0b77250eb5e0','舟中曉賦','陸游','宋','宋诗','song-poetry','','[]','小艇下滄浪，吳歌特地長。',48,'全唐诗/poet.song.129000.json','["小艇下滄浪，吳歌特地長。", "斜分半艙月，滿載一篷霜。", "香甑炊菰白，醇醪點蟹黄。", "宦遊元爲口，莫恨老江鄉。"]'),
('70a710bc-3f8d-4a18-9a88-2505548aef03','野興二首  其一','陸游','宋','宋诗','song-poetry','','[]','玉門關外何妨死，飯顆山頭不怕窮。',32,'全唐诗/poet.song.129000.json','["玉門關外何妨死，飯顆山頭不怕窮。", "春瓮已成花欲動，了無一事着胸中。"]'),
('88011ed5-3173-446d-9cf7-5cf7eeb66247','野興二首  其二','陸游','宋','宋诗','song-poetry','','[]','猿臂將軍老未衰，氣吞十萬羽林兒。',32,'全唐诗/poet.song.129000.json','["猿臂將軍老未衰，氣吞十萬羽林兒。", "南山射虎自堪樂，何用封侯高帝時。"]'),
('3d938403-18a8-4472-adc7-a84b1dcf6952','月夜有感','陸游','宋','宋诗','song-poetry','','[]','炯炯冰輪升，澹澹玉宇碧。',72,'全唐诗/poet.song.129000.json','["炯炯冰輪升，澹澹玉宇碧。", "高樓傾美酒，一醉不容失。", "陸生獨何事，閉户飽岑寂。", "年来負風月，豈止此一夕。", "平生酒邊身，欲老每自惜。", "夜闌耿不寐，浩歌出金石。"]'),
('c6ef8946-ebb9-43ef-a9c4-4def58d0ce3a','落魄','陸游','宋','宋诗','song-poetry','','[]','落魄東吳莫笑儂，今年要不負春風。',64,'全唐诗/poet.song.129000.json','["落魄東吳莫笑儂，今年要不負春風。", "閑愁擲向乾坤外，永日移来歌吹中。", "酒浪欲爭湖水綠，花光却妒舞衫紅。", "公卿憂責如山重，肻信人間有放翁。"]'),
('1a9f7392-39f4-47bd-a1e2-5019d35ec945','遣興','陸游','宋','宋诗','song-poetry','','[]','壯年一箭落雙鵰，野餉如今擷藥苖。',64,'全唐诗/poet.song.129000.json','["壯年一箭落雙鵰，野餉如今擷藥苖。", "寒與梅花同不睡，悶尋鸚鵡說無憀。", "烏絲闌上詩初就，緑綺聲中酒半消。", "老去可憐風味在，未應山海混漁樵。"]'),
('56da5e04-1f71-4d3e-be47-5f49f7cd7e44','湖村野興二首  其一','陸游','宋','宋诗','song-poetry','','[]','十里疏鐘到野堂，五更殘月伴清霜。',32,'全唐诗/poet.song.129000.json','["十里疏鐘到野堂，五更殘月伴清霜。", "已知無奈姮娥冷，瘦損梅花更斷腸。"]'),
('15d64ffe-e5e7-454a-b750-7fc93a428224','湖村野興二首  其二','陸游','宋','宋诗','song-poetry','','[]','山色空濛雨點微，醉中不覺濕蓑衣。',32,'全唐诗/poet.song.129000.json','["山色空濛雨點微，醉中不覺濕蓑衣。", "何妨乞與丹靑本，一棹横衝翠靄歸。"]'),
('f135551b-2150-4c52-899e-8864d919e108','看鏡','陸游','宋','宋诗','song-poetry','','[]','局促人間百不如，每看清鏡嘆頭顱。',64,'全唐诗/poet.song.129000.json','["局促人間百不如，每看清鏡嘆頭顱。", "醉来風月心雖在，老去軒裳夢已無。", "棋劫正忙停晚餉，詩聨未穩畫寒爐。", "乘除尚喜身强健，六十登山不用扶。"]'),
('1567c5ba-b2db-4735-9652-9dce141ccd0c','塞上','陸游','宋','宋诗','song-poetry','','[]','塞上今年有事宜，將軍承詔出全師。',64,'全唐诗/poet.song.129000.json','["塞上今年有事宜，將軍承詔出全師。", "精金錯落八尺馬，刺繡鮮明五丈旗。", "上谷飛狐傳號令，蕭關積石列城陴。", "不應幕府無班固，早晚燕然刻頌詩。"]'),
('ff516022-33e9-4ae7-b2cd-f7e3117b7ca4','舟過會稽山下因繫舟遊近村迨暮乃歸','陸游','宋','宋诗','song-poetry','','[]','六十齒髮衰，歲月如逝波。',96,'全唐诗/poet.song.129000.json','["六十齒髮衰，歲月如逝波。", "秦王酒瓮邊，知復幾經過。", "欣然捨畫檝，仄步捫青蘿。", "一徑入幽谷，四面聞樵歌。", "白雲忽破碎，翠木相蕩摩。", "瀲瀲春塘滿，柳陰戲雙鵝。", "浮生百憂中，此樂顧豈多。", "日暮吾其歸，已恐爛斧柯。"]'),
('778d1c08-a1e5-4b77-86d1-9623e3067a53','人日偶遊民家小園有山茶方開','陸游','宋','宋诗','song-poetry','','[]','人日西郊路，晨光射淺灘。',48,'全唐诗/poet.song.129000.json','["人日西郊路，晨光射淺灘。", "停橈喜蕭散，照影嘆衰殘。", "社酒香浮瓮，春蔬綠滿盤。", "山茶雖慰眼，不似海雲看。"]'),
('7b636f89-3ee3-4e25-9445-eff9b5b39d9f','過杜浦橋二首  其一','陸游','宋','宋诗','song-poetry','','[]','橋外波如鴨頭緑，杯中酒作鵝兒黄。',32,'全唐诗/poet.song.129000.json','["橋外波如鴨頭緑，杯中酒作鵝兒黄。", "山茶花下醉初醒，却過西村看夕陽。"]'),
('a046ea24-53ab-4d5d-8597-3b6d7046f6e4','過杜浦橋二首  其二','陸游','宋','宋诗','song-poetry','','[]','橋北雨餘春水生，橋南日落暮山横。',32,'全唐诗/poet.song.129000.json','["橋北雨餘春水生，橋南日落暮山横。", "問君對酒胡不樂，聽取菱歌烟外聲。"]'),
('c221e9cf-280e-4353-91c8-ea797306801f','上元日晝臥','陸游','宋','宋诗','song-poetry','','[]','積雨連上元，孤愁臥空館。',72,'全唐诗/poet.song.129000.json','["積雨連上元，孤愁臥空館。", "宿酲殊未解，欲起意復懶。", "床敷蠻氊穩，被擁吳綾暖。", "殘香碧縷細，軟火紅焰短。", "雖云少睡眠，聊喜屢展轉。", "昏昏忽已暮，一笑呼茗椀。"]'),
('30b59515-9e4c-440e-a6a4-ad9f2308b630','莊器之作招隱閣項平父諸人賦詩予亦繼作','陸游','宋','宋诗','song-poetry','','[]','諸公共賦反招隱，細字斜行肻見傳。',64,'全唐诗/poet.song.129000.json','["諸公共賦反招隱，細字斜行肻見傳。", "語到淮南小山作，人如江左永和年。", "一窗蘿月禁春瘦，萬壑松風撼晝眠。", "我亦尚嫌林谷淺，因君更擬斸雲烟。"]'),
('122a8c03-6821-46df-9520-4508bf2feca4','春夜讀書感懷','陸游','宋','宋诗','song-poetry','','[]','荒林梟獨嘯，野水鵝群鳴。',144,'全唐诗/poet.song.129000.json','["荒林梟獨嘯，野水鵝群鳴。", "我坐蓬窗下，答以讀書聲。", "悲哉白髮翁，世事已飽更。", "一身不自恤，憂國涕縱横。", "永懷天寶末，李郭出治兵。", "河北雖未下，要是復兩京。", "三千同德士，百萬羽林營。", "歲周一甲子，不見胡塵清。", "賊酋實孱王，賊將非人英。", "如何失此時，坐待奸雄生。", "我死骨即朽，靑史亦無名。", "此詩倘不作，丹心尚誰明。"]'),
('4aa15f7f-f48a-40e7-a7db-087d1f1c8ed5','宿能仁寺','陸游','宋','宋诗','song-poetry','','[]','小雨暗江城，倦客寄僧榻。',48,'全唐诗/poet.song.129000.json','["小雨暗江城，倦客寄僧榻。", "孤燈如秋螢，清夜自開闔。", "遥憐萍青青，厭聽鼃閤閤。", "窗明竟無寐，卯酒倒殘榼。"]'),
('651d8824-dd47-4833-aa67-81a2b7199e27','寄題方伯謨遠庵','陸游','宋','宋诗','song-poetry','','[]','方侯胸中負經濟，議論源源有根柢。',64,'全唐诗/poet.song.129000.json','["方侯胸中負經濟，議論源源有根柢。", "借令不用老山林，尚欲著書垂萬世。", "百年苦短萬世長，榮利一時真聚蚋。", "渠曹定自别肺肝，今夕不爲明旦計。"]'),
('88d7a183-e108-4bb4-9f27-f0df00ab062e','雨中宿石帆山下民家','陸游','宋','宋诗','song-poetry','','[]','老覺山行倦，閑便水宿幽。',48,'全唐诗/poet.song.129000.json','["老覺山行倦，閑便水宿幽。", "雨泥看放鴨，烟草聽呼牛。", "槃箸煩頻勸，窗扉喜小留。", "餘年竟何事，高枕送悠悠。"]'),
('361a5189-58d4-4014-8653-13207f8392c1','中夜雨霽月色入户起飲酒一杯作絕句','陸游','宋','宋诗','song-poetry','','[]','吹盡浮雲天宇清，城頭疊鼓報三更。',32,'全唐诗/poet.song.129000.json','["吹盡浮雲天宇清，城頭疊鼓報三更。", "平生無此一杯酒，玉笥峰頭看月生。"]'),
('a199b250-1b6d-4b3e-8884-e4e9ec6ad9cd','贈石帆老人','陸游','宋','宋诗','song-poetry','','[]','地僻林深客到稀，高舂未起閉柴扉。',64,'全唐诗/poet.song.129000.json','["地僻林深客到稀，高舂未起閉柴扉。", "新松鬱鬱三千本，密竹蕭蕭一尺圍。", "溪叟旋分菰米滑，山童新采蕨芽肥。", "因君更作長閑想，麟閣雲臺竟是非。"]'),
('8f763cb8-c56f-4ccf-9938-d5e013cc3860','溪上醉吟','陸游','宋','宋诗','song-poetry','','[]','行行不知溪路深，但怪素月生遥岑。',32,'全唐诗/poet.song.129000.json','["行行不知溪路深，但怪素月生遥岑。", "不辭醉袖拂花絮，與子更醉青蘿陰。"]'),
('8fa57228-f2c7-44fc-9bc3-000df83bca8d','囚山','陸游','宋','宋诗','song-poetry','','[]','垣屋參差綠樹邊，囚山光景餞華顛。',64,'全唐诗/poet.song.129000.json','["垣屋參差綠樹邊，囚山光景餞華顛。", "平川極目思秦地，大澤浮空憶楚天。", "刺虎射麋俱已矣，舉杯開劍忽悽然。", "此生終遣英雄笑，棘沒銅駝六十年。"]'),
('76213408-2d8a-46a0-b655-eeab74936f1e','小園','陸游','宋','宋诗','song-poetry','','[]','松菊僅三畝，作園真強名。',48,'全唐诗/poet.song.129000.json','["松菊僅三畝，作園真強名。", "馴禽驚不去，熟果墜無聲。", "倦就盤陀坐，閑拈楖栗行。", "茅亭亦疏豁，憑檻看春耕。"]'),
('69ade165-d488-4850-b0d3-cf8d5ed180f0','鄉人或病予詩多道蜀中遨樂之盛適春日遊鏡湖共請賦山陰風物遂即杯酒間作四絕句却當持以誇西州故人也  其一','陸游','宋','宋诗','song-poetry','','[]','嫩日輕雲淡沲天，撲燈過後賣花前。',32,'全唐诗/poet.song.129000.json','["嫩日輕雲淡沲天，撲燈過後賣花前。", "便從水閣杭湖去，捲起朱簾上畫船。"]'),
('dbc77ffe-b703-4f1a-8bd8-e88093c6a607','鄉人或病予詩多道蜀中遨樂之盛適春日遊鏡湖共請賦山陰風物遂即杯酒間作四絕句却當持以誇西州故人也  其二','陸游','宋','宋诗','song-poetry','','[]','舫子窗扉面面開，金壺桃杏間尊罍。',32,'全唐诗/poet.song.129000.json','["舫子窗扉面面開，金壺桃杏間尊罍。", "東風忽送笙歌近，一片樓臺泛水来。"]'),
('0fdd97fb-a6fc-4523-90ac-583f680bed65','鄉人或病予詩多道蜀中遨樂之盛適春日遊鏡湖共請賦山陰風物遂即杯酒間作四絕句却當持以誇西州故人也  其三','陸游','宋','宋诗','song-poetry','','[]','湖波緑似鴨頭深，一日春晴直萬金。',32,'全唐诗/poet.song.129000.json','["湖波緑似鴨頭深，一日春晴直萬金。", "好事誰家鬭歌舞，方舟齊榜出花陰。"]'),
('3267578b-a834-41db-a3a8-d79834f40d06','鄉人或病予詩多道蜀中遨樂之盛適春日遊鏡湖共請賦山陰風物遂即杯酒間作四絕句却當持以誇西州故人也  其四','陸游','宋','宋诗','song-poetry','','[]','花光柳色滿牆頭，病酒今朝懶出遊。',32,'全唐诗/poet.song.129000.json','["花光柳色滿牆頭，病酒今朝懶出遊。", "却就水亭開小宴，繡簾銀燭看歸舟。"]'),
('cfb00e02-efeb-40a9-b4b3-18361d7a79a6','病中','陸游','宋','宋诗','song-poetry','','[]','風雨暗江天，幽窗起復眠。',48,'全唐诗/poet.song.129000.json','["風雨暗江天，幽窗起復眠。", "忍窮安晚境，留病壓災年。", "客助修琴料，僧分買藥錢。", "餘生均逆旅，未死且陶然。"]'),
('45ea05f8-51c6-48a8-8995-efe1de232448','病起','陸游','宋','宋诗','song-poetry','','[]','開歲忽六十，病餘閑炷香。',48,'全唐诗/poet.song.129000.json','["開歲忽六十，病餘閑炷香。", "春光向客淡，夜漏爲愁長。", "已老鷄豚社，永違鵷鷺行。", "蒼龍西角月，孤夢墮微茫。"]'),
('edf3043c-2dd5-408e-b403-3b749c79a7f1','小築','陸游','宋','宋诗','song-poetry','','[]','小築茅茨鏡水濱，天敎靜處著閑身。',64,'全唐诗/poet.song.129000.json','["小築茅茨鏡水濱，天敎靜處著閑身。", "平原不復賦豪士，甫里但思歌散人。", "翠壁微泉時的皪，衡門疉嶂曉嶙峋。", "子虚誤辱諸公賞，萬里輕鷗豈易馴。"]'),
('fb717569-fa49-4f9e-97a8-9b8ec938a487','記夢','陸游','宋','宋诗','song-poetry','','[]','東吳春暮寒猶重，睡美不聞城角動。',64,'全唐诗/poet.song.129000.json','["東吳春暮寒猶重，睡美不聞城角動。", "身雖衰惰怕出門，江山尚入幽窗夢。", "夢到青羊看修竹，道人告我丹將熟。", "試求一黍換肝腸，它日重来駕黄鵠。"]'),
('9e1fe10b-33e2-403a-8787-9a83e6bb5457','久雨排悶','陸游','宋','宋诗','song-poetry','','[]','一春略無十日晴，雨脚纔斷雲已生。',96,'全唐诗/poet.song.129000.json','["一春略無十日晴，雨脚纔斷雲已生。", "奇葩摧敗等青莧，嘉穀漂蕩隨浮萍。", "書生病臥苔及榻，濕薪燎衣熏欲盲。", "腰頑足痺空嘆息，咫尺不得行中庭。", "讀書窗黑不見字，彈琴弦緩那成聲。", "老盆濁酒且復醉，兩部鼓吹方施行。"]'),
('0a0c1dbd-1fec-47de-8f58-b2ad78bbb831','雨中泊舟蕭山縣驛','陸游','宋','宋诗','song-poetry','','[]','端居無策散閑愁，聊作人間汗漫遊。',64,'全唐诗/poet.song.129000.json','["端居無策散閑愁，聊作人間汗漫遊。", "晚笛隨風来倦枕，春湖带雨送孤舟。", "店家菰飯香初熟，市擔蓴絲滑欲流。", "自笑勞生成底事，黄塵陌上雪蒙頭。"]'),
('26bea399-44fb-42cf-8972-314c79971909','夜漏欲盡行度浮橋至錢清驛待舟','陸游','宋','宋诗','song-poetry','','[]','潮生抹沙岸，雲薄漏月明。',96,'全唐诗/poet.song.129000.json','["潮生抹沙岸，雲薄漏月明。", "江頭曉色動，鴉起人未行。", "扶攜度長橋，仰視天宇清。", "遥憐繫舟人，聽我高屐聲。", "水檻得小憩，一笑拄杖横。", "澄漪弄孤影，微風吹宿酲。", "湛然方寸間，不受塵事攖。", "寄語市朝人，此樂未易名。"]'),
('f0ddf461-e107-4e5a-b105-44c60258a14b','江頭十日雨','陸游','宋','宋诗','song-poetry','','[]','江頭十日雨，雨止春已盡。',72,'全唐诗/poet.song.129000.json','["江頭十日雨，雨止春已盡。", "殘紅如掃空，草木皆綠潤。", "村墟櫻筍鬧，節物團糉近。", "可憐笠澤翁，百憂集雙鬢。", "賦詩空自清，學道了不進。", "林間一甌茶，晤語君勿吝。"]'),
('96141b7f-4c36-47b1-8550-9563ea7d8e51','柯橋客亭二首  其一','陸游','宋','宋诗','song-poetry','','[]','小市初晴已過春，朱櫻青杏一番新。',32,'全唐诗/poet.song.129000.json','["小市初晴已過春，朱櫻青杏一番新。", "灞陵老子無人識，暫借郵亭整角巾。"]'),
('dd416f89-7b85-4665-a95f-213df7602671','柯橋客亭二首  其二','陸游','宋','宋诗','song-poetry','','[]','梅子生仁燕護雛，遶簷新葉緑扶疏。',32,'全唐诗/poet.song.129000.json','["梅子生仁燕護雛，遶簷新葉緑扶疏。", "朝来酒興不可耐，買得釣船雙鱖魚。"]'),
('02ad052b-cb3a-4bad-9bcf-3c6e1dddb81d','小雨舟過梅市','陸游','宋','宋诗','song-poetry','','[]','故故催詩襯雨蓬，悠悠破夢隔雲鐘。',64,'全唐诗/poet.song.129000.json','["故故催詩襯雨蓬，悠悠破夢隔雲鐘。", "遥看漁火兩三點，已過暮山千萬峰。", "老矣自應埋病骨，歸哉莫念抗塵容。", "停橈小住青楓岸，吴市高人儻可逢。"]'),
('82737751-024e-4d14-b841-15243c5d9b72','曉枕','陸游','宋','宋诗','song-poetry','','[]','曉枕鶯聲带夢聽，忽看淡日滿窗櫺。',32,'全唐诗/poet.song.129000.json','["曉枕鶯聲带夢聽，忽看淡日滿窗櫺。", "閑愁誰遣濃如酒，醉過殘春不解酲。"]'),
('ed35aa04-a185-4e89-a622-9e946565d1ba','巢菜','陸游','宋','宋诗','song-poetry','','[]','冷落無人佐客庖，庾郎三九困譏嘲。',32,'全唐诗/poet.song.129000.json','["冷落無人佐客庖，庾郎三九困譏嘲。", "此行忽似蟆津路，自候風爐煮小巢。"]'),
('04a93086-d2a1-4240-a156-dc6178089ebf','吳娘曲','陸游','宋','宋诗','song-poetry','','[]','鏡奩蠶出千黑蟻，釵梁梅小雙青豆。',64,'全唐诗/poet.song.129000.json','["鏡奩蠶出千黑蟻，釵梁梅小雙青豆。", "吳娘十四未知愁，羅衣已覺傷春瘐。", "閑尋女伴過西家，鬬草歸来日未斜。", "睡睫濛濛嬌欲閉，隔簾微雨壓楊花。"]'),
('d83aa270-b495-488a-99af-3f9077793cf5','感舊','陸游','宋','宋诗','song-poetry','','[]','醉眼常輕兒女曹，西遊對客尚能豪。',64,'全唐诗/poet.song.129000.json','["醉眼常輕兒女曹，西遊對客尚能豪。", "縷金羯鼓龜兹樂，鏤玉琵琶邏逤槽。", "巫峽已回行雨夢，錦江空憶浣花遨。", "閑情何計都除盡，爲覓并州快剪刀。"]'),
('90f93966-8a09-4230-8e09-671b3fb08361','晨起閑步','陸游','宋','宋诗','song-poetry','','[]','飛紅掠地送春忙，嫰綠成陰带露香。',32,'全唐诗/poet.song.129000.json','["飛紅掠地送春忙，嫰綠成陰带露香。", "聽徹曉天鶯百囀，却隨飛蝶度横塘。"]'),
('adf05b07-056c-48e1-8ffc-b0527aabc197','初夏同桑甥世昌過鄰家','陸游','宋','宋诗','song-poetry','','[]','空谷舊生涯，蕭條只自嗟。',48,'全唐诗/poet.song.129000.json','["空谷舊生涯，蕭條只自嗟。", "妻饞嗔護筍，兒病失澆花。", "赤米老能飽，濁醪貧可賖。", "徴科幸差簡，扶杖過鄰家。"]'),
('9a372916-0c01-4196-9abe-60a25e219cb8','寓嘆','陸游','宋','宋诗','song-poetry','','[]','孤生拙料事，諸老誤知人。',48,'全唐诗/poet.song.129000.json','["孤生拙料事，諸老誤知人。", "世故幾翻覆，此身常賤貧。", "有書藏禹穴，無地靜胡塵。", "衰病今年劇，呻吟欲過旬。"]'),
('78c2ef9a-13de-4b81-8a68-f2d344e45bf2','春夏雨暘調適頗有豐歲之望喜而有作','陸游','宋','宋诗','song-poetry','','[]','二十年無赤白囊，人間何地不耕桑。',64,'全唐诗/poet.song.129000.json','["二十年無赤白囊，人間何地不耕桑。", "陂塘處處分秧遍，村落家家煮繭忙。", "野老逢年知飽暖，書生隨例得猖狂。", "雨餘天氣初清潤，曵履長歌出草堂。"]'),
('cabebb32-e33e-4c04-b045-090cabd481da','聞虜酋遁歸漠北','陸游','宋','宋诗','song-poetry','','[]','幽州遺民欵塞来，来者扶老携其孩。',128,'全唐诗/poet.song.129000.json','["幽州遺民欵塞来，来者扶老携其孩。", "共言單于遠逃遁，一夕荆棘生燕臺。", "天威在上賊膽破，捧頭鼠竄吁可哀。", "妄期舊穴得孳育，不知天網方恢恢。", "老上龍庭豈不遠，漢兵一炬成飛灰。", "陛下中興天所命，築壇授鉞皆雄才。", "煌煌九霄掲日月，浩浩萬里行風雷。", "虢山多獸可遊獵，汝不請命何歸哉。"]'),
('0af4656d-cabf-40ca-843e-2b0d82adf9c4','初夏遊凌氏小園','陸游','宋','宋诗','song-poetry','','[]','水滿池塘葉滿枝，曲廊危榭愜幽期。',64,'全唐诗/poet.song.129000.json','["水滿池塘葉滿枝，曲廊危榭愜幽期。", "風和海燕分泥處，日永吳蠶上簇時。", "閑理阮咸尋舊譜，細傾白墮賦新詩。", "從来夏淺勝春日，兒女紛紛豈得知。"]'),
('f948ce71-2d40-4fd2-a903-5faba2c5362e','偶得北虜金泉酒小酌賦絕句二首  其一','陸游','宋','宋诗','song-poetry','','[]','草草杯盤莫笑貧，朱櫻羊酪也嘗新。',32,'全唐诗/poet.song.129000.json','["草草杯盤莫笑貧，朱櫻羊酪也嘗新。", "燈前耳熱顛狂甚，邊酒誰言不醉人。"]'),
('3ef13dc6-6e1e-486e-a36c-ba369eb22eff','偶得北虜金泉酒小酌賦絕句二首  其二','陸游','宋','宋诗','song-poetry','','[]','逆胡萬里跨燕秦，志士悲歌泪滿巾。',32,'全唐诗/poet.song.129000.json','["逆胡萬里跨燕秦，志士悲歌泪滿巾。", "未履戰塲齊奏凱，一樽先醉范陽春。"]'),
('31870a68-b9bb-4dcf-ab14-f77a0533d376','無題','陸游','宋','宋诗','song-poetry','','[]','珠鞲玉指擘箜篌，誰記山南秉燭遊。',64,'全唐诗/poet.song.129000.json','["珠鞲玉指擘箜篌，誰記山南秉燭遊。", "結綺詩成江令醉，橐泉夢斷沈郎愁。", "天涯落日孤鴻沒，鏡裏流年兩鬢秋。", "不用更求驅豆術，人生離合判悠悠。"]'),
('fc63a5f0-32da-47b2-9c64-8af06f720d41','戲贈','陸游','宋','宋诗','song-poetry','','[]','簾幕陰陰晝漏遲，鵝黄雪白絡新絲。',32,'全唐诗/poet.song.129000.json','["簾幕陰陰晝漏遲，鵝黄雪白絡新絲。", "只應笑殺東鄰女，不見鞦韆到折時。"]'),
('193f2677-191b-4fcf-95f7-d21bfb4cec61','題少陵畫像','陸游','宋','宋诗','song-poetry','','[]','長安落葉紛可掃，九陌北風吹馬倒。',64,'全唐诗/poet.song.129000.json','["長安落葉紛可掃，九陌北風吹馬倒。", "杜公四十不成名，袖裏空餘三賦草。", "車聲馬聲喧客枕，三百青銅市樓飲。", "杯殘炙冷正悲辛，仗內鬭雞催賜錦。"]'),
('8b4977da-72b9-425b-adaa-5e8887dce2cc','閑居書事','陸游','宋','宋诗','song-poetry','','[]','園林綠葉一番新，桃李吹成陌上塵。',64,'全唐诗/poet.song.129000.json','["園林綠葉一番新，桃李吹成陌上塵。", "玩易焚香消永日，聽琴煮茗送殘春。", "隱居正欲求吾志，大患元因有此身。", "堪笑癡人營冨貴，百年贏得冢前麟。"]'),
('4de2fc29-c544-4855-8abf-b64160cdced5','登臺遇雨避於山亭晚霽乃歸','陸游','宋','宋诗','song-poetry','','[]','溽暑不堪蝸舍陋，瘦藤扶我上危臺。',64,'全唐诗/poet.song.129000.json','["溽暑不堪蝸舍陋，瘦藤扶我上危臺。", "搏禽俊鶻横空去，卷雨狂風掠野来。", "壯觀深知化工妙，幽尋却蹋夕陽回。", "悠然有喜君知否，屐齒留痕遍綠苔。"]'),
('5467604b-c879-455e-9613-606d5519bfc4','村居書觸目','陸游','宋','宋诗','song-poetry','','[]','雨霽郊原刈麥忙，風清門巷曬絲香。',64,'全唐诗/poet.song.129000.json','["雨霽郊原刈麥忙，風清門巷曬絲香。", "人饒笑語豐年樂，吏省徴科化日長。", "枝上花空閑蝶翅，林間葚美滑鶯吭。", "飽知遊宦無多味，莫恨爲農老故鄉。"]'),
('194c4d5a-d97f-4001-aab8-9c44418fed10','訪醫','陸游','宋','宋诗','song-poetry','','[]','衰與病相乘，況復積憂慮。',72,'全唐诗/poet.song.129000.json','["衰與病相乘，況復積憂慮。", "眩昏坐輒瞑，疲弱行欲仆。", "今晨訪之醫，見語疾當去。", "脉来如泉源，未易測君數。", "盛衰當自察，信醫固多誤。", "養氣勿動心，生死良細故。"]'),
('b11d5e39-4805-49aa-a91e-6f3f08c80107','夏夜讀書自嘲','陸游','宋','宋诗','song-poetry','','[]','事業無成去日遒，只今身世付滄洲。',64,'全唐诗/poet.song.129000.json','["事業無成去日遒，只今身世付滄洲。", "風烟慘慘菰蒲老，星斗離離河漢流。", "寂寞書生學奇字，窮愁客子著春秋。", "白頭自苦君無笑，骨朽成塵志未休。"]'),
('245f3a4a-98aa-41b9-a3f1-b36e1d14d91d','夏日小宴','陸游','宋','宋诗','song-poetry','','[]','横吹銅笛蒼龍聲，雙奏玉笙丹鳳鳴。',64,'全唐诗/poet.song.129000.json','["横吹銅笛蒼龍聲，雙奏玉笙丹鳳鳴。", "已判百年終醉死，要將一笑壓愁生。", "旋移畫舫破山影，高捲朱簾延月明。", "試問炎歊在何許，夜闌翻怯葛衣輕。"]'),
('b5e2a4e1-7d9b-4adc-88a2-d5aa19daf603','送紫霄女道士四明謝君二首','陸游','宋','宋诗','song-poetry','','[]','一别南充十四年，時時清夢到金泉。',64,'全唐诗/poet.song.129000.json','["一别南充十四年，時時清夢到金泉。", "山陰道上秋風早，却見神仙小自然。", "道骨仙風凛不群，清秋采藥到江村。", "自言家住雲南北，知是遺塵幾世孫。"]'),
('9124aca1-062d-4335-868d-31e9cfc0ab2e','醉中夜自村市歸','陸游','宋','宋诗','song-poetry','','[]','村市夜騎黄犢還，却登小閣倚闌干。',64,'全唐诗/poet.song.129000.json','["村市夜騎黄犢還，却登小閣倚闌干。", "銀河斜界曉天碧，璧月下入秋江寒。", "吾輩身閑且飲酒，人生事定須闔棺。", "元自胸中著雲夢，莫驚緑鬢耐悲歡。"]'),
('6d373091-d887-4955-8a19-0ac4f8e06281','城北夜','陸游','宋','宋诗','song-poetry','','[]','端居厭孤寂，偶繫北城舟。',48,'全唐诗/poet.song.129000.json','["端居厭孤寂，偶繫北城舟。", "天地凄凉色，江湖汗漫遊。", "螢光矜暗夜，蟲語報新秋。", "老去功名意，青燈映布裯。"]'),
('0ed3e043-d133-4ad1-8bb0-b543c3e0ac3b','秋夜舟中作','陸游','宋','宋诗','song-poetry','','[]','沽酒黄葉村，炊飯紅蓼岸。',72,'全唐诗/poet.song.129000.json','["沽酒黄葉村，炊飯紅蓼岸。", "居人不孰何，正作漁父看。", "漁父我所羨，尚恐不得作。", "讀書端自癡，遊宦亦何樂。", "四顧澤茫茫，仰視天離離。", "長歌入雲去，月落斗未欹。"]'),
('5c29e425-dbf0-44fa-8913-5fa1e2add64d','日晚散步湖上遇小雨','陸游','宋','宋诗','song-poetry','','[]','暮色蒼蒼日初落，寒聲策策風正作。',96,'全唐诗/poet.song.129000.json','["暮色蒼蒼日初落，寒聲策策風正作。", "湖邊倚杖隄上行，病起聊試遊山脚。", "平生出門輕萬里，老去謝客專一壑。", "風濤澒洞鮫鰐横，閶闔崔嵬鬼神惡。", "春蕪二頃叱黄犢，老學爲農元不錯。", "兜鍪蟬冕俱掃空，雨笠香新織青篛。"]'),
('3c9a7ec3-9858-4509-9ead-348c78ae7143','安期篇','陸游','宋','宋诗','song-poetry','','[]','我昔遊岷峨，捫蘿千仞峰。',96,'全唐诗/poet.song.129000.json','["我昔遊岷峨，捫蘿千仞峰。", "丈人倚赤藤，恐是安期翁。", "贈我一丸藥，五雲出瓢中。", "服之未轉刻，瑩然冰雪容。", "素手掬山靄，緑髮吹天風。", "丈人顧我喜，共騎一蒼龍。", "蓬莱亦何求，愛此萬里空。", "却来過齊州，螘垤看青嵩。"]'),
('31de84b5-63fc-4f3d-bcda-aaaa3b18ca0e','曉望海山','陸游','宋','宋诗','song-poetry','','[]','暮山青尚淺，曉山如黛染。',96,'全唐诗/poet.song.129000.json','["暮山青尚淺，曉山如黛染。", "開窗望海山，天清霧方斂。", "向来六月中，黑雲齊如截。", "蒼龍下曵尾，卷雨灑炎熱。", "造物信老手，忽作萬里秋。", "刻削此孤峭，巉然消客愁。", "豈無一布帆，寄我浩蕩意。", "會當駕長風，清嘯遺世事。"]'),
('6a0789e6-257d-44bf-a1d8-3e2eb4cf1056','山園草木四絕句 紫薇','陸游','宋','宋诗','song-poetry','','[]','鐘鼓樓前宫様花，誰令流落到天涯。',32,'全唐诗/poet.song.129000.json','["鐘鼓樓前宫様花，誰令流落到天涯。", "少年妄想今除盡，但愛清樽浸晚霞。"]'),
('7bc3238a-144f-4d79-9718-a1148333ef4a','山園草木四絕句 黄蜀葵','陸游','宋','宋诗','song-poetry','','[]','開時閑淡斂時愁，蘭菊應容預勝流。',32,'全唐诗/poet.song.129000.json','["開時閑淡斂時愁，蘭菊應容預勝流。", "剩欲持杯相領略，一庭風露不禁秋。"]'),
('65e67e0f-672f-4bf6-87d2-15b5a844e80f','山園草木四絕句 拒霜','陸游','宋','宋诗','song-poetry','','[]','滿庭黄葉舞西風，天地方收肅殺功。',32,'全唐诗/poet.song.129000.json','["滿庭黄葉舞西風，天地方收肅殺功。", "何事獨蒙青女力，牆頭催放數苞紅。"]'),
('10b27c6f-726b-43f3-95ce-e5a95a0664da','山園草木四絕句 蓼花','陸游','宋','宋诗','song-poetry','','[]','十年詩酒客刀州，每爲名花秉燭遊。',32,'全唐诗/poet.song.129000.json','["十年詩酒客刀州，每爲名花秉燭遊。", "老作漁翁猶喜事，數枝紅蓼醉清秋。"]'),
('9ee9a230-1df5-4406-b9fb-71c271ff4be8','賽神曲','陸游','宋','宋诗','song-poetry','','[]','叢祠千歲臨江渚，拜貺今年那可數。',96,'全唐诗/poet.song.129000.json','["叢祠千歲臨江渚，拜貺今年那可數。", "須晴得晴雨得雨，人意所向神輒許。", "嘉禾九穗持上府，廟前女巫遞歌舞。", "嗚嗚歌謳坎坎鼓，香烟成雲神降語。", "大餅如槃牲腯肥，再拜獻神神不違。", "晚来人醉相扶歸，蟬聲滿廟鎖斜暉。"]'),
('e1f9ad17-7641-427c-a9ff-b3fbe1b6c68e','夜中起讀書戲作二首  其一','陸游','宋','宋诗','song-poetry','','[]','髮已凋零齒已疏，忍饑白首臥蝸廬。',32,'全唐诗/poet.song.129000.json','["髮已凋零齒已疏，忍饑白首臥蝸廬。", "風聲忽轢蓬窗過，夜半呼燈起讀書。"]'),
('5879047f-fdce-4e93-8451-f8774817b0b1','夜中起讀書戲作二首  其二','陸游','宋','宋诗','song-poetry','','[]','滅虜區區計本疏，水邊喬木擁茅廬。',32,'全唐诗/poet.song.129000.json','["滅虜區區計本疏，水邊喬木擁茅廬。", "九原定發韓公笑，至老依然一束書。"]'),
('581c964c-b2b9-4096-902a-bd8ca4cce0de','秋夜出門觀月','陸游','宋','宋诗','song-poetry','','[]','六十衰翁適得閑，一秋無事掩柴關。',64,'全唐诗/poet.song.129000.json','["六十衰翁適得閑，一秋無事掩柴關。", "雁来慘淡沙場外，月出蒼茫雲海間。", "飲酒已衰猶愛客，著書初畢可藏山。", "此生終羨漁家樂，小艇常衝夕靄還。"]'),
('1f18fb0b-9834-49a7-9e87-cfed264212d0','雨中買酒鏡湖酒樓','陸游','宋','宋诗','song-poetry','','[]','陰風號大澤，暮雨上高樓。',48,'全唐诗/poet.song.129000.json','["陰風號大澤，暮雨上高樓。", "愁憶新豐酒，寒思季子裘。", "登臨天地迮，老病歲時遒。", "安得急裝去，北平防盛秋。"]'),
('6d21f447-44ee-454b-a2a4-df41bf0e7ba3','聞虜政衰亂掃蕩有期喜成口號二首  其一','陸游','宋','宋诗','song-poetry','','[]','正朔今年被百蠻，遥知喜色動天顔。',64,'全唐诗/poet.song.129000.json','["正朔今年被百蠻，遥知喜色動天顔。", "風雷傳號臨春水，貔虎移軍過玉關。", "博士已成封禪草，單于將就會朝班。", "孤臣老抱周南恨，壯觀空存夢想間。"]'),
('f385287d-2a80-4cc1-af9a-d5a007d79160','聞虜政衰亂掃蕩有期喜成口號二首  其二','陸游','宋','宋诗','song-poetry','','[]','遺虜遊魂豈足憂，漢家方運幄中籌。',64,'全唐诗/poet.song.129000.json','["遺虜遊魂豈足憂，漢家方運幄中籌。", "天開地闢逢千載，雷動風行遍九州。", "刁斗令嚴青海夜，旌旗色照鐵關秋。", "功名自是英豪事，不用君王萬户侯。"]'),
('ebab6013-5ad7-4229-b9c3-e42691777743','甲辰中秋無月十七夜獨皦然達旦','陸游','宋','宋诗','song-poetry','','[]','老覺人間無一欣，窮閻掃軌謝紛紛。',64,'全唐诗/poet.song.129000.json','["老覺人間無一欣，窮閻掃軌謝紛紛。", "已憑白露洗明月，更遣清風收亂雲。", "棲鵲揀枝寒未穩，斷鴻呼伴遠猶聞。", "病羸慵踏梧桐影，倚柱長吟夜向分。"]'),
('a919386f-b189-4c0b-b2a3-9f50233f3f57','悲秋','陸游','宋','宋诗','song-poetry','','[]','病後支離不自持，湖邊蕭瑟早寒時。',64,'全唐诗/poet.song.129000.json','["病後支離不自持，湖邊蕭瑟早寒時。", "已驚白髮馮唐老，又起清秋宋玉悲。", "枕上數聲新到雁，燈前一局欲殘棋。", "丈夫幾許襟懷事，天地無情似不知。"]'),
('aea0c678-2563-471a-bff2-8227ecc8bc39','農家秋晚戲詠','陸游','宋','宋诗','song-poetry','','[]','鞭地如鏡築我場，破礱玉粒輸官倉。',64,'全唐诗/poet.song.129000.json','["鞭地如鏡築我場，破礱玉粒輸官倉。", "九月野空天欲霜，甑中初喜新粳香。", "舍邊蕭蕭落葉多，野蠶出繭飛黄蛾。", "寒蔬種罷醉且歌，隻雞短紙賽園婆。"]'),
('ebcfd1d6-d3ce-458b-ab0d-2beb360f1f69','病中作','陸游','宋','宋诗','song-poetry','','[]','老鶴遼天興未窮，此生光景自匆匆。',64,'全唐诗/poet.song.129000.json','["老鶴遼天興未窮，此生光景自匆匆。", "家爲逆旅相逢處，身在嚴裝欲發中。", "澀眼尚于書有味，孤愁殊覺酒無功。", "揮戈草檄今誰記，歲晚江邊白髮翁。"]'),
('87340cb6-fce9-4bc5-9018-2525022c04f5','秋夜讀書','陸游','宋','宋诗','song-poetry','','[]','讀書喜夜長，著書悲齒暮。',72,'全唐诗/poet.song.129000.json','["讀書喜夜長，著書悲齒暮。", "平生企前哲，凜有庸人懼。", "吾廬大澤中，地曠北風怒。", "徂年凋草木，寒氣逼霜露。", "燈昏老眼闇，鈍馬行惡路。", "投枕卷未終，吾衰嘆非故。"]'),
('3415fc7d-a59b-4386-82e4-86501bceee0e','病起','陸游','宋','宋诗','song-poetry','','[]','頹垣破屋暗藜蒿，病起不知秋已高。',64,'全唐诗/poet.song.129000.json','["頹垣破屋暗藜蒿，病起不知秋已高。", "晨倚山楹群木脫，暮臨苔砌百蟲號。", "力殫編簡初何得，腰折塵埃只漫勞。", "賴有濁醪生耳熱，狂歌醉草寄吾豪。"]'),
('f2a195d6-c3bd-460e-aa38-8077df654b7a','晨起','陸游','宋','宋诗','song-poetry','','[]','孤夢忽自驚，小窗初送明。',72,'全唐诗/poet.song.129000.json','["孤夢忽自驚，小窗初送明。", "珍禽語庭樹，可愛不知名。", "向者事宦遊，塵土過半生。", "傳呼束带出，鼕鼕尚殘更。", "山居雖自由，晨起亦有程。", "洗硯拂書几，一笑愜幽情。"]'),
('c2d9e278-c50f-42c7-8945-9d4eb1d61a6f','秋夜','陸游','宋','宋诗','song-poetry','','[]','老病龍鍾不入城，濁醪麤飯餞餘生。',64,'全唐诗/poet.song.129000.json','["老病龍鍾不入城，濁醪麤飯餞餘生。", "未霜村舍秋先冷，無月江天夜自明。", "出塞雖慚平賊手，下帷聊喜讀書聲。", "山童睡熟青燈暗，自撥殘爐候藥鐺。"]'),
('1f31e3e4-673f-4c51-b3ea-6c4b8662b45b','雨中過東村','陸游','宋','宋诗','song-poetry','','[]','小雨空濛物象奇，偶扶藤杖過東陂。',64,'全唐诗/poet.song.129000.json','["小雨空濛物象奇，偶扶藤杖過東陂。", "墊巾風度人爭看，蠟屐年光我自悲。", "窮鬼有靈揮不去，死魔多力到無期。", "歸来笑向譍門說，且了浮生一首詩。"]'),
('66217a98-c65f-4c62-b015-2f73b894c9a3','山寺','陸游','宋','宋诗','song-poetry','','[]','寺門壓石危欲崩，槎牙老松挂蒼藤。',64,'全唐诗/poet.song.129000.json','["寺門壓石危欲崩，槎牙老松挂蒼藤。", "風傳上方出定磬，雨暗古殿長明燈。", "宿林野鶻驚復起，爭栗山童呼不譍。", "谿南聞道更幽絕，明日裂布縫行縢。"]'),
('234572af-b314-448c-b6d0-7867a3c13585','天王廣敎院在蕺山東麓予年二十餘時與老僧惠迪遊略無十日不到也淳熙甲辰秋觀潮海上偶繫舟其門曵杖再遊怳如隔世矣','陸游','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','遊山如讀書，深淺皆可樂。',96,'全唐诗/poet.song.129000.json','["遊山如讀書，深淺皆可樂。", "道邉小精舍，亦自一丘壑。", "凄凉四十年，始復重著脚。", "老僧逝已久，講座塵漠漠。", "當時童子輩，衰鬢亦蕭索。", "掃壁觀舊題，歲月真電雹。", "文章卑不傳，衣食窘如昨。", "出門意惘然，遼海渺孤鶴。"]'),
('66d29084-3d06-4a37-97ac-9e9830268397','江月歌','陸游','宋','宋诗','song-poetry','','[]','放翁平生一釣船，秋水未落江渺然。',96,'全唐诗/poet.song.129000.json','["放翁平生一釣船，秋水未落江渺然。", "露洗玉宇清無烟，月輪徐行萬里天。", "人間聲利何足捐，浩歌看月冷不眠。", "孤鶴掠水来翩翩，似欲駕我從此仙。", "我寓紅塵今幾年，俛首韁鎖常自憐。", "樂哉揮手過月邉，西風未凋玉井蓮。"]'),
('bb207174-95fb-45b1-8c17-6ec584f1d23d','初寒書懷','陸游','宋','宋诗','song-poetry','','[]','嵩雲緱月本閑人，誤落塵中白髮新。',64,'全唐诗/poet.song.129000.json','["嵩雲緱月本閑人，誤落塵中白髮新。", "萬事看山差入眼，百年把酒獨關身。", "棧邊老馬行安往，床下寒龜息自勻。", "藜杖一枝猶好在，未妨閑探早梅春。"]'),
('ee0b3ca1-4aa3-4eb9-a641-beb48bff6f47','歲暮','陸游','宋','宋诗','song-poetry','','[]','小築幽栖與拙宜，讀書寫字伴兒嬉。',64,'全唐诗/poet.song.129000.json','["小築幽栖與拙宜，讀書寫字伴兒嬉。", "己無嘆老嗟卑意，却喜分冬守歲時。", "羮𦞦芳鮮新弋雁，衣襦輕暖自繅絲。", "農家歲暮真堪樂，說向公卿未必知。"]'),
('15641e30-718c-4b08-81ca-d86c23f55315','晨興','陸游','宋','宋诗','song-poetry','','[]','倦枕厭寒夜，起尋殘火溫。',48,'全唐诗/poet.song.129000.json','["倦枕厭寒夜，起尋殘火溫。", "喈喈衆雞動，耿耿一燈昏。", "野氣增霜力，窗光淡月痕。", "早朝非老事，且復灌吾園。"]'),
('fe9c93c2-a764-4f9d-b8b3-f0ab88a4c21c','村飲','陸游','宋','宋诗','song-poetry','','[]','少年喜任俠，見酒氣已吞。',120,'全唐诗/poet.song.129000.json','["少年喜任俠，見酒氣已吞。", "一飲但計日，斗斛何足論。", "緑草滿雉場，紅旗植毬門。", "三叫落烏幘，倒瀉黄金盆。", "銀爐熾獸炭，狐兔紛炮燔。", "浩歌撼空雲，壯志排帝閽。", "回首今幾時，去日如車奔。", "朱顔辭曉鏡，白髮老孤村。", "鄰翁勸黍酒，稚子供魚飱。", "功名信巳乎，萬事付乾坤。"]'),
('13868b20-3a87-4686-be28-26a54868c1b2','夜半讀書罷出門徙倚久之歸賦長句','陸游','宋','宋诗','song-poetry','','[]','浩歌曵杖出柴扉，不管三更露濕衣。',64,'全唐诗/poet.song.129000.json','["浩歌曵杖出柴扉，不管三更露濕衣。", "擬看林梢殘月上，偶逢浦口斷雲歸。", "驚鴻脫網寒相倚，饑鶻思巢夜亦飛。", "却掩北窗誰晤語，聊憑香盌洗塵鞿。"]'),
('501f263e-c2d1-4a06-b897-dfe7f0434bc3','曝書偶見舊稿有感','陸游','宋','宋诗','song-poetry','','[]','日滿晴軒理蠧魚，壯遊回首一欷歔。',64,'全唐诗/poet.song.129000.json','["日滿晴軒理蠧魚，壯遊回首一欷歔。", "凄凉王粲從軍作，零落相如諫獵書。", "歌吹恍思登北固，弓刀誰記渡南沮。", "虎頭本欠功名相，歸老林間計未疏。"]'),
('e6ff0ef6-3079-405f-8356-b0ae44bb1564','崑崙行','陸游','宋','宋诗','song-poetry','','[]','陰雲解駮朝暾紅，黄河直與崑崙通。',96,'全唐诗/poet.song.129000.json','["陰雲解駮朝暾紅，黄河直與崑崙通。", "不駕鸞鳳驂虬龍，徑躡香烟上空中。", "吾行忽過日月宮，下視積氣青濛濛。", "寒暑不分晝夜同，嵳峨九關常烈風。", "凜然蕭森變沖融，不悸不眩身如空。", "塵沙浩劫環無窮，詎須更覓安期翁。"]'),
('c208815f-cd9a-4ba6-a353-1ecb9f4e012e','一室','陸游','宋','宋诗','song-poetry','','[]','九萬笑鵬摶，幽居一室寛。',48,'全唐诗/poet.song.129000.json','["九萬笑鵬摶，幽居一室寛。", "雨聲便早睡，酒力壓新寒。", "懶覺閑多味，衰知死有端。", "此生吾自斷，不必夢邯鄲。"]'),
('2474f70a-09fb-4982-9a84-fea925705025','得所親廣州書','陸游','宋','宋诗','song-poetry','','[]','音信連年恨不聞，書来細讀却消魂。',64,'全唐诗/poet.song.129000.json','["音信連年恨不聞，書来細讀却消魂。", "人稀野店山魈語，路僻蠻村荔子繁。", "毒草自揺春寂寂，瘴雲不動晝昏昏。", "此生相見應無日，且置清愁近一樽。"]'),
('302c3479-43e6-4f01-91c0-3d6c33acf4e0','幽居戲詠','陸游','宋','宋诗','song-poetry','','[]','清泉遶屋竹連牆，回首微官意已忘。',64,'全唐诗/poet.song.129000.json','["清泉遶屋竹連牆，回首微官意已忘。", "小瓮带泥收洛筍，細鱗穿柳買河魴。", "黄旗萬里無侯骨，紅燭千鍾有酒腸。", "欲起九原誰可友，蘭亭修褉晉諸王。"]'),
('b87b68e3-06d6-422c-ab3d-3f0a5cc7faf7','幽事','陸游','宋','宋诗','song-poetry','','[]','蕭然四壁野人家，幽事還堪對客誇。',64,'全唐诗/poet.song.129000.json','["蕭然四壁野人家，幽事還堪對客誇。", "快日明窗閑試墨，寒泉古鼎自煎茶。", "桐凋無復吟風葉，蘋老猶殘泣露花。", "萬里封侯真已矣，只將高枕作生涯。"]'),
('2c5b298f-1897-4211-8472-48171908857e','初冬雜題六首  其一','陸游','宋','宋诗','song-poetry','','[]','勛業文章意已闌，暮年不足是看山。',32,'全唐诗/poet.song.129000.json','["勛業文章意已闌，暮年不足是看山。", "江南寺寺樓堪倚，安得身如杜牧閑。"]'),
('715e46db-5b6e-4201-9d69-f9ce5819ae43','初冬雜題六首  其二','陸游','宋','宋诗','song-poetry','','[]','暮嫌風雨作新寒，一樹青楓已半丹。',32,'全唐诗/poet.song.129000.json','["暮嫌風雨作新寒，一樹青楓已半丹。", "身在范寛圖畫裏，小樓西角剩憑闌。"]'),
('e24f9612-a93b-4140-a98a-c88401a6c4d2','初冬雜題六首  其三','陸游','宋','宋诗','song-poetry','','[]','風横雲低雨脚斜，一枝柔櫓暮咿啞。',32,'全唐诗/poet.song.129000.json','["風横雲低雨脚斜，一枝柔櫓暮咿啞。", "昏昏醉臥知何處，推起船篷忽到家。"]'),
('669c3e53-679a-4b73-8a9b-07df7c773dd0','初冬雜題六首  其四','陸游','宋','宋诗','song-poetry','','[]','五斗安能解醉酲，瞢騰睡眼怯窗明。',32,'全唐诗/poet.song.129000.json','["五斗安能解醉酲，瞢騰睡眼怯窗明。", "策勛賴有春芽在，臥聽山童轉磑聲。"]'),
('a0907aad-b4e9-4191-90f9-62634ca552ea','初冬雜題六首  其五','陸游','宋','宋诗','song-poetry','','[]','荒郊寒雨晚凄凄，四壁穿頹旋補泥。',32,'全唐诗/poet.song.129000.json','["荒郊寒雨晚凄凄，四壁穿頹旋補泥。", "物我元須各安穩，自苫牛屋織雞棲。"]'),
('12907fe2-800a-4c51-ac3e-6482cc3f9e17','初冬雜題六首  其六','陸游','宋','宋诗','song-poetry','','[]','風雨聲豪入夢中，不知身世寄孤蓬。',32,'全唐诗/poet.song.129000.json','["風雨聲豪入夢中，不知身世寄孤蓬。", "狐裘氊帽如龍馬，天漢西南小益東。"]'),
('86107c00-5dde-411b-af3d-5a84c97c541a','閉户','陸游','宋','宋诗','song-poetry','','[]','屏居無一事，閉户常經旬。',48,'全唐诗/poet.song.129000.json','["屏居無一事，閉户常經旬。", "勿云草舍陋，愛此油窗新。", "三日不作詩，幽禽語撩人。", "尺素雜行草，往檄江梅春。"]'),
('a3f423e3-1673-4f98-8ac2-ae18b2fddab1','十月四日夜記夢','陸游','宋','宋诗','song-poetry','','[]','四客聨轡来，我醉久不知。',144,'全唐诗/poet.song.129000.json','["四客聨轡来，我醉久不知。", "倒衣出迎客，愧謝前致辭。", "客意極疏豁，大笑軒鬚眉。", "禮豈爲我設，度外以相期。", "衮衮吐雄辯，泠泠誦新詩。", "共言攜酒壺，掃地臨前墀。", "意氣相顧喜，忽如少年時。", "老雞不解事，喚覺空嗟咨。", "涉世四十年，賢雋常追隨。", "爾来風俗壞，動脚墮險巇。", "森然義府刀，誰爲叔度陂。", "起作四客篇，捕影吾其癡。"]'),
('c963f21c-b031-4fe5-ad00-b9ddbe928952','西路口山店','陸游','宋','宋诗','song-poetry','','[]','日薄霜清十月天，馬蹄聲裏送流年。',64,'全唐诗/poet.song.129000.json','["日薄霜清十月天，馬蹄聲裏送流年。", "店當古路三乂處，山似孤雲兩角邊。", "淹泊自悲窮不醒，衰殘更著病相纏。", "榆關瀚海知何在，目送飛鴻入暮烟。"]'),
('98fade7b-2e14-40e7-aab8-63575bf8433e','題海首座俠客像','陸游','宋','宋诗','song-poetry','','[]','趙魏沙塵千丈黄，遺民膏血飽豺狼。',32,'全唐诗/poet.song.129000.json','["趙魏沙塵千丈黄，遺民膏血飽豺狼。", "功名不遣斯人了，無奈和戎白面郎。"]'),
('921271a1-e363-41ed-be9b-dbaf2df18371','送綽姪住庵吴興山中二首  其一','陸游','宋','宋诗','song-poetry','','[]','一杯淡粥不烹蔬，自占雲根結草廬。',32,'全唐诗/poet.song.129000.json','["一杯淡粥不烹蔬，自占雲根結草廬。", "非佛非心猶坐斷，定知不看夾山書。"]'),
('0ea7ba86-a63a-4ae0-a975-d39f774d28ef','送綽姪住庵吴興山中二首  其二','陸游','宋','宋诗','song-poetry','','[]','湖海相從十日留，頗哀老子鬢驚秋。',32,'全唐诗/poet.song.129000.json','["湖海相從十日留，頗哀老子鬢驚秋。", "目光猶射車牛背，不用殷勤舉話頭。"]'),
('2646ffc0-2fa8-484b-979d-6196598be936','冬夜與溥庵主說川食戲作','陸游','宋','宋诗','song-poetry','','[]','唐安薏米白如玉，漢嘉栮脯美勝肉。',96,'全唐诗/poet.song.129000.json','["唐安薏米白如玉，漢嘉栮脯美勝肉。", "大巢初生蠶正浴，小巢漸老麥米熟。", "龍鶴作羮香出釜，木魚瀹葅子盈腹。", "未論索餅與饡飯，最愛紅糟并缹粥。", "東来坐閱七寒暑，未嘗舉箸忘吾蜀。", "何時一飽與子同，更煎土茗浮甘菊。"]'),
('3e13fc74-fbc7-406c-b5d3-bd86c55b6be8','仗錫平老自都城回見訪索怡雲堂詩','陸游','宋','宋诗','song-poetry','','[]','東華軟塵飛撲帽，黄金絡馬人看好。',96,'全唐诗/poet.song.129000.json','["東華軟塵飛撲帽，黄金絡馬人看好。", "渠儂胸中誰得知，畏禍憂讒鬢先老。", "舉世輸與平元衡，青山白雲過一生。", "出門曵杖便千里，白雲不約常同行。", "敲門剝啄雲沒履，劇談未竟還東去。", "到山分我一片雲，併遣春風吹好句。"]'),
('5a23282f-7c89-47a3-97e9-56ca79f05b80','野飲','陸游','宋','宋诗','song-poetry','','[]','青山千載老英雄，濁酒三杯失阨窮。',64,'全唐诗/poet.song.129000.json','["青山千載老英雄，濁酒三杯失阨窮。", "訪古頽垣荒塹裏，覓交屠狗賣漿中。", "平堤漸放春蕪緑，細浪遥翻夕照紅。", "已把殘年付天地，騎牛吹笛伴村童。"]'),
('e245af11-ca12-4436-b1a3-66ac1cba684f','樊江觀梅','陸游','宋','宋诗','song-poetry','','[]','莫笑山翁老據鞍，探梅今夕到江干。',64,'全唐诗/poet.song.129000.json','["莫笑山翁老據鞍，探梅今夕到江干。", "半灘流水浸殘月，一夜清霜催曉寒。", "倚醉更教重秉燭，怕寒元自怯憑欄。", "誰知携客芳華日，曾費纏頭錦百端。"]'),
('fa19b76c-c9e1-4f89-9678-350f2fc7135c','山亭觀梅','陸游','宋','宋诗','song-poetry','','[]','與梅歲歲有幽期，忘却如今兩鬢絲。',64,'全唐诗/poet.song.129000.json','["與梅歲歲有幽期，忘却如今兩鬢絲。", "乘淡月時和雪看，斸蒼苔地带花移。", "先春瘦損應多恨，靜夜香来更一奇。", "醉倒欄邊君勿笑，明朝紅蕚綴空枝。"]'),
('86befba6-9588-4d90-932a-a972bfb5bb00','射的山觀梅二首  其一','陸游','宋','宋诗','song-poetry','','[]','射的山前雨墊巾，籬邊初見一枝新。',64,'全唐诗/poet.song.129000.json','["射的山前雨墊巾，籬邊初見一枝新。", "照谿盡洗驕春意，倚竹真成絕代人。", "餐玉元知非火食，化衣應笑走京塵。", "即今畫史無名手，試把清詩當寫真。"]'),
('a81deaa7-4101-4920-9308-86457a47f1c7','射的山觀梅二首  其二','陸游','宋','宋诗','song-poetry','','[]','凌厲冰霜節愈堅，人間乃有此癯仙。',64,'全唐诗/poet.song.129000.json','["凌厲冰霜節愈堅，人間乃有此癯仙。", "坐收國士無雙價，獨立東皇太一前。", "此去幽尋應盡日，向来别恨動經年。", "花中竟是誰流輩，欲許芳蘭恐未然。"]'),
('46075bce-9391-47a4-841f-1e98943cd8cc','别梅','陸游','宋','宋诗','song-poetry','','[]','竹籬數掩傍魚磯，萬點梅花掠地飛。',64,'全唐诗/poet.song.129000.json','["竹籬數掩傍魚磯，萬點梅花掠地飛。", "正喜巡簷来索笑，已悲臨水送將歸。", "影横月處愁空絕，子滿枝時事更非。", "自古情鍾在吾輩，尊前莫怪泪沾衣。"]'),
('97015f46-c748-4eb3-9d18-dcde68d77446','憶梅','陸游','宋','宋诗','song-poetry','','[]','護惜常愁滿樹開，況無一片在蒼苔。',64,'全唐诗/poet.song.129000.json','["護惜常愁滿樹開，況無一片在蒼苔。", "眼高懶爲凡花醉，腸斷驚聞暮角哀。", "寫向素綃時拂拭，移来幽圃自栽培。", "論心竟是明年事，輸與酴醿在酒杯。"]'),
('3c67a2b3-e63f-42da-b108-848b52dd5241','新晴午枕初起信筆','陸游','宋','宋诗','song-poetry','','[]','閉户日陶然，晴窗春已妍。',48,'全唐诗/poet.song.129000.json','["閉户日陶然，晴窗春已妍。", "華胥夢中國，龍漢劫初年。", "浩浩塵揚海，茫茫杵倚天。", "何妨駕孤鶴，小憩華山前。"]'),
('3965acce-e9c5-4f3a-a615-304c2227f102','乙巳早春','陸游','宋','宋诗','song-poetry','','[]','故故啼鶯傍曲廊，飛飛戲蝶度横塘。',64,'全唐诗/poet.song.129000.json','["故故啼鶯傍曲廊，飛飛戲蝶度横塘。", "病来對酒心雖怯，老去逢花眼尚狂。", "床擁琴書供枕籍，簾通風月索平章。", "一丘一壑從来事，起就功名未苦忙。"]'),
('5543e101-8196-4d3b-b64a-2d07a9e2a4ad','小雨','陸游','宋','宋诗','song-poetry','','[]','細細濕春光，霏霏破夕陽。',48,'全唐诗/poet.song.129000.json','["細細濕春光，霏霏破夕陽。", "臥聞驚倦枕，起看入虚堂。", "映葉鶯猶囀，爭泥燕正忙。", "閑愁無遣處，誰與共飛觴。"]'),
('945981dd-fd9c-4b35-a33b-f8421af2de9b','南⿰木養遇大風雨','陸游','宋','宋诗','song-poetry','','[]','嘆息誰如造物雄，故將意氣壓衰翁。',64,'全唐诗/poet.song.129000.json','["嘆息誰如造物雄，故將意氣壓衰翁。", "千群鐵馬雲屯野，百尺金蛇電掣空。", "身羡漁蓑鳴急雨，心憐鴉陣困狂風。", "世間變態誰能測，歸路斜陽十里紅。"]'),
('449c7aac-f74c-43d2-89e9-a74aeee8a3b5','春晚至山中因訪陳道人','陸游','宋','宋诗','song-poetry','','[]','一春衰病集殘骸，太息流塵覆酒杯。',64,'全唐诗/poet.song.129000.json','["一春衰病集殘骸，太息流塵覆酒杯。", "僧鉢始知蓴菜老，佛瓶初見杏花開。", "蘋溪小雨成幽討，松院斜陽又獨来。", "不爲愛閑從野叟，年来萬事學低摧。"]'),
('e2eed852-be19-44da-95c0-da289f97cd0d','小隱','陸游','宋','宋诗','song-poetry','','[]','小隱在江干，茆廬亦易安。',48,'全唐诗/poet.song.129000.json','["小隱在江干，茆廬亦易安。", "庖厨供白小，籬落蔓黄團。", "蹭蹬馮唐老，飄零范叔寒。", "世情從迫隘，醉眼覺天寛。"]'),
('3854319e-e2cb-4674-84dd-1c568cc49b68','春興','陸游','宋','宋诗','song-poetry','','[]','萬事不關身，翛然一幅巾。',48,'全唐诗/poet.song.129000.json','["萬事不關身，翛然一幅巾。", "雖非愛酒伴，猶是别花人。", "領略琴書意，掃空車馬塵。", "東阡與南陌，隨處夢殘春。"]'),
('dce7ecb9-8eed-4939-aeeb-80b4a2f91e79','曾仲躬見過適遇予出留小詩而去次韵二首  其一','陸游','宋','宋诗','song-poetry','','[]','地僻元無俗客来，蓬門只欲爲君開。',32,'全唐诗/poet.song.129000.json','["地僻元無俗客来，蓬門只欲爲君開。", "山横翠黛供詩本，麥卷黄雲足酒材。"]'),
('3256f42c-64bd-4377-a76c-b4f9bf72f0e9','曾仲躬見過適遇予出留小詩而去次韵二首  其二','陸游','宋','宋诗','song-poetry','','[]','數樹山花草舍東，想公繫馬落殘紅。',32,'全唐诗/poet.song.129000.json','["數樹山花草舍東，想公繫馬落殘紅。", "那知老子耶溪上，正泛朝南暮北風。"]'),
('87edcd15-cc77-4d2d-bf5b-c159fd053533','睡起','陸游','宋','宋诗','song-poetry','','[]','風約飛花滿曲廊，蕭然無客共焚香。',64,'全唐诗/poet.song.129000.json','["風約飛花滿曲廊，蕭然無客共焚香。", "瓮醅力重初投枕，鼻鼾聲豪已撼床。", "栩栩夢遊心自適，昏昏起坐日方長。", "靜憑一几吾何恨，笑殺穿簾燕子忙。"]'),
('d4220892-8cde-4a80-b927-c0c7f81ef89b','病起','陸游','宋','宋诗','song-poetry','','[]','山村病起帽圍寛，春盡江南尚薄寒。',64,'全唐诗/poet.song.129000.json','["山村病起帽圍寛，春盡江南尚薄寒。", "志士凄涼閑處老，名花零落雨中看。", "斷香漠漠便支枕，芳草離離悔倚闌。", "收拾吟牋停酒椀，年来觸事動憂端。"]'),
('38268c23-c50e-4ef4-9fe4-ec66c749c9aa','山居戲題二首  其一','陸游','宋','宋诗','song-poetry','','[]','海山縹緲斸雲扄，掃地焚香悦性靈。',64,'全唐诗/poet.song.129000.json','["海山縹緲斸雲扄，掃地焚香悦性靈。", "嫩白半甌嘗日鑄，硬黄一卷學蘭亭。", "衰顔冉冉臨清鏡，華髮蕭蕭倚素屏。", "尊酒不空身見在，莫爭天上少微星。"]'),
('3e5354f9-3e5e-43ea-a28d-9178ff0ac003','山居戲題二首  其二','陸游','宋','宋诗','song-poetry','','[]','病起清羸不自持，年光都上鬢邊絲。',64,'全唐诗/poet.song.129000.json','["病起清羸不自持，年光都上鬢邊絲。", "昏昏雨細梅黄後，漫漫秧青水滿時。", "曲几方床娛永日，矮冠高屐駭群兒。", "客来莫笑狂顛甚，此處那容世俗知。"]'),
('5a2eba55-5a36-428b-9c67-5cb1853e58a8','芒種後經旬無日不雨偶得長句','陸游','宋','宋诗','song-poetry','','[]','芒種初過雨及時，紗厨睡起角巾欹。',64,'全唐诗/poet.song.129000.json','["芒種初過雨及時，紗厨睡起角巾欹。", "癡雲不散常遮塔，野水無聲自入池。", "緑樹晚涼鳩語閙，畫梁晝寂燕歸遲。", "閑身自喜渾無事，衣覆熏籠獨誦詩。"]'),
('e81716fa-2b03-4e87-b542-abaffd219017','久雨喜晴十韵','陸游','宋','宋诗','song-poetry','','[]','一雨二十日，頽牆屋茆爛。',120,'全唐诗/poet.song.129000.json','["一雨二十日，頽牆屋茆爛。", "扶杖出門行，四顧水瀰漫。", "村迥鳩爭巢，村昏雞失旦。", "荒庭蛙黽豪，空廡螢火亂。", "蠧魚敗書編，萍草黏户半。", "清風忽東来，一剪雨脚斷。", "天青日杲杲，河白星燦燦。", "車轍尋舊途，船步出新岸。", "稍喜泥潦乾，破竈得炊爨。", "賤貧固多憂，長歌寄吾嘆。"]'),
('1e0a477e-5985-4309-888b-459d48dceec0','盆池','陸游','宋','宋诗','song-poetry','','[]','人生何處不兒嬉，一世元知孰是非。',64,'全唐诗/poet.song.129000.json','["人生何處不兒嬉，一世元知孰是非。", "汲井埋盆鑿苔破，敲針作釣得魚歸。", "蕭蕭菰葉風聲細，嫋嫋蘋花雨點稀。", "竝舍老翁能喜事，爲添拳石象苔磯。"]'),
('7e78d21c-6c51-4514-8681-0596f9266ecb','月中過蜻蜓浦','陸游','宋','宋诗','song-poetry','','[]','天光水色合爲一，舟出西城猶落日。',96,'全唐诗/poet.song.129000.json','["天光水色合爲一，舟出西城猶落日。", "一規忽見寒璧升，萬頃坐嘆溶銀溢。", "哀哀姑惡訴何苦，熠熠螢火光自失。", "葦低時見小艇過，水響遥知大魚出。", "銅壺玉酒我徑醉，短髮垂肩蓬不櫛。", "緩篙遡月勿遽行，坐待湘妃鼓瑶瑟。"]'),
('87b33997-85b9-4f03-9162-4234daa3ea8c','六峰項里看采楊梅連日留山中','陸游','宋','宋诗','song-poetry','','[]','綠陰翳翳連山市，丹實纍纍照路隅。',64,'全唐诗/poet.song.129000.json','["綠陰翳翳連山市，丹實纍纍照路隅。", "未愛滿盤堆火齊，先驚探頷得驪珠。", "斜簪寶髻看遊舫，細織筠籠入上都。", "醉裏自矜豪氣在，欲乘風露摘千株。"]'),
('853ac2e8-2bde-43fe-950e-7f14fd8efe66','雨中自項里夜至新塘捨舟步歸二首  其一','陸游','宋','宋诗','song-poetry','','[]','樺炬如椽點不明，還家潦水與階平。',32,'全唐诗/poet.song.129000.json','["樺炬如椽點不明，還家潦水與階平。", "一杯濁酒頽然睡，恍似金牛夜下程。"]'),
('7ba820cb-41eb-4c7c-844f-3619007145a5','雨中自項里夜至新塘捨舟步歸二首  其二','陸游','宋','宋诗','song-poetry','','[]','天如漆黑泥沒踝，老健猶能踸踔歸。',32,'全唐诗/poet.song.129000.json','["天如漆黑泥沒踝，老健猶能踸踔歸。", "裊裊爐香支枕看，終年只合掩柴扉。"]'),
('4b61ed7b-5506-4dc7-a62c-5717fc7c4674','夜聽竹間雨聲','陸游','宋','宋诗','song-poetry','','[]','解酲不用酒，聽雨神自清。',72,'全唐诗/poet.song.129000.json','["解酲不用酒，聽雨神自清。", "治疾不用藥，聽雨體自輕。", "我居萬竹間，蕭瑟送此聲。", "焚香倚蒲團，袖手坐三更。", "人苦不自覺，忿慾投隙生。", "起歃簷間雨，更與此君盟。"]'),
('28bbcd2d-e63a-4099-a5b9-45652da543df','泛三江海浦','陸游','宋','宋诗','song-poetry','','[]','鼇負三山碧海秋，龍驤萬斛放翁遊。',64,'全唐诗/poet.song.129000.json','["鼇負三山碧海秋，龍驤萬斛放翁遊。", "少舒我輩胸中氣，一掃群兒分外愁。", "醉斬長鯨倚天劍，笑凌駭浪濟川舟。", "悠然高詠平生事，齷齪寧能老故丘。"]'),
('e6bc1b8c-42cd-4a59-9429-df99669a7e20','獨酌有懷南鄭','陸游','宋','宋诗','song-poetry','','[]','憶從嶓冡涉南沮，笳鼓聲酣醉膽麤。',64,'全唐诗/poet.song.129000.json','["憶從嶓冡涉南沮，笳鼓聲酣醉膽麤。", "投筆書生古来有，從軍樂事世間無。", "秋風逐虎花叱撥，夜雪射熊金僕姑。", "白首功名元未晚，笑人四十嘆頭顱。"]'),
('c28e20c5-006f-4a0d-bfa1-f685003f87a2','秋日泛鏡中憩千秋觀','陸游','宋','宋诗','song-poetry','','[]','病起重来理釣絲，扁舟迨及素秋時。',64,'全唐诗/poet.song.129000.json','["病起重来理釣絲，扁舟迨及素秋時。", "舊交猶有青山在，幽趣唯應白鳥知。", "冉冉年光行老矣，茫茫世路欲何之。", "秦皇酒榼苔封遍，虚負霜螯左手持。"]'),
('c7e02b12-aea5-4f83-b476-39472bd4114e','秋夕虹橋舟中偶賦','陸游','宋','宋诗','song-poetry','','[]','解纜初離小市門，放篙衝破一谿雲。',64,'全唐诗/poet.song.129000.json','["解纜初離小市門，放篙衝破一谿雲。", "露螢合散自成陣，水鳥飛鳴如覓群。", "楓落荷疏秋漸老，河傾斗轉夜將分。", "書生老負功名志，醉裏長歌強一欣。"]'),
('5064de9c-b467-4bc0-a3fd-ff5a469d70e6','秋思','陸游','宋','宋诗','song-poetry','','[]','一徑苔侵四壁空，北窗支枕聽秋鐘。',64,'全唐诗/poet.song.129000.json','["一徑苔侵四壁空，北窗支枕聽秋鐘。", "故人去後登樓怯，白髮多来覽鏡慵。", "狂憶射麋窮楚澤，閑思釣雪泛吳松。", "相如病渴年来劇，釀酒傾家畏不供。"]'),
('23fcec31-ea10-44bd-97e3-76483ecf2039','自嘲','陸游','宋','宋诗','song-poetry','','[]','窮途久矣嘆吾衰，雙鬢新添幾縷絲。',64,'全唐诗/poet.song.129000.json','["窮途久矣嘆吾衰，雙鬢新添幾縷絲。", "身是在家狂道士，心如退院病禪師。", "極知勾漏求丹藥，不及衡陽賣漉籬。", "習氣若爲除未盡，小軒風月又成詩。"]'),
('9aac4bcc-4835-457a-b87a-f4656b230c1e','豐年行','陸游','宋','宋诗','song-poetry','','[]','秋風蕭蕭秋日薄，築場穫稻方竭作。',96,'全唐诗/poet.song.129000.json','["秋風蕭蕭秋日薄，築場穫稻方竭作。", "志士雖懷晚歲悲，農家自足豐年樂。", "撥醅白酒喚鄰曲，啄黍黄雞初束縳。", "長魚出網健欲飛，新兔臥盤肥可𦞦。", "躬耕辛苦四十年，一飽豈非天所酢。", "書生識字亦聊爾，莫作揚雄老投閣。"]'),
('be8b9ab0-c74c-4fef-b2ea-c514837c867b','秋夜泊舟亭山下','陸游','宋','宋诗','song-poetry','','[]','逢水逢山到處留，可憐身世寄孤舟。',64,'全唐诗/poet.song.129000.json','["逢水逢山到處留，可憐身世寄孤舟。", "一汀蘋露漁村晚，十里荷花野店秋。", "羽檄未聞傳塞外，金椎先報擊衙頭。", "煌煌太白高千丈，那得功名取次休。"]'),
('93ab2930-a23d-4c32-be32-bb1268ed9209','初秋山中作','陸游','宋','宋诗','song-poetry','','[]','萬里西風吹幅巾，即今真箇是閑人。',64,'全唐诗/poet.song.129000.json','["萬里西風吹幅巾，即今真箇是閑人。", "堆盤菱熟燕脂角，藉藻鱸新淡墨鱗。", "姥嶺蹇驢尋雪徑，娥江孤艇繫烟津。", "飄然樂事真當勉，遠付十年無此身。"]'),
('99547f0f-0658-431e-bce5-30efe9bfa4e5','秋夜讀書有感','陸游','宋','宋诗','song-poetry','','[]','久病畏長夏，枕簟如炮焚。',120,'全唐诗/poet.song.129000.json','["久病畏長夏，枕簟如炮焚。", "扶持賴藥物，俛仰秋已分。", "清夜炷爐香，裊裊起孤雲。", "靈府豁蒙滯，舊學資鉏耘。", "言念總角初，操觚極艱勤。", "諸老頗賞識，謂可與斯文。", "沉痼幸鍼石，輪囷勞斧斤。", "可憐四十年，薄陋負所聞。", "白首猶著書，逝將獻吾君。", "太官薦玉食，野人徒美芹。"]'),
('30e1f7f9-c46c-452f-9e62-e54d0f84e57f','晚涼登山亭','陸游','宋','宋诗','song-poetry','','[]','庭空葉飛秋，村迥鳩喚雨。',72,'全唐诗/poet.song.129000.json','["庭空葉飛秋，村迥鳩喚雨。", "新涼入巾褐，老子顛欲舞。", "憑高望稽山，秀色溢天宇。", "一鏡三百里，水落分别浦。", "凄涼吊禹穴，秦漢未爲古。", "世俗誰與歸，吾其老農圃。"]'),
('54675fc7-1132-440d-b7cb-3bbabe56cffc','夜步','陸游','宋','宋诗','song-poetry','','[]','市人莫笑雪蒙頭，北陌南阡信脚遊。',64,'全唐诗/poet.song.129000.json','["市人莫笑雪蒙頭，北陌南阡信脚遊。", "風逓鐘聲雲外寺，水揺燈影酒家樓。", "鶴歸遼海逾千歲，楓落吳江又一秋。", "却掩船扉耿無寐，半窗落月照清愁。"]'),
('4e5578b4-6127-4b40-a93e-4f9f16b21aa2','感秋','陸游','宋','宋诗','song-poetry','','[]','秋堂露氣清，蕭爽入毛骨。',96,'全唐诗/poet.song.129000.json','["秋堂露氣清，蕭爽入毛骨。", "葛裯耿無寐，坐待山月沒。", "濕螢飛不起，熠熠依衰草。", "勁風西北號，落葉紛可掃。", "老生惜歲月，烈士志功名。", "登臨送將去，非復兒女情。", "懸知青海邊，殺氣横千里。", "良時不可失，胡行速如鬼。"]'),
('5e0cef47-73c4-4a14-accb-897a39dd542d','病中作','陸游','宋','宋诗','song-poetry','','[]','一病二十日，直愁難自還。',48,'全唐诗/poet.song.129000.json','["一病二十日，直愁難自還。", "殘書不成讀，長夜只供閑。", "風舞迎霜葉，雲昏欲雨山。", "臨窗忽自笑，詩思又相關。"]'),
('f65bd92d-3dfb-4230-a2cb-a79e349da40f','送猷講主赴李明府姜山之招','陸游','宋','宋诗','song-poetry','','[]','貫花籖帙壓車轅，惟子窮探到本源。',64,'全唐诗/poet.song.129000.json','["貫花籖帙壓車轅，惟子窮探到本源。", "聽法鬼神環麈尾，質疑英俊集龍門。", "孤舟此日輕爲别，尺素何時遠見存。", "坐想文殊對摩詰，高談無礙九河翻。"]'),
('b594257a-fecd-4a76-8022-b28900d219e4','雨中排悶','陸游','宋','宋诗','song-poetry','','[]','點點滴滴雨不晴，暗暗淡淡燈不明。',96,'全唐诗/poet.song.129000.json','["點點滴滴雨不晴，暗暗淡淡燈不明。", "皇天胡爲貸此老，病臥垂困今已平。", "却慚向者力量淺，鼠肝蟲臂猶關情。", "百年終歸朝露速，一死正自秋毫輕。", "明朝且作山中行，青鞵已覺白雲生。", "豐年處處村酒好，莫教湘湖蓴菜老。"]'),
('ad35716d-1b8b-4ccd-b16a-0cb545aaa66b','秋夜歌','陸游','宋','宋诗','song-poetry','','[]','書生白首無處著，病臥空齋夜蕭索。',96,'全唐诗/poet.song.129000.json','["書生白首無處著，病臥空齋夜蕭索。", "茶鐺颼颼候湯熟，燈檠蓛蓛看燼落。", "山童喚起已復倒，顧影自笑如孤鶴。", "人言富貴墮駭機，一生窮愁正不惡。", "架上故裘破見肘，床頭殘酒傾到脚。", "問君何以鏖霜風，悠然臥聽山城角。"]'),
('b3e4e21c-d314-4340-a0e9-1e3db2d23402','病起鏡中見白髮此去七十無十寒暑矣偶得長句','陸游','宋','宋诗','song-poetry','','[]','短鬢蕭條失故青，人間真似宿郵亭。',64,'全唐诗/poet.song.129000.json','["短鬢蕭條失故青，人間真似宿郵亭。", "正令寛作十年夢，安用更留三日醒。", "覆瓿書成空自苦，擊轅歌罷遣誰聽。", "客来若覓衰翁處，睡起悠然倚素屏。"]'),
('ca31aa22-b8de-4bb8-a65e-c13f64b035e3','初寒宴坐','陸游','宋','宋诗','song-poetry','','[]','微火如螢度篆盤，明窗坐敗幾蒲團。',64,'全唐诗/poet.song.129000.json','["微火如螢度篆盤，明窗坐敗幾蒲團。", "群兒誰信老懷懶，萬事不禁醒眼看。", "道在簞瓢端自足，心閑天地本来寛。", "此生自斷君知否，不辦歸裝也挂冠。"]'),
('16583865-4394-4abf-a9a5-cdc0100230da','溪行二首  其一','陸游','宋','宋诗','song-poetry','','[]','霜落水初澄，星繁月未升。',48,'全唐诗/poet.song.129000.json','["霜落水初澄，星繁月未升。", "近村聞夜犬，隔浦見秋燈。", "多病乃如許，微寒已不勝。", "平生鄰曲意，移棹避漁罾。"]'),
('3068d27e-96ab-4c79-a7d5-22a6465ab3d9','溪行二首  其二','陸游','宋','宋诗','song-poetry','','[]','疏鐘度莽蒼，遠火耿微茫。',48,'全唐诗/poet.song.129000.json','["疏鐘度莽蒼，遠火耿微茫。", "歲暮水歸壑，夜寒天霣霜。", "人生一蟲臂，世路幾羊腸。", "老大忘繩檢，狂歌盡意長。"]'),
('d3397637-fa99-470b-96f4-d7fc8466712c','讀書','陸游','宋','宋诗','song-poetry','','[]','遠遯江湖上，端居風雨中。',48,'全唐诗/poet.song.129000.json','["遠遯江湖上，端居風雨中。", "紙新窗正白，爐暖火通紅。", "籖帙方重整，聲形且細窮。", "扶衰倘未死，更破十年功。"]'),
('de9275fb-e814-42f0-8a31-836a0fb79d6e','自嘲用前韵','陸游','宋','宋诗','song-poetry','','[]','殘年過六十，寂寞臥山中。',48,'全唐诗/poet.song.129000.json','["殘年過六十，寂寞臥山中。", "病眼驚新暗，衰顔失舊紅。", "人譏作詩瘦，自憫著書窮。", "輸與封侯骨，雲臺競策功。"]'),
('61b97738-f1c6-4e88-98dd-9573d59ab6b2','病中久廢遊覽悵然有感','陸游','宋','宋诗','song-poetry','','[]','裘馬清狂徧兩川，十年身是地行仙。',64,'全唐诗/poet.song.129000.json','["裘馬清狂徧兩川，十年身是地行仙。", "歸来訪舊半爲鬼，已矣此生休問天。", "不恨杯觴無藉在，但悲山水曠周旋。", "垂虹風月休如昨，安得青錢買釣船。"]'),
('b53d159b-ba55-404d-bb77-6f052249bbfe','新釀熟小飲二首  其一','陸游','宋','宋诗','song-poetry','','[]','玉船瀲瀲酌鵝黄，菊欲殘時抵死香。',32,'全唐诗/poet.song.129000.json','["玉船瀲瀲酌鵝黄，菊欲殘時抵死香。", "似與幽人爲醉地，清笳聲裏一天霜。"]'),
('baffea32-0b8e-4ccc-9667-a2456f80e6ec','新釀熟小飲二首  其二','陸游','宋','宋诗','song-poetry','','[]','籬菊猶堪采落英，一尊玉瀣釀初成。',32,'全唐诗/poet.song.129000.json','["籬菊猶堪采落英，一尊玉瀣釀初成。", "今宵要向中庭飲，不展華茵展月明。"]'),
('6f356f19-08a7-49d9-ae77-34b5cda128c9','題徐淵子環碧亭亭有茶山曾先生詩','陸游','宋','宋诗','song-poetry','','[]','茶山丈人厭囂譁，幅巾每訪博士家。',160,'全唐诗/poet.song.129000.json','["茶山丈人厭囂譁，幅巾每訪博士家。", "小亭談笑不知暮，往往城上聞吹笳。", "興来傑作粲珠璧，歲久妙墨亡龍蛇。", "郎君弟子多白髮，回頭日月如奔車。", "徐卿赤城古仙子，十年四海推才華。", "覽觀陳迹喜不寐，旋補罅漏支傾斜。", "曲池還浸古来月，樷莽忽見當時花。", "重題舊句照高棟，力振風雅排滛哇。", "席間紵袍已散鵠，堂上講鼓初停撾。", "速宜力置竹葉酒，不用更瀹桃花茶。"]'),
('cba3cfd3-7790-4f98-8d85-d829ae2919e3','雜興三首  其一','陸游','宋','宋诗','song-poetry','','[]','鰻井初生一縷雲，鮑郎山下雨昏昏。',32,'全唐诗/poet.song.129000.json','["鰻井初生一縷雲，鮑郎山下雨昏昏。", "櫓聲嘔軋秋空曉，水際人家尚閉門。"]'),
('81663e67-059c-4bd4-8a1b-5476e08c8e49','雜興三首  其二','陸游','宋','宋诗','song-poetry','','[]','孤夢初回揭短篷，橋邊曉日已曈曨。',32,'全唐诗/poet.song.129000.json','["孤夢初回揭短篷，橋邊曉日已曈曨。", "太平氣象君知否，盡在豐年笑語中。"]'),
('19f9bfaf-b3dc-4dc2-bf11-32748731c4fc','雜興三首  其三','陸游','宋','宋诗','song-poetry','','[]','古寺高樓暮倚闌，野雲不散白漫漫。',32,'全唐诗/poet.song.129000.json','["古寺高樓暮倚闌，野雲不散白漫漫。", "好山遮盡君無恨，且作滄溟萬里看。"]'),
('c1cca1a0-2f2a-40ac-a67c-e269d532a279','大雪','陸游','宋','宋诗','song-poetry','','[]','大雪江南見未曾，今年方始是嚴凝。',64,'全唐诗/poet.song.129000.json','["大雪江南見未曾，今年方始是嚴凝。", "巧穿簾罅如相覓，重壓林梢欲不勝。", "氊幄擲盧忘夜睡，金羈立馬怯晨興。", "此生自笑功名晚，空想黄河徹底冰。"]'),
('6d885019-1db3-4482-90d6-5b2b78fb079a','遣興','陸游','宋','宋诗','song-poetry','','[]','書生不自憐，老眼付皇天。',48,'全唐诗/poet.song.129000.json','["書生不自憐，老眼付皇天。", "已飽三升稷，寧堆百屋錢。", "紅塵忙過日，青嶂醉論年。", "名字元虚幻，從人謗是仙。"]'),
('bb5ee454-4c6c-44f6-8903-e84917682d82','委轡','陸游','宋','宋诗','song-poetry','','[]','委轡去悠悠，山窮得渡頭。',48,'全唐诗/poet.song.129000.json','["委轡去悠悠，山窮得渡頭。", "白雲生碧巘，翠木擁朱樓。", "野榼淵朙酒，征塵季子裘。", "自憐詩興在，杜若滿芳洲。"]'),
('001a7967-0e00-48b1-9a10-8dc52d66dcfb','雪中作','陸游','宋','宋诗','song-poetry','','[]','竹折松僵鳥雀愁，閉門我亦擁貂裘。',64,'全唐诗/poet.song.129000.json','["竹折松僵鳥雀愁，閉門我亦擁貂裘。", "已忘作賦遊梁苑，但憶衘枚入蔡州。", "屬國餐氊真強項，翰林煮茗自風流。", "明朝日暖君須記，更看青鴛玉半溝。"]'),
('719d9a35-532e-4514-84d9-5889575faf71','夢筆驛','陸游','宋','宋诗','song-poetry','','[]','朱扉水際亭，白塔道邊寺。',96,'全唐诗/poet.song.129000.json','["朱扉水際亭，白塔道邊寺。", "扁舟幾往返，每過輒歔欷。", "經秋病不死，歲暮復不至。", "少年自喧譁，此老獨憔悴。", "可憐釣鰲客，終返屠羊肆。", "吾身行亦無，榮辱安所寄。", "短燈照孤愁，寒衾推殘醉。", "明當臨大江，一灑壯士泪。"]'),
('ebca76bb-9820-44be-9951-b17ea12700ca','舟中感懷三絕句呈太傅相公兼簡岳大用郎中  其一','陸游','宋','宋诗','song-poetry','','[]','浪中鞺鞳雨聲寒，孤夢初回燭半殘。',32,'全唐诗/poet.song.129000.json','["浪中鞺鞳雨聲寒，孤夢初回燭半殘。", "甲子一周戎未滅，關山還带泪痕看。"]'),
('a092ff44-6797-4bcc-be3b-28ef30407f20','舟中感懷三絕句呈太傅相公兼簡岳大用郎中  其二','陸游','宋','宋诗','song-poetry','','[]','雨打孤篷酒漸消，昏燈與我共無聊。',32,'全唐诗/poet.song.129000.json','["雨打孤篷酒漸消，昏燈與我共無聊。", "功名本是無憑事，不及寒江日兩潮。"]'),
('86639b1a-649e-4a43-aa09-5dd29dfeda6b','舟中感懷三絕句呈太傅相公兼簡岳大用郎中  其三','陸游','宋','宋诗','song-poetry','','[]','夢筆亭邊擁鼻吟，壯圖蹭蹬老侵尋。',32,'全唐诗/poet.song.129000.json','["夢筆亭邊擁鼻吟，壯圖蹭蹬老侵尋。", "不眠數盡雞三唱，自笑當年起舞心。"]'),
('e92cf5fe-56ca-46f6-ae1f-49eb632ea71b','西興泊舟','陸游','宋','宋诗','song-poetry','','[]','衰髮不勝白，寸心殊未降。',48,'全唐诗/poet.song.129000.json','["衰髮不勝白，寸心殊未降。", "避風留水市，岸幘倚船窗。", "日上金鎔海，潮来雪捲江。", "登臨數奇觀，未易敵吾邦。"]'),
('798da71c-dce7-4cf7-a275-80349d4edd92','錢清夜渡','陸游','宋','宋诗','song-poetry','','[]','輕舟夜絕江，天濶星磊磊。',96,'全唐诗/poet.song.129000.json','["輕舟夜絕江，天濶星磊磊。", "地勢下東南，壯哉水所匯。", "月出半天赤，轉盼離巨海。", "清暉流玉宇，草木盡光彩。", "男子志功名，徒死不容悔。", "坐思黄河上，横戈被重鎧。", "晚途雖益困，此志顧常在。", "一日天勝人，醜虜安足醢。"]'),
('1e9c3b90-8d85-4ce0-989a-02a73375e97c','夜歸','陸游','宋','宋诗','song-poetry','','[]','晡時捩柂離西興，錢清夜渡見月升。',128,'全唐诗/poet.song.129000.json','["晡時捩柂離西興，錢清夜渡見月升。", "浮橋沽酒市嘈囋，江口過埭牛凌兢。", "寒韲煮餅坐茆店，小鮮供饌尋魚罾。", "偶逢估客問姓字，歡笑便足爲交朋。", "須臾一飽各散去，帆席健快如超騰。", "雲間戍樓鼓坎坎，山尾佛塔燈層層。", "夜分到家趨篝火，稺子驚起頭鬅鬙。", "道途辛苦未暇說，一尊且復驅嚴凝。"]'),
('6e3c4c6d-a4e0-422a-a1fb-54459d30dada','江北莊取米到作飯香甚有感','陸游','宋','宋诗','song-poetry','','[]','我昔從戎清渭側，散關嵯峨下臨賊。',128,'全唐诗/poet.song.129000.json','["我昔從戎清渭側，散關嵯峨下臨賊。", "鐵衣上馬蹴堅冰，有時三日不火食。", "山蕎畬粟雜沙磣，黑黍黄粱如土色。", "飛霜掠面寒壓指，一寸赤心惟報國。", "即今歸臥稽山下，眼昏臂弱衰境逼。", "新秔炊飯香出甑，風飱澗飲何曾識。", "我豈農家志飽暖，閉户惟思事耕織。", "征遼詔下倘可期，盾鼻猶堪試殘墨。"]'),
('d043743d-8e62-4cdd-b8b4-4d04c716825c','感興','陸游','宋','宋诗','song-poetry','','[]','築室真須待伯夷，起墳仍合近要離。',64,'全唐诗/poet.song.129000.json','["築室真須待伯夷，起墳仍合近要離。", "藥来賊境靈何用，米出胡奴死不炊。", "下石紛紛驚俗薄，絕弦寂寂嘆吾衰。", "一尊且作尋春計，又見東風浩蕩時。"]'),
('34d34f42-ac17-461a-b4a7-41961f7bfd01','新春','陸游','宋','宋诗','song-poetry','','[]','濛濛烟雨暗江干，新歲還勝故歲寒。',64,'全唐诗/poet.song.129000.json','["濛濛烟雨暗江干，新歲還勝故歲寒。", "酒壓濁清鳴社瓮，菜分紅綠簇春盤。", "良辰節物元如昨，病客情懷自鮮歡。", "却羨村鄰機上女，隔籬相喚祭蠶官。"]'),
('1dc78585-c5d3-4816-b225-b7cd5201762c','新年','陸游','宋','宋诗','song-poetry','','[]','寄迹人間夢已長，新年脫帽始微霜。',64,'全唐诗/poet.song.129000.json','["寄迹人間夢已長，新年脫帽始微霜。", "坐中使氣如秦俠，陌上行歌類楚狂。", "掃榻欲招貧與語，杜門聊以醉爲鄉。", "稽山剡曲雖堪樂，終憶祁連古戰場。"]'),
('0095ce94-0bb4-4f6c-a227-f5c97a2080d7','遊鏡湖','陸游','宋','宋诗','song-poetry','','[]','禹祠柳未黄，剡曲水已白。',96,'全唐诗/poet.song.129000.json','["禹祠柳未黄，剡曲水已白。", "魴鱮来洋洋，鳬雁去拍拍。", "皇天亦大度，能容此狂客。", "挂席乘長風，未覺湖海迮。", "讀書五十年，自笑安所獲。", "昔人精微意，豈獨在簡册。", "驥空萬馬群，裘非一狐腋。", "超然登玉笥，及此烟月夕。"]'),
('e94eedea-04ea-4f6c-bac8-482628563043','初春晚晴','陸游','宋','宋诗','song-poetry','','[]','雪盡冰消斂積威，參差碧瓦带斜暉。',64,'全唐诗/poet.song.129000.json','["雪盡冰消斂積威，參差碧瓦带斜暉。", "土膏漸釋人東作，天氣初和雁北歸。", "小閣金船嘗臘酒，華堂銀燭製春衣。", "關心雖有尋梅夢，冷蕊幽香事已非。"]'),
('eb03de26-22db-412c-b295-19bdf4501e59','偶讀山谷老境五十六翁之句作六十二翁吟','陸游','宋','宋诗','song-poetry','','[]','三百里湖水接天，六十二翁身刺船。',64,'全唐诗/poet.song.129000.json','["三百里湖水接天，六十二翁身刺船。", "飯足便休慵念祿，丹成不服怕登仙。", "胸中浩浩了無物，世上紛紛徒可憐。", "但有青錢沽白酒，猶堪醉倒落梅前。"]'),
('c4e3ea02-af2e-4f51-b3e5-20c4787581ea','自開歲略無三日晴戲作長句','陸游','宋','宋诗','song-poetry','','[]','新年暗曀覺春慳，變化相乘一瞬間。',64,'全唐诗/poet.song.129000.json','["新年暗曀覺春慳，變化相乘一瞬間。", "雨脚稍收初見日，風花忽起又遮山。", "欲行幽圃還成阻，未脫重裘自笑孱。", "桃李會開君勿恨，清尊且用破衰顔。"]'),
('f9e1a0ed-21e0-4ce9-b457-8f4bab991ece','置酒梅花下作短歌','陸游','宋','宋诗','song-poetry','','[]','歲月不貸人，綠髮成華顛。',96,'全唐诗/poet.song.129000.json','["歲月不貸人，綠髮成華顛。", "此生幾兩屐，念之每悽然。", "我本塵外客，已絕區中緣。", "惟當及未死，勤醉梅花前。", "瘦影寫微月，疏枝横夕烟。", "偃蹇巖壑間，欲與松忘年。", "豈亦薄世俗，忽逐天風翩。", "吾詩不徒歌，持配湘娥弦。"]'),
('8cc8c3e5-beff-4a7f-a841-890e41175521','梅花已過聞東村一樹盛開特往尋之慨然有感','陸游','宋','宋诗','song-poetry','','[]','春晚城南十里陂，亭亭獨立見奇姿。',64,'全唐诗/poet.song.129000.json','["春晚城南十里陂，亭亭獨立見奇姿。", "品流不落松竹後，懷抱惟應風月知。", "旋拂亂雲成小佇，重攜芳榼卜幽期。", "佳人空谷從来事，莫恨桃花笑昔時。"]'),
('8d77d351-192f-4874-9c74-fd765dc001a5','思蜀','陸游','宋','宋诗','song-poetry','','[]','老子饞堪笑，珍盤憶少城。',48,'全唐诗/poet.song.129000.json','["老子饞堪笑，珍盤憶少城。", "流匙抄薏飯，加糝啜巢羮。", "柑美傾筠籠，茶香出土鐺。", "西郊有舊隱，何日返柴荆。"]'),
('d3d967d7-b2dc-4493-894e-8e9b0ffbf82d','書憤','陸游','宋','宋诗','song-poetry','','["\u7231\u56fd", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u5b8b\u8bd7", "\u5fc6\u65e7"]','早歲那知世事艱，中原北望氣如山。',64,'全唐诗/poet.song.129000.json','["早歲那知世事艱，中原北望氣如山。", "樓船夜雪瓜洲渡，鐵馬秋風大散關。", "塞上長城空自許，鏡中衰鬢已先斑。", "出師一表真名世，千載誰堪伯仲間。"]'),
('c1535399-29c6-41c1-82cf-093d859cc7bc','南窗擘黄柑獨酌有感','陸游','宋','宋诗','song-poetry','','[]','放翁潦倒鬢成絲，也把花前酒一巵。',32,'全唐诗/poet.song.129000.json','["放翁潦倒鬢成絲，也把花前酒一巵。", "何限人間堪恨事，黄柑丹荔不同時。"]'),
('bd84e755-4e02-4251-ad25-b5bf6946eeec','久雨驟晴山園桃李爛漫獨海棠未甚開戯作','陸游','宋','宋诗','song-poetry','','[]','雨霽風和日漸長，小園尊酒答年光。',32,'全唐诗/poet.song.129000.json','["雨霽風和日漸長，小園尊酒答年光。", "直令桃李能言語，何似多情睡海棠。"]'),
('d957bfa2-aa59-4fe0-82b3-dc93f63e41dc','臨安春雨初霽','陸游','宋','宋诗','song-poetry','','["\u5199\u96e8", "\u6625\u5929", "\u96e8", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u5b8b\u8bd7", "\u5fe7\u6101"]','世味年来薄似紗，誰令騎馬客京華。',64,'全唐诗/poet.song.129000.json','["世味年来薄似紗，誰令騎馬客京華。", "小樓一夜聽春雨，深巷明朝賣杏花。", "矮紙斜行閑作草，晴窗細乳戲分茶。", "素衣莫起風塵嘆，猶及清明可到家。"]'),
('22e9ce2e-733c-4b02-aae2-254bd1c2dca3','延和殿退朝口號二首、  其一','陸游','宋','宋诗','song-poetry','','[]','雨餘未肯放朝暾，穿仗恭承聖主恩。',64,'全唐诗/poet.song.129000.json','["雨餘未肯放朝暾，穿仗恭承聖主恩。", "清蹕傳聲徐御殿，紫衣引拜許龍門。", "徘徊漫結堯階戀，零落難招楚澤魂。", "歸去猶堪誇里巷，桐江新賜兩朱轓。"]'),
('403f4f5d-6e15-4e24-a2ba-67ca11c36737','延和殿退朝口號二首、  其二','陸游','宋','宋诗','song-poetry','','[]','十年短櫂樂滄波，強著朝衫棄釣蓑。',64,'全唐诗/poet.song.129000.json','["十年短櫂樂滄波，強著朝衫棄釣蓑。", "才薄何堪試馮翊，恩深猶許對延和。", "空牆烟柳遥迎馬，輦路春泥欲濺鞾。", "莫恨此身衰病去，同時朝士久無多。"]'),
('eda2613e-cb91-4a4b-b35f-c4f280a9d228','簡楊庭秀','陸游','宋','宋诗','song-poetry','','[]','衮衮過白日，悠悠良自欺。',48,'全唐诗/poet.song.129000.json','["衮衮過白日，悠悠良自欺。", "未成千古事，易滿百年期。", "黄卷閑多味，紅塵老不宜。", "相逢又輕别，此恨定誰知。"]'),
('f6c02968-ed99-4dac-ab1e-735f72f6c090','飲張功父園戲題扇上','陸游','宋','宋诗','song-poetry','','[]','寒食清明數日中，西園春事又匆匆。',32,'全唐诗/poet.song.129000.json','["寒食清明數日中，西園春事又匆匆。", "梅花自避新桃李，不爲高樓一笛風。"]'),
('bc6393a5-ce4e-40a0-a3e4-fc4b5dc501d4','夜泛西湖示桑甥世昌','陸游','宋','宋诗','song-poetry','','["\u897f\u6e56"]','嗟我客上都，忽已見暮春。',144,'全唐诗/poet.song.129000.json','["嗟我客上都，忽已見暮春。", "騎馬出闇門，眯眼吹紅塵。", "西湖商賈區，山僧多市人。", "誰令污泉石，只合加冠巾。", "黄冠更可憎，狀與屠沽鄰。", "齁齁酒肉氣，吾輩何由親。", "少須一鬨散，境寂鷗自馴。", "舉手邀素月，移舟采青蘋。", "鍾從南山来，殷殷浮烟津。", "鶴髮隱者歟，長樂收釣緍。", "畏冷不竟夕，恨此老病身。", "明發復擾擾，吾詩其絕麟。"]'),
('be212caf-2c4e-47cb-a70d-aaeac933ff88','小舟過御園二首  其一','陸游','宋','宋诗','song-poetry','','[]','聖主憂民罷露臺，春風别苑晝常開。',64,'全唐诗/poet.song.129000.json','["聖主憂民罷露臺，春風别苑晝常開。", "盡除曼衍魚龍戲，不禁芻蕘雉兔来。", "水鳥避人横翠靄，宫花經雨委蒼苔。", "殘年自喜身強健，又作清都夢一回。"]'),
('2e2c094b-d1a9-41cf-aa7f-b3a25a2bf10b','小舟過御園二首  其二','陸游','宋','宋诗','song-poetry','','[]','水殿西頭起砌臺，緑楊閙處杏花開。',64,'全唐诗/poet.song.129000.json','["水殿西頭起砌臺，緑楊閙處杏花開。", "簫韶本與人同樂，羽衛纔聞歲一来。", "鷁首波生涵藻荇，金鋪雨後上莓苔。", "遠臣侍宴應無日，目斷堯雲到晚回。"]'),
('63af0f8c-9c47-4ef4-8af1-e9315d603c86','自真珠園泛舟至孤山','陸游','宋','宋诗','song-poetry','','[]','呼船徑截鴨頭波，岸幘閑登瑪瑙坡。',64,'全唐诗/poet.song.129000.json','["呼船徑截鴨頭波，岸幘閑登瑪瑙坡。", "弦管未嫌驚鷺起，塵埃無奈污花何。", "宦情不到漁蓑底，詩興偏於野寺多。", "明日一藤龍井去，誰知伴我醉行歌。"]'),
('e81927ad-4489-4a60-93fd-2e6739443329','真珠園雨中作','陸游','宋','宋诗','song-poetry','','[]','清晨得小雨，憑閣意欣然。',48,'全唐诗/poet.song.129000.json','["清晨得小雨，憑閣意欣然。", "一掃群兒迹，稍稀遊女舩。", "烟波蘸山脚，濕翠到闌邊。", "坐誦空濛句，予懷玉局仙。"]'),
('208e8b15-4e86-48cd-a770-98bac666ad75','還家二首  其一','陸游','宋','宋诗','song-poetry','','[]','富貴元須早致身，白頭豈復市朝人。',64,'全唐诗/poet.song.129000.json','["富貴元須早致身，白頭豈復市朝人。", "數聲鵯鵊呼殘夢，一架酴醿送晚春。", "疊嶂出雲明客眼，澄江漲雨濯京塵。", "逢人枉道哦詩瘦，下語今年尚未親。"]'),
('54ca280c-bb98-4769-b7f5-6a5d28c9653b','還家二首  其二','陸游','宋','宋诗','song-poetry','','[]','天津橋上醉騎驢，一錦囊詩一束書。',64,'全唐诗/poet.song.129000.json','["天津橋上醉騎驢，一錦囊詩一束書。", "作客況當多病後，還家已過暮春初。", "泥深村巷人誰顧，草滿園畦手自鉏。", "不爲衰遲思屏迹，此心元向利名疏。"]'),
('57896619-6270-49fe-ad03-7ba043688830','初歸偶到近村戲書','陸游','宋','宋诗','song-poetry','','[]','雨過一村暗，風回百草香。',48,'全唐诗/poet.song.129000.json','["雨過一村暗，風回百草香。", "刺船過古埭，倚杖立新塘。", "醉覺乾坤大，閑知日月長。", "暮歸詩滿卷，雖老尚能狂。"]'),
('bcc6646e-de3f-4fcc-8f9f-749269966520','題跨湖橋下酒家','陸游','宋','宋诗','song-poetry','','[]','湖水綠於染，野花紅欲燃。',48,'全唐诗/poet.song.129000.json','["湖水綠於染，野花紅欲燃。", "春當三月半，狂勝十年前。", "小店開新酒，平橋上畫船。", "翩翩幸強健，不必愧華顛。"]'),
('bb49dc11-ab6e-425c-931b-6c517a3980d4','春遊至樊江戲示坐客','陸游','宋','宋诗','song-poetry','','[]','江頭蕭蕭春色暮，柳陰遊魚飽飛絮。',96,'全唐诗/poet.song.129000.json','["江頭蕭蕭春色暮，柳陰遊魚飽飛絮。", "芼羮箭筍美如玉，點豉絲蒓滑縈筯。", "銀鞍烏帽尋春客，朱户青旗沽酒處。", "浮生細看纔幾時，一笑自應忘百慮。", "綠杯到手不肯盡，寶带照地身何與。", "酴醿爛漫我欲狂，茗艼還家君勿遽。"]'),
('02e33831-66e2-4d0f-a6e4-7d4b09efcb2d','暮春','陸游','宋','宋诗','song-poetry','','[]','憔悴都門白髮新，歸来一振客衣塵。',64,'全唐诗/poet.song.129000.json','["憔悴都門白髮新，歸来一振客衣塵。", "啼鶯妒夢頻催曉，飛絮鍾情獨殿春。", "湖上風光猶淡沱，尊前懷抱頗清真。", "詩成絕恨知心少，自寫吳牋寄故人。"]'),
('6d3193e5-7f49-409b-a865-118e5695d9a0','天華寺前遇縣令過避之入寺僧皆晝睡','陸游','宋','宋诗','song-poetry','','[]','墮絮飛花掠釣舩，天華寺下賞春妍。',64,'全唐诗/poet.song.129000.json','["墮絮飛花掠釣舩，天華寺下賞春妍。", "縣多官府鳴騶過，僧少樷林避客眠。", "出網長魚猶鱍鱍，爭泥新燕欲翩翩。", "典衣剩買旗亭醉，已過旗亭六十年。"]'),
('207d4882-2fb1-4e80-b7e0-dfd40fd33628','偶得海錯侑酒戲作','陸游','宋','宋诗','song-poetry','','[]','判無神藥斸清冥，放筯那憎海物腥。',64,'全唐诗/poet.song.129000.json','["判無神藥斸清冥，放筯那憎海物腥。", "滿貯醇醪漬黄甲，密封小瓮餉紅丁。", "從来一飽忘南北，此去千鍾任醉醒。", "添雪更知憑茗椀，山童敲臼隔窗聽。"]'),
('1844b5f6-7e7f-45a6-a3be-35a562d9ba49','雨晴遊香山','陸游','宋','宋诗','song-poetry','','[]','雨打酴醿夜未拆，一晴柳岸先飄雪。',128,'全唐诗/poet.song.129000.json','["雨打酴醿夜未拆，一晴柳岸先飄雪。", "我揺畫檝鏡湖中，碧水青天兩奇絕。", "長歌縹緲雲不動，横笛清悲竹將裂。", "悠然起舞影零亂，卓爾四顧心激烈。", "好山可隱輕捨去，故人已貴長乖隔。", "肺渴生塵防酒興，眼暈成花作書厄。", "平生所期無一遂，獨有曠快相除折。", "夜歸燈火閙湖邊，淡淡西南一鈎月。"]'),
('502fa76d-46db-4b09-9aa3-b2dd38dab447','春遊絕句','陸游','宋','宋诗','song-poetry','','[]','一百五日春郊行，三十六溪春水生。',32,'全唐诗/poet.song.129000.json','["一百五日春郊行，三十六溪春水生。", "千秋觀裏逢急雨，射的峰前看晚晴。"]'),
('0ec82668-4689-4804-8fba-81de5c194c17','夜行玉笥樵風之間宿龍瑞','陸游','宋','宋诗','song-poetry','','[]','野店谿橋供晚餉，吟邊醉裏弄春風。',64,'全唐诗/poet.song.129000.json','["野店谿橋供晚餉，吟邊醉裏弄春風。", "馬行缺月黄昏後，鍾下亂山空翠中。", "名宦不辭成寂寂，歲時惟恨去怱怱。", "頗聞禹穴遺書在，安得高人與細窮。"]'),
('13455aad-c2de-442e-a978-72a4d51cae2b','聞傅氏莊紫笑花開急棹小舟觀之','陸游','宋','宋诗','song-poetry','','[]','日長無奈清愁處，醉裏来尋紫笑香。',32,'全唐诗/poet.song.129000.json','["日長無奈清愁處，醉裏来尋紫笑香。", "漫道閑人無一事，逢春也似蜜蜂忙。"]'),
('20ef9e40-6084-42c6-ade5-e3084db668b0','遊法雲寺觀彝老新葺小園','陸游','宋','宋诗','song-poetry','','[]','古寺朱扉傍水開，高僧笑語共徘徊。',64,'全唐诗/poet.song.129000.json','["古寺朱扉傍水開，高僧笑語共徘徊。", "陰陰曲徑人稀到，一一名花手自栽。", "竹筧引泉滋藥壟，風爐篝火試茶杯。", "此行自喜非生客，二百年間六世来。"]'),
('ae8540d1-4376-400b-886e-cac7885db492','鹹韲十韵','陸游','宋','宋诗','song-poetry','','[]','九月十月屋瓦霜，家人共畏畦蔬黄。',160,'全唐诗/poet.song.129000.json','["九月十月屋瓦霜，家人共畏畦蔬黄。", "小甖大甕盛滌濯，青菘緑韭謹蓄藏。", "天氣初寒手訣妙，吳鹽正白山泉香。", "挾書旁觀稺子喜，洗刀竭作厨人忙。", "園丁無事臥曝日，棄葉狼籍堆空廊。", "泥爲緘封糠作火，守護不敢非時嘗。", "人生各自有貴賤，百花開時促高宴。", "劉伶病酲相如渴，長魚大肉何由薦。", "凍韲此際價千金，不數狐泉槐葉麫。", "摩挲便腹一欣然，作歌聊續冰壺傳。"]'),
('e1f7328b-edf4-4e22-b486-3c5049403429','長門怨','陸游','宋','宋诗','song-poetry','','[]','未央宫中花月夕，歌舞稱觴天咫尺。',96,'全唐诗/poet.song.129000.json','["未央宫中花月夕，歌舞稱觴天咫尺。", "從来所恃獨君王，一日讒興誰爲直。", "咫尺之天今萬里，空在長安一城裏。", "春風時送簫韶聲，獨掩羅巾泪如洗。", "泪如洗兮天不知，此生再見應無期。", "不如南粤匈奴使，航海梯山有到時。"]'),
('a2c7acb9-b97b-46e2-b64b-9133858e5bcb','遣興','陸游','宋','宋诗','song-poetry','','[]','莫羨朝回带萬釘，吾曹要可草堂靈。',64,'全唐诗/poet.song.129000.json','["莫羨朝回带萬釘，吾曹要可草堂靈。", "風来弱柳揺官綠，雲破奇峰湧帝青。", "聽盡啼鶯春欲去，驚回夢蝶醉初醒。", "從教俗眼憎疏放，行矣桐江酹客星。"]'),
('5107f388-c2bd-4388-9460-3d5653b26632','晨坐道室有感','陸游','宋','宋诗','song-poetry','','[]','一缽青精便有餘，世間萬事總成疏。',64,'全唐诗/poet.song.129000.json','["一缽青精便有餘，世間萬事總成疏。", "手揮弦上烏棲曲，口誦巖間鳥跡書。", "丹氣初升勤沐浴，芝房未熟飽耘鋤。", "碧霄騰舉人人事，莫戀污渠與臭帑。"]'),
('4954c135-71c0-4617-9d9a-7adb9caf977c','晝臥','陸游','宋','宋诗','song-poetry','','[]','忽忽見春盡，徂年那更還。',48,'全唐诗/poet.song.129000.json','["忽忽見春盡，徂年那更還。", "香生帳裏霧，書積枕邊山。", "凌厲心猶壯，沈緜氣已孱。", "千秋有管葛，看鏡汗吾顔。"]'),
('887f061c-9dd5-4f36-9847-5e1fc36a39a6','雨晴','陸游','宋','宋诗','song-poetry','','[]','久雨作我病，今朝身頓輕。',48,'全唐诗/poet.song.129000.json','["久雨作我病，今朝身頓輕。", "花房避初旭，簾影弄新晴。", "漉酒綸巾折，聽琴拄杖横。", "翛然又終日，未覺負平生。"]'),
('f3f2ba8a-4f2f-489e-b29c-29e52a313439','宿石帆山下二首  其一','陸游','宋','宋诗','song-poetry','','[]','卷地東風吹釣船，石帆重到又經年。',32,'全唐诗/poet.song.129000.json','["卷地東風吹釣船，石帆重到又經年。", "放翁夜半酒初解，落月啣山聞杜鵑。"]'),
('2cb68c0d-36aa-4e73-a037-553d2d1d5647','宿石帆山下二首  其二','陸游','宋','宋诗','song-poetry','','[]','繫船禹廟醉如泥，投宿漁家月向低。',32,'全唐诗/poet.song.129000.json','["繫船禹廟醉如泥，投宿漁家月向低。", "濕翠撲人濃可掬，始知身在石帆西。"]'),
('990bafde-2af1-4d27-a16b-af967b2ae5a1','小雨泛鏡湖','陸游','宋','宋诗','song-poetry','','[]','吾州清絕冠三吴，天寫雲山萬幅圖。',64,'全唐诗/poet.song.129000.json','["吾州清絕冠三吴，天寫雲山萬幅圖。", "龍化廟梁飛白雨，鶴收仙箭下青蕪。", "菱歌嫋嫋遥相答，烟樹昏昏淡欲無。", "端辦一船多貯酒，敢辭送老向南湖。"]'),
('e8cb1379-13a7-4b67-b048-1f61a86d665e','小憩村舍','陸游','宋','宋诗','song-poetry','','[]','藤梢維艇子，烟際覓人家。',48,'全唐诗/poet.song.129000.json','["藤梢維艇子，烟際覓人家。", "小婦篸新麥，群童摘晚茶。", "溪雲易成雨，崖樹少開花。", "聊寄平生快，青鞵到若耶。"]'),
('1fca2a82-693a-4019-8d27-e08497babc0c','平水','陸游','宋','宋诗','song-poetry','','[]','水悍溪橋敗，沙頽野徑移。',48,'全唐诗/poet.song.129000.json','["水悍溪橋敗，沙頽野徑移。", "年華入詩卷，心事付笻枝。", "雨霽鵓鳩喜，春歸鶗鴂知。", "客庖消底物，麥飯薦蒓絲。"]'),
('3bbce8ab-6774-4a2c-99c5-cdb946ff098a','初夏山中','陸游','宋','宋诗','song-poetry','','[]','又報東皇促駕歸，醉中闕賦送春詩。',64,'全唐诗/poet.song.129000.json','["又報東皇促駕歸，醉中闕賦送春詩。", "佛缾是處見紅藥，僧榻有時聞子規。", "野客欵門聊倒屣，谿潭照影一軒眉。", "年光佳處惟初夏，兒女紛紛詎得知。"]'),
('5b2f42a6-e351-4cd2-a567-1dc3043c867f','雨後','陸游','宋','宋诗','song-poetry','','[]','礎潤還成雨，雲收旋作晴。',48,'全唐诗/poet.song.129000.json','["礎潤還成雨，雲收旋作晴。", "巖花分日發，林筍逐番生。", "筆硯行常具，軒窗晚更明。", "塵埃幸不到，那得廢詩情。"]'),
('4ccc0f0a-64fb-461c-a107-7d5ca55ec6b8','雲門溪上獨步','陸游','宋','宋诗','song-poetry','','[]','山路聨翩十日陰，晚晴剩喜得幽尋。',64,'全唐诗/poet.song.129000.json','["山路聨翩十日陰，晚晴剩喜得幽尋。", "殘紅猶有數枝在，漲緑真成一倍深。", "泉響珮環鳴闇壑，月明珠璧散疏林。", "歸来寂寞鐘初動，羞向孤燈說壯心。"]'),
('be158c5a-1cf0-4d4f-9029-57ff2a84ba5f','雲門過何山','陸游','宋','宋诗','song-poetry','','[]','漠漠稻滿陂，濛濛雨霑衣。',144,'全唐诗/poet.song.129000.json','["漠漠稻滿陂，濛濛雨霑衣。", "林花落更新，磎鳥止復飛。", "我作山中行，十日未擬歸。", "思酒過野店，念茶叩僧扉。", "眠枕松下石，適意無訶譏。", "心廣體自舒，泰然不肉肥。", "念昔在官塗，萬事與願違。", "逢人無一欣，對食或累欷。", "低回三十年，竟不飽蕨薇。", "空將書五車，自誑腹十圍。", "餘日猶幾何，可復貪塵鞿。", "賸拾柏子香，閉門觀昨非。"]'),
('40612b4e-731e-45e1-b078-c15b9252e05b','明覺院','陸游','宋','宋诗','song-poetry','','[]','細路蟠青壁，層軒倚碧空。',48,'全唐诗/poet.song.129000.json','["細路蟠青壁，層軒倚碧空。", "天香下塵世，僧梵起雲中。", "藤絡將頹石，松號不斷風。", "尤憐扶杖處，直下數飛鴻。"]'),
('d5e49777-9ad2-40c2-9811-15a72cf6f863','自雲門至上竈欲遊一二僧庵以雨不果','陸游','宋','宋诗','song-poetry','','[]','道遠晨炊米，風和晝減衣。',48,'全唐诗/poet.song.129000.json','["道遠晨炊米，風和晝減衣。", "花殘孔官廟，苔滿葛仙磯。", "剩欲尋僧話，先判秉炬歸。", "山昏又成雨，心事固多違。"]'),
('a6f61f70-b81d-453c-9b93-62038aaba74d','自上竈過陶山','陸游','宋','宋诗','song-poetry','','[]','宿雨初收見夕陽，縱横流水入陂塘。',64,'全唐诗/poet.song.129000.json','["宿雨初收見夕陽，縱横流水入陂塘。", "蠶家忌客門門閉，茶户供官處處忙。", "綠樹村邊停醉帽，紫藤架底倚胡床。", "不因蕭散遺塵事，那覺人間白日長。"]'),
('a5c7fae4-ef1a-477d-be7e-5ff332181376','四月','陸游','宋','宋诗','song-poetry','','[]','四月江南暑尚微，虚堂初換葛衣時。',64,'全唐诗/poet.song.129000.json','["四月江南暑尚微，虚堂初換葛衣時。", "懶陪陌上雍容騎，且對窗間腷膊棋。", "糝徑落花猶片片，拂雲新竹已離離。", "年来病肺疏杯酌，應接風光賴有詩。"]'),
('f5b3f224-9e84-48cc-8e1d-bf091ffb2c55','初夏閑居即事','陸游','宋','宋诗','song-poetry','','[]','門巷蕭蕭日正長，方床曲几傲羲皇。',64,'全唐诗/poet.song.129000.json','["門巷蕭蕭日正長，方床曲几傲羲皇。", "輕風忽起楊花閙，清露初晞藥草香。", "對奕兩奩飛黑白，讎書千卷雜朱黄。", "穿簾語燕能從我，分爾湖邊一夏涼。"]'),
('0c9385e6-1238-41db-9e33-8f591a5d5b8c','夜汲','陸游','宋','宋诗','song-poetry','','[]','酒渴起夜汲，月白天正青。',72,'全唐诗/poet.song.129000.json','["酒渴起夜汲，月白天正青。", "銅瓶響寒泉，聞之心自醒。", "井邊雙梧桐，映月影離離。", "上有獨棲鵲，細爪握高枝。", "我欲畫團扇，良工不可求。", "三嘆拊庭楯，浩然風露秋。"]'),
('280c603c-7e38-4634-a0de-4ae71b505d29','排悶','陸游','宋','宋诗','song-poetry','','[]','老去知心少，流塵鎖斷弦。',48,'全唐诗/poet.song.129000.json','["老去知心少，流塵鎖斷弦。", "尊空問字酒，囊罄作碑錢。", "掃葉供朝爨，和泥補漏船。", "胸中元浩浩，白眼望青天。"]'),
('4a2a15da-41f1-41bd-b6fb-ff3bd348ea44','初夏夜賦','陸游','宋','宋诗','song-poetry','','[]','好景入新夏，幽人臥弊廬。',48,'全唐诗/poet.song.129000.json','["好景入新夏，幽人臥弊廬。", "廊腰得風遠，樹罅見星疏。", "門掩鴉棲後，鐘鳴月上初。", "青燈尚堪近，起了讀殘書。"]'),
('20797e69-182a-48db-a08e-1c417aba67d1','新霽城南舟中夜興','陸游','宋','宋诗','song-poetry','','[]','身是江湖不繫船，雨餘隨處一翛然。',64,'全唐诗/poet.song.129000.json','["身是江湖不繫船，雨餘隨處一翛然。", "浮雲盡斂出青嶂，孤月徐升行碧天。", "收網漁歌移别浦，隔城塔影落前川。", "明朝閑就平洲飲，巾履追涼又一年。"]'),
('d82e3faf-c3da-40cf-a682-dc08d69d5694','泊舟二首  其一','陸游','宋','宋诗','song-poetry','','[]','蘸岸烟波檥畫船，幅巾蕭散餞流年。',32,'全唐诗/poet.song.129000.json','["蘸岸烟波檥畫船，幅巾蕭散餞流年。", "兩行楊柳吹晴雪，只著啼鶯未著蟬。"]'),
('00b50d1f-7bfd-42e6-895e-eaaf4c6ef28f','泊舟二首  其二','陸游','宋','宋诗','song-poetry','','[]','湖水無風鏡面平，巉巉倒影萬峰青。',32,'全唐诗/poet.song.129000.json','["湖水無風鏡面平，巉巉倒影萬峰青。", "放翁眼界便疏豁，過盡蘆村泊蓼汀。"]'),
('7070d429-c7f2-4a36-9018-aee2d44ca322','飲伯山家因留宿','陸游','宋','宋诗','song-poetry','','[]','小醉悠然不作酲，斷雲飛盡却成晴。',64,'全唐诗/poet.song.129000.json','["小醉悠然不作酲，斷雲飛盡却成晴。", "月生檐外見簾影，風下城頭聞角聲。", "岸幘莎庭便髮冷，酌泉桐井覺魂清。", "雞號忽報明星上，夢破虚皇白玉京。"]'),
('2b35829f-88b6-40bc-b6b5-4ce68b9e7c9b','夜泛蜻蜓浦','陸游','宋','宋诗','song-poetry','','[]','四顧水無際，三更月未生。',48,'全唐诗/poet.song.129000.json','["四顧水無際，三更月未生。", "偶成揺檝去，不減御風行。", "烟浦漁歌斷，蘆洲鬼火明。", "還家人已睡，小立叩柴荆。"]'),
('18f2a0c7-207d-4b69-910d-11ea20e6b031','晨起看山飲酒','陸游','宋','宋诗','song-poetry','','[]','愛山入骨髓，嗜酒在膏肓。',48,'全唐诗/poet.song.129000.json','["愛山入骨髓，嗜酒在膏肓。", "跌宕風烟外，歌呼麯蘖傍。", "虚窗天柱曉，小瓮槖泉香。", "垂老叨微祿，齋居靜不忙。"]'),
('be48a91e-387b-4305-9566-a54790312e2c','枕上偶賦','陸游','宋','宋诗','song-poetry','','[]','初夏暑猶薄，紗幮怯夜深。',48,'全唐诗/poet.song.129000.json','["初夏暑猶薄，紗幮怯夜深。", "孤螢入窗罅，斜月下牆陰。", "靜養觀書眼，窮悲濟世心。", "吾衰亦久矣，徂歲苦駸駸。"]'),
('29962cec-7627-45c8-a90d-37fc5f3af028','自詠','陸游','宋','宋诗','song-poetry','','[]','射的山前一老樵，此生何敢辱旌招。',64,'全唐诗/poet.song.129000.json','["射的山前一老樵，此生何敢辱旌招。", "繆緣學道肱三折，不遇知音尾半焦。", "去蠧區區慚啄木，附高矯矯鄙凌霄。", "但令窮死心無愧，也勝鳴珂事早朝。"]'),
('04831ab0-527c-4a47-bfd3-4d030269db80','題齋壁四首  其一','陸游','宋','宋诗','song-poetry','','[]','二十餘年此結茆，園公谿父日論交。',64,'全唐诗/poet.song.129000.json','["二十餘年此結茆，園公谿父日論交。", "風翻半浦亂荷背，雨放一林新笋梢。", "隔葉晚鶯啼谷口，唼花雛鴨聚塘坳。", "出門行罷還無事，借得丹經手自抄。"]'),
('a8e15ab8-43bf-4dd6-9e2d-990abe0de670','題齋壁四首  其二','陸游','宋','宋诗','song-poetry','','[]','四顧茫茫水接天，幽居真箇似乘船。',64,'全唐诗/poet.song.129000.json','["四顧茫茫水接天，幽居真箇似乘船。", "月窗竹影連棲鵲，露井桐聲带斷蟬。", "甘寢每憎茶作祟，清狂直以酒爲仙。", "形骸那得常羈束，六十年来又二年。"]'),
('363c950a-40cd-43fc-b8df-316693070315','題齋壁四首  其三','陸游','宋','宋诗','song-poetry','','[]','舴艋爲家一老翁，陽狂羞與俗人同。',64,'全唐诗/poet.song.129000.json','["舴艋爲家一老翁，陽狂羞與俗人同。", "夢回菱曲漁歌裏，身寄蘋洲蓼浦中。", "斷簡塵埃存治道，高丘草棘閉英雄。", "旗亭村酒何勞醉，聊豁平生芥蒂胸。"]'),
('549aa1fc-d80d-4b0a-8bdc-48f7733c2983','題齋壁四首  其四','陸游','宋','宋诗','song-poetry','','[]','稽山千載翠依然，著我山前一釣舩。',64,'全唐诗/poet.song.129000.json','["稽山千載翠依然，著我山前一釣舩。", "瓜蔓水平芳草岸，魚鱗雲襯夕陽天。", "出從父老觀秧馬，歸伴兒童放紙鳶。", "君看此翁閑適處，不應便謂世無仙。"]'),
('4ffc6a80-44ee-4044-ac3d-4b98c52dcfab','丙午五月大雨五日不止鏡湖渺然想見湖未廢時有感而賦','陸游','宋','宋诗','song-poetry','','[]','朝雨暮雨梅正黄，城南積潦入車箱。',128,'全唐诗/poet.song.129000.json','["朝雨暮雨梅正黄，城南積潦入車箱。", "鏡湖無復鍼青秧，直浸山脚白茫茫。", "湖三百里漢訖唐，千載未嘗廢陂防。", "屹如長城限氐羌，嗇夫有秩走且僵。", "旱有灌注水何傷，越民歲歲常豐穰。", "泆湖誰始謀不臧，使我婦子饜糟糠。", "陵遷谷變亦何常，會有妙手開湖光。", "蒲魚自足被四方，烟艇滿目菱歌長。"]'),
('41b4ac45-b639-4724-bdf6-7587f7df1725','遊鄞','陸游','宋','宋诗','song-poetry','','[]','晚雨初收旋作晴，買舟訪舊海邊城。',64,'全唐诗/poet.song.129000.json','["晚雨初收旋作晴，買舟訪舊海邊城。", "高帆斜挂夕陽色，急櫓不聞人語聲。", "掠水翻翻沙鷺過，供厨片片雪鱗明。", "山川不與人俱老，更幾東来了此生。"]'),
('11570d3a-8da7-4ace-a8a2-17021bc5fea1','泊上虞縣','陸游','宋','宋诗','song-poetry','','[]','鄞江久不到，乘興偶東遊。',48,'全唐诗/poet.song.129000.json','["鄞江久不到，乘興偶東遊。", "漲水崩沙岸，歸雲抱縣樓。", "吟餘聲混混，梳罷髮颼颼。", "喜見時平象，新絲入市稠。"]'),
('dae3d35d-96fb-4095-a8bb-1d8e5355213d','發丈亭二首  其一','陸游','宋','宋诗','song-poetry','','[]','姚江乘潮潮始生，長亭却趁落潮行。',32,'全唐诗/poet.song.129000.json','["姚江乘潮潮始生，長亭却趁落潮行。", "參差鄰舫一時發，臥聽滿江柔櫓聲。"]'),
('4225d1bb-5b78-4afb-ad85-5a2a7886353b','發丈亭二首  其二','陸游','宋','宋诗','song-poetry','','[]','玄雲垂天暗如漆，櫓聲嘔軋知船行。',32,'全唐诗/poet.song.129000.json','["玄雲垂天暗如漆，櫓聲嘔軋知船行。", "南風忽起卷雲去，江月已作金盆傾。"]'),
('9f026848-0f3a-4043-85ea-c7e03dd7aa36','明州','陸游','宋','宋诗','song-poetry','','[]','豐年滿路笑歌聲，蠶麥俱收穀價平。',64,'全唐诗/poet.song.129000.json','["豐年滿路笑歌聲，蠶麥俱收穀價平。", "村步有船衘尾泊，江橋無柱架空横。", "海東估客初登岸，雲北山僧遠入城。", "風物可人吾欲住，擔頭蒓菜正堪烹。"]'),
('ed13e4dd-8404-41fb-ba37-931cf377b738','水亭獨酌十二韵','陸游','宋','宋诗','song-poetry','','[]','清風掃鬱蒸，爽氣生户牖。',144,'全唐诗/poet.song.129000.json','["清風掃鬱蒸，爽氣生户牖。", "客中淡無事，翛然一杯酒。", "書生拙自料，事業期不朽。", "少年忝朝跡，蹭蹬今白首。", "歴觀千載事，和戎固嘗有。", "定襄伍原間，乃可畫地守。", "神州在何許，東巡已去久。", "煌煌一統業，謨訓其可負。", "荆楚多劍客，宣潤冨弩手。", "孰能用其長，坐使老農畞。", "講武幸長楊，勞軍臨細柳。", "中興望聖時，未死得見否。"]'),
('5dc8970e-4dfe-4303-aa0b-b4fa758b7df5','坐客有談狄魚眼眶之美者感嘆而作','陸游','宋','宋诗','song-poetry','','[]','黄雀頭顱羞五鼎，狄魚眼眶參雋永。',128,'全唐诗/poet.song.129000.json','["黄雀頭顱羞五鼎，狄魚眼眶參雋永。", "兩螯何辠蟹喪軀，一臠可憐牛斷領。", "霜刀斫膾幾許痛，公子方誇醉魂醒。", "物生怖死與我均，碪几流丹只俄頃。", "哀哉堂堂七尺身，正坐舌端成業境。", "豪華只可誇僕妾，報應那知類形影。", "世間擾擾何時了，一念超然差若頴。", "不妨瓦缽飽晚菘，更汲山泉試春茗。"]'),
('baf5d7e0-0e83-4e72-97fb-d56aae072237','衰病不復能劇飲而多不見察戲作此詩','陸游','宋','宋诗','song-poetry','','[]','平生不持面看人，寧作五湖雲水身。',96,'全唐诗/poet.song.129000.json','["平生不持面看人，寧作五湖雲水身。", "忍窮閉門豈自苦，是中有味敵八珍。", "酒杯瀲灩鼓吹作，我自悲吒人自樂。", "更闌坐睡不得去，如鷹在鞲虎遭縛。", "丈夫歡樂自有時，遇酒先怯非予衰。", "萬騎擊胡青海岸，此時意氣令君看。"]'),
('61d759e7-33ee-4788-ac8d-7f30e2797fbb','或以予辭酒爲過復作長句','陸游','宋','宋诗','song-poetry','','[]','陸生酒戸如蠡迮，痛酒豈能堪大白。',112,'全唐诗/poet.song.129000.json','["陸生酒戸如蠡迮，痛酒豈能堪大白。", "正緣一快敗萬事，往往吐茵仍墮幘。", "爾来人情甚不美，似欲殺我以麯蘖。", "滿傾不許計性命，傍睨更復騰頰舌。", "醉時狂呼不復覺，醒後追思空自責。", "即今願與交舊約，三爵甫過當亟徹。", "解衣摩腹午窗明，茶磑無聲看霏雪。"]'),
('45fe2b0f-c0c1-4145-87c0-e9dd11fba429','行路難','陸游','宋','宋诗','song-poetry','','[]','平生結交無十人，與君契合懷抱真。',96,'全唐诗/poet.song.129000.json','["平生結交無十人，與君契合懷抱真。", "春遊有時馬忘秣，夜話不覺雞報晨。", "極知貧賤别離苦，明日有懷就誰語。", "人無根柢似浮萍，未死相逢在何許。", "道邊日斜泣相持，旗亭取醉不須辭。", "君貴堂厨萬錢食，我勸一杯應不得。"]'),
('893fbc11-f6f7-4c80-8e68-4148f8a361c5','千峰榭宴坐','陸游','宋','宋诗','song-poetry','','[]','蒼寒千疉擁官居，吏退憑高樂有餘。',64,'全唐诗/poet.song.129000.json','["蒼寒千疉擁官居，吏退憑高樂有餘。", "盡日烟雲窮變化，入秋草木漸凋疏。", "朱弦靜按新傳譜，黄卷閑披累譯書。", "聊與邦人共無事，吾僚不用笑迂疏。"]'),
('47c96746-ec74-491f-a4e7-c4630a64d137','喜雨二首  其一','陸游','宋','宋诗','song-poetry','','[]','勢掠郊原飛急雪，聲揺窗户過奔雷。',32,'全唐诗/poet.song.129000.json','["勢掠郊原飛急雪，聲揺窗户過奔雷。", "坐知多稼連雲熟，不獨新涼傍枕来。"]'),
('5d9cb425-adaf-4205-b1d3-3bdb36957af7','喜雨二首  其二','陸游','宋','宋诗','song-poetry','','[]','淅瀝簷聲枕上聞，攬衣起坐對爐熏。',32,'全唐诗/poet.song.129000.json','["淅瀝簷聲枕上聞，攬衣起坐對爐熏。", "萬家歌舞豐年樂，未費烏龍一綫雲。"]'),
('4c166353-ff42-4b2e-84e7-4e6151283cbd','五鼓','陸游','宋','宋诗','song-poetry','','[]','樓堞鼕鼕鼓，簾櫳煜煜燈。',48,'全唐诗/poet.song.129000.json','["樓堞鼕鼕鼓，簾櫳煜煜燈。", "浪名隨牒吏，實似打包僧。", "衰病元難強，疏慵每自憎。", "誰知戍邊日，秋野正呼鷹。"]'),
('5473ba9a-ce87-4b8d-88b4-5402ddf7d00b','官居戲詠三首  其一','陸游','宋','宋诗','song-poetry','','[]','萬里飄然似斷蓬，桐廬江上又秋風。',64,'全唐诗/poet.song.129000.json','["萬里飄然似斷蓬，桐廬江上又秋風。", "判餘牘尾棲鴉濕，衙退庭中立雁空。", "燈火市樓知酒賤，歌呼村路覺年豐。", "誰言病守無歡意，也與他人一笑同。"]'),
('d2891c99-bf38-4f85-980a-2e64be1f3bc8','官居戲詠三首  其二','陸游','宋','宋诗','song-poetry','','[]','說著功名即自羞，暮年世味轉悠悠。',64,'全唐诗/poet.song.129000.json','["說著功名即自羞，暮年世味轉悠悠。", "一庭落葉楸梧老，萬里悲風鼓角秋。", "懷綬不爲明日計，登樓且散異鄉愁。", "漁舟大似非凡子，能揀溪山勝處留。"]'),
('4c0e83ca-5f45-46de-807f-5edadd7973f3','官居戲詠三首  其三','陸游','宋','宋诗','song-poetry','','[]','城頭閑倚一枝藤，病起清羸不自勝。',64,'全唐诗/poet.song.129000.json','["城頭閑倚一枝藤，病起清羸不自勝。", "衙鼓有期催晚坐，絛鈴無賴喚晨興。", "愛書習氣嗟猶在，寡過工夫愧未能。", "寂寞已無臺省夢，諸公衮衮自飛騰。"]'),
('5698f048-bba3-42e6-bb89-c6cb352f9bb8','倦眼','陸游','宋','宋诗','song-poetry','','[]','看書澀似上羊腸，得睡甘如飲蜜房。',32,'全唐诗/poet.song.129000.json','["看書澀似上羊腸，得睡甘如飲蜜房。", "起坐藤床搔短髮，數聲畫角報斜陽。"]'),
('cc84e980-ba00-4c82-8368-eb7ee6d121f9','拜旦表','陸游','宋','宋诗','song-poetry','','[]','一封馳奏效嵩呼，清蹕何時返故都。',32,'全唐诗/poet.song.129000.json','["一封馳奏效嵩呼，清蹕何時返故都。", "只道建炎巡狩禮，誰知故事自祥符。"]'),
('da0303e7-a28f-4dc3-990b-24d0594c8805','早自烏龍廟歸','陸游','宋','宋诗','song-poetry','','[]','殘漏聲中聽曵鈴，翩翩吹帽出郊坰。',64,'全唐诗/poet.song.129000.json','["殘漏聲中聽曵鈴，翩翩吹帽出郊坰。", "雨餘澗落雙虹白，雲合山餘一髮青。", "鐵馬蹴冰悲昨夢，朱顔辭鏡感頽齡。", "歸来獨對空齋冷，鳥迹蒼苔自滿庭。"]'),
('ce93d642-8265-4fa4-9e3f-2986390c26db','上丁','陸游','宋','宋诗','song-poetry','','[]','燎火朙中庭，老槐泣殘雨。',96,'全唐诗/poet.song.129000.json','["燎火朙中庭，老槐泣殘雨。", "白頭奉祀事，恐懼劇仰俯。", "三終樂在懸，再拜肉升爼。", "誰言千載後，恍若到鄒魯。", "吾國雖褊小，大社胙茆土。", "如何儼章綬，日夜臨箠楚。", "藏書如丘山，及物無一羽。", "吾其可憐哉，去去老農圃。"]'),
('618ca77c-5eec-4c51-af6b-4f9e2b182cc8','新秋','陸游','宋','宋诗','song-poetry','','[]','打窗落葉報秋期，病叟頽然兩鬢絲。',64,'全唐诗/poet.song.129000.json','["打窗落葉報秋期，病叟頽然兩鬢絲。", "縱酒已無年少夢，讀書仍負夜涼時。", "問囚損氣嗟誰念，學道刳心恐已遲。", "買鶴清溪歸計足，寄聲先遣故人知。"]'),
('905a0cea-a894-4a8b-92c0-8f85e7e3cb29','殘年','陸游','宋','宋诗','song-poetry','','[]','殘年迫鍾漏，病骨怯風霜。',48,'全唐诗/poet.song.129000.json','["殘年迫鍾漏，病骨怯風霜。", "投幘早當去，強顔徒自傷。", "文符紛似雨，訟訴進如牆。", "笑殺滄浪客，微官有許忙。"]'),
('a2e4b479-78c9-464b-89a0-470584d2ab89','休日行郡圃','陸游','宋','宋诗','song-poetry','','[]','南山如黛照朱扉，地接官居到亦稀。',64,'全唐诗/poet.song.129000.json','["南山如黛照朱扉，地接官居到亦稀。", "寒蝶徘徊掠衰草，孤花閑淡弄斜暉。", "荒城歌舞難娛客，休日文書且解圍。", "猶勝去年窮巷底，臥聞砧杵念秋衣。"]'),
('17439846-212c-46cd-8f0e-4c3238d3790f','登北榭','陸游','宋','宋诗','song-poetry','','[]','繞城山作翠濤傾，底事文書日有程。',64,'全唐诗/poet.song.129000.json','["繞城山作翠濤傾，底事文書日有程。", "無溷我爲揮吏散，獨登樓去看雲生。", "香浮鼻觀煎茶熟，喜動眉間煉句成。", "莫笑衰翁淡生活，它年猶得配玄英。"]'),
('3a6fc64c-190e-4af0-8c46-1ceb0fb68e73','小酌','陸游','宋','宋诗','song-poetry','','[]','簾外桐疏見露蟬，一壺聊醉嫩寒天。',64,'全唐诗/poet.song.129000.json','["簾外桐疏見露蟬，一壺聊醉嫩寒天。", "團臍磊落吴江蟹，縮項輪囷漢水鯿。", "投老宦遊真漫爾，平生懷抱固超然。", "文書縛急何由耐，會向長安市上眠。"]'),
('93d89fa3-a837-458c-9bcb-a3b4be5ff30c','焚香作墨瀋決訟吏皆退立一丈外戲作此詩','陸游','宋','宋诗','song-poetry','','[]','客鬢新添幾縷絲，山城且付一官癡。',64,'全唐诗/poet.song.129000.json','["客鬢新添幾縷絲，山城且付一官癡。", "空濛碧靄籠香岫，霮䨴玄雲起墨池。", "判牒不妨閑作草，坐衙聊得細哦詩。", "吏民莫怪秋来健，漸近南山射虎時。"]'),
('f802a3e1-4d56-435a-8f30-157bfee4c22e','齋中閑詠','陸游','宋','宋诗','song-poetry','','[]','風號萬物作濤聲，雲截千峰似几平。',64,'全唐诗/poet.song.129000.json','["風號萬物作濤聲，雲截千峰似几平。", "多病支離仍老境，暮秋蕭瑟更山城。", "燕觴久罷塵痕積，庭訟全稀蘚暈生。", "莫道齋中日無事，焚香掃地又詩成。"]'),
('52c770d1-9ae0-4521-86c6-c1426b24621f','秋夜聞雨','陸游','宋','宋诗','song-poetry','','[]','香斷燈昏小幌深，不堪病裏值秋霖。',64,'全唐诗/poet.song.129000.json','["香斷燈昏小幌深，不堪病裏值秋霖。", "驚回萬里關河夢，滴碎孤臣犬馬心。", "清似釣舩聞急瀨，悲於靜院聽繁砧。", "玉峰老去情懷惡，穩受千莖雪鬢侵。"]'),
('8b88e456-917c-4a26-b9a6-812a05f6a554','自詠','陸游','宋','宋诗','song-poetry','','[]','鈍似窗間十月蠅，淡如世外一孤僧。',64,'全唐诗/poet.song.129000.json','["鈍似窗間十月蠅，淡如世外一孤僧。", "心勞撫字雖亡補，筆判虚空却粗能。", "厭見文書衘客袖，但思蔬水曲吾肱。", "何時却宿雲門寺，靜聽霜鐘對佛燈。"]'),
('7414a548-15ed-4402-9926-b5d7652f13d6','秋懷','陸游','宋','宋诗','song-poetry','','[]','少時本願守墳墓，讀書射獵畢此生。',161,'全唐诗/poet.song.129000.json','["少時本願守墳墓，讀書射獵畢此生。", "斷蓬遇風不自覺，偶入戎幙從西征。", "朝看十萬閱武罷，暮馳三百巡邊行。", "馬蹏度隴雹聲急，士甲照日波光朙。", "興懷徒寄廣武嘆，薄福不挂雲臺名。", "頷鬚白盡愈落莫，始讀法律親笞榜。", "訟氓滿庭閙如市，吏牘圍坐高于城。", "未嫌樵唱作野哭，最怕甜酒傾稀金文。", "平生養氣頗自許，雖老尚可吞司并。", "何時擁馬横戈去，聊爲君王護北平。"]'),
('1c9eaea7-8500-4746-9ea1-67d50113efae','不寐','陸游','宋','宋诗','song-poetry','','[]','閏年九月已重裘，說著功名即自羞。',64,'全唐诗/poet.song.129000.json','["閏年九月已重裘，說著功名即自羞。", "病骨不禁霜氣峭，高風正送雁聲遒。", "半杯濁酒如欺老，一點青燈欲訴愁。", "不寐裁詩真習氣，輸它睡足向黄州。"]'),
('73247246-53fb-48a2-a159-ac5b23ec0905','醉中戲作','陸游','宋','宋诗','song-poetry','','[]','當年買酒醉新豐，豪士相期意氣中。',64,'全唐诗/poet.song.129000.json','["當年買酒醉新豐，豪士相期意氣中。", "插羽軍書立談辦，如山鐵騎一麾空。", "玉關久付清宵夢，笠澤今成白髮翁。", "堪笑燈前如意舞，尚將老健壓諸公。"]'),
('83a10d1d-bc6c-4323-8892-0ac683993e7b','頻夜夢至南鄭小益之間慨然感懷二首  其一','陸游','宋','宋诗','song-poetry','','[]','身似庵居老病僧，罷參不復繫行縢。',32,'全唐诗/poet.song.129000.json','["身似庵居老病僧，罷參不復繫行縢。", "夢中忽在三泉驛，庭樹鳴梟鬼弄燈。"]'),
('30fd7399-1790-44bc-9b56-4ff4d8648360','頻夜夢至南鄭小益之間慨然感懷二首  其二','陸游','宋','宋诗','song-poetry','','[]','客枕夢遊何處所，梁州西北上危臺。',32,'全唐诗/poet.song.129000.json','["客枕夢遊何處所，梁州西北上危臺。", "雪雲不隔平安火，一點遥從駱谷来。"]'),
('4bd007e3-74fb-4c68-b617-77a7ebc2bf56','夜雨枕上','陸游','宋','宋诗','song-poetry','','[]','秋雨不肯晴，秋夜不肯明。',48,'全唐诗/poet.song.129000.json','["秋雨不肯晴，秋夜不肯明。", "寸心集百憂，厭此點滴聲。", "歲月不貸人，老病忽至此。", "丈夫本憂世，兒女乃畏死。"]'),
('51029778-eb2c-448b-b6d5-b570347701ec','雨夜','陸游','宋','宋诗','song-poetry','','[]','蒼雲晝埋山，白雨夜溢渠。',72,'全唐诗/poet.song.129000.json','["蒼雲晝埋山，白雨夜溢渠。", "虚堂閃風燈，獨處誰與娱。", "吾生過六十，鬢髮日夜疏。", "出當飲美酒，歸當讀奇書。", "可憐兩不遂，兀兀如枯株。", "明復對胥吏，孤憤何由攄。"]'),
('d049621a-03fc-4a7b-b922-2ac5db403e0f','安流亭俟客不至獨坐成詠','陸游','宋','宋诗','song-poetry','','[]','憶昔西征鬢未霜，拾遺陳迹吊微茫。',64,'全唐诗/poet.song.129000.json','["憶昔西征鬢未霜，拾遺陳迹吊微茫。", "蜀江春水千帆落，禹廟空山百草香。", "馬影斜陽經劍閣，櫓聲清曉下瞿唐。", "酒徒雲散無消息，水榭憑欄泪數行。"]'),
('a6ad51aa-f851-4cc4-bebf-3442013c0477','秋興二首  其一','陸游','宋','宋诗','song-poetry','','[]','楸槐雨霋霋，鳬雁水拍拍。',72,'全唐诗/poet.song.129000.json','["楸槐雨霋霋，鳬雁水拍拍。", "曉行城南路，落葉滿阡陌。", "新霜上衰鬢，吾死亦已迫。", "那將有限身，常作未歸客。", "長吟側紗帽，萬里一秋色。", "世俗不足論，天豈無皁白。"]'),
('dd185886-8f55-47ea-812c-8f69a6363698','秋興二首  其二','陸游','宋','宋诗','song-poetry','','[]','朝先鳴雞興，夕殿棲鵶還。',72,'全唐诗/poet.song.129000.json','["朝先鳴雞興，夕殿棲鵶還。", "符檄積几案，寢飯於其間。", "搒笞督租賦，涉筆騂我顔。", "忽忽過白日，胡能慰惸鰥。", "葉脫横林疏，䰀鬌溪南山。", "豈無一杯酒，吾事何時閑。"]'),
('6c22bf7d-8498-4a7d-b608-ba1f0208132f','燕堂獨坐意象殊憒憒起登子城作此詩','陸游','宋','宋诗','song-poetry','','[]','睡魔困衰翁，白日坐兀兀。',168,'全唐诗/poet.song.129000.json','["睡魔困衰翁，白日坐兀兀。", "忽然振衣起，目瞭尚如鶻。", "憑高望中原，佳氣未消歇。", "逆賊稽大刑，痛憤深至骨。", "新霜下昌陵，草有胡馬齕。", "羽林百萬士，何日聞北伐。", "賤臣官有守，不敢叫行闕。", "夢中涉黄河，太行高硉矹。", "天河未洗兵，封豕食上國。", "坐令河洛間，百郡暗荆棘。", "夷吾非王佐，尚足救左袵。", "中原消息斷，吾輩何安寢。", "世俗苦齷齪，誰與共此功。", "安知無奇士，悲歌燕市中。"]'),
('1f094e3b-e6f2-46af-a829-ab436a599594','秋雨北榭作','陸游','宋','宋诗','song-poetry','','[]','秋風吹雨到江濆，小閣疏簾曉色分。',64,'全唐诗/poet.song.129000.json','["秋風吹雨到江濆，小閣疏簾曉色分。", "津吏報增三尺水，山僧歸入萬重雲。", "飄零露井無桐葉，斷續烟汀有雁群。", "了却文書早尋睡，檐聲偏愛枕閑聞。"]'),
('98625979-130f-4967-bfd5-33b62f301fe6','次韵王給事見寄','陸游','宋','宋诗','song-poetry','','[]','大手方司一世文，癯儒何敢望餘塵。',64,'全唐诗/poet.song.129000.json','["大手方司一世文，癯儒何敢望餘塵。", "誰知天上黄扉貴，肯記江邊白髮新。", "末路愈窮詩有祟，舊書渾忘筆無神。", "床頭周易尊中酒，猶賴渠儂不負人。"]'),
('f65daf46-9083-4adf-979e-853a5cd72b12','病中夜半','陸游','宋','宋诗','song-poetry','','[]','蕭蕭欲脫猶吟葉，耿耿微明未滅燈。',32,'全唐诗/poet.song.129000.json','["蕭蕭欲脫猶吟葉，耿耿微明未滅燈。", "夜半不眠閑倚壁，使君清似北山僧。"]'),
('53a06f71-a4fb-4f8c-acc1-6225764e1a50','即事','陸游','宋','宋诗','song-poetry','','[]','組繡紛紛衒女工，詩家於此欲途窮。',32,'全唐诗/poet.song.129000.json','["組繡紛紛衒女工，詩家於此欲途窮。", "語君白日飛昇法，正在焚香聽雨中。"]'),
('2a30706f-d87a-4d55-a62b-29330ab7d538','歲晚懷故人','陸游','宋','宋诗','song-poetry','','[]','衰髯白盡無添處，病骨癯然欲折時。',64,'全唐诗/poet.song.129000.json','["衰髯白盡無添處，病骨癯然欲折時。", "客抱琴来聨瀹茗，吏封印去又哦詩。", "山横城上勢如壓，角動樓頭聲正悲。", "零落斷鴻書不到，歲殘何以慰相思。"]'),
('ccc94bbf-a3e5-4ec5-9d79-8fbabb5684bd','焉耆行二首  其一','陸游','宋','宋诗','song-poetry','','[]','焉耆山頭暮烟紫，牛羊聲斷行人止。',64,'全唐诗/poet.song.129000.json','["焉耆山頭暮烟紫，牛羊聲斷行人止。", "平沙風急捲寒蓬，天似穹廬月如水。", "大胡太息小胡悲，投鞍欲眠且復起。", "漢家詔用李輕車，萬丈戰雲来壓壘。"]'),
('f8765bd0-4cb9-45bb-a184-2aa532f7623f','焉耆行二首  其二','陸游','宋','宋诗','song-poetry','','[]','焉耆山下春雪晴，莽莽惟有蒺藜生。',64,'全唐诗/poet.song.129000.json','["焉耆山下春雪晴，莽莽惟有蒺藜生。", "射麋食肉飲其血，五穀自古惟聞名。", "樵蘇切莫近亭障，將軍臥護真長城。", "十年牛馬向南睡，知是中原今太平。"]'),
('e35600fc-6ead-4ce2-968b-4bbaaeead663','丙午初冬得心腹痛疾大下而愈羸耗不支方在告臥燕堂東偏聞民間前一夕被盜者慨然有感','陸游','宋','宋诗','song-poetry','','[]','愔愔四壁空，宛宛一室奧。',96,'全唐诗/poet.song.129000.json','["愔愔四壁空，宛宛一室奧。", "雨聲靜更聞，雨氣深不到。", "下簾設紙屏，篝火支藥竈。", "勿言此幽陋，足以養衰眊。", "頗聞閭里間，比夕多狗盗。", "游徼無乃闕，鰥寡將孰告。", "家貧未决去，祿食當念報。", "臥痾疇敢安，起立擲吾帽。"]'),
('9aba3e09-3a02-4525-b085-950adca29a37','因王給事回使奉寄','陸游','宋','宋诗','song-poetry','','[]','雨昏郡郭連三日，吏報江流忽數回。',64,'全唐诗/poet.song.129000.json','["雨昏郡郭連三日，吏報江流忽數回。", "正嘆舩如天上坐，那知人自日邊来。", "臂弓腰箭身今老，航海梯山運已開。", "漢冦不應常自守，期公決策畫雲臺。"]'),
('8ec657e3-67ce-4824-b2ad-a41d69db904e','病告中遇風雪作長歌排悶','陸游','宋','宋诗','song-poetry','','[]','風雪横街不能出，閉戸垂帷養衰疾。',160,'全唐诗/poet.song.129000.json','["風雪横街不能出，閉戸垂帷養衰疾。", "黄昏臥聽打窗聲，聊挽清寒入詩律。", "公孫布被久有味，子敬青氊暖無匹。", "石鼎閑烹似爪茶，霜皺旋破如拳栗。", "蹲鴟足火微點鹽，罌粟熬湯旋添蜜。", "龍蛇𧥄𧥄寒筍束，子母累累丹柿實。", "玉狸試說涎已墮，石芥纔嘗酒如失。", "天公付汝亦已厚，飽食長謠抱雙膝。", "丈夫豈爲口腹計，壯志常恐無時畢。", "伐胡疏奏端許前，腰領敢辭膏斧鑕。"]'),
('36977d38-3fa9-4f37-84c5-69eb9f7f20e8','冬夜戲作','陸游','宋','宋诗','song-poetry','','[]','賤貧百年愁，老大萬事倦。',96,'全唐诗/poet.song.129000.json','["賤貧百年愁，老大萬事倦。", "起家來牧民，竊語笑丞掾。", "拘攣拙徵科，儉陋省遊宴。", "不思返江湖，乃爾辱畿甸。", "斯言中吾病，有靦在其面。", "行當自劾去，暫寓等郵傳。", "十月夜正長，歲事到冰霰。", "膏油幸可具，更盡書一卷。"]'),
('f257a46d-37d0-4a0f-b65e-c42aa9332a5d','夜坐二首  其一','陸游','宋','宋诗','song-poetry','','[]','曲几蒲團夜過分，頹然半脫鹿皮巾。',64,'全唐诗/poet.song.129000.json','["曲几蒲團夜過分，頹然半脫鹿皮巾。", "驚鴻避弋鳴煙渚，斷角凌風上雪雲。", "仕宦愈知林下貴，窮愁方策酒中勛。", "扁舟東去何時辦，昔向金丹幸有聞。"]'),
('6518db46-d57e-4b38-b19a-8ea6fc0bcc32','夜坐二首  其二','陸游','宋','宋诗','song-poetry','','[]','山城意象自蕭然，況是高齋作雪天。',64,'全唐诗/poet.song.129000.json','["山城意象自蕭然，況是高齋作雪天。", "漸暗玉蟲寒有燼，欲殘金鴨暖無烟。", "衰容病後如添歲，遥夜冬来抵過年。", "安得龍綃三丈幅，爲君試寫白雲篇。"]'),
('3e4c4782-cbdd-405b-acf8-4e0624341824','遣興','陸游','宋','宋诗','song-poetry','','[]','圖書雞犬共扁舟，又續人間汗漫遊。',64,'全唐诗/poet.song.129000.json','["圖書雞犬共扁舟，又續人間汗漫遊。", "醉眼本輕千古事，釣竿新賜一灘秋。", "慣看浮世成陵谷，莫露神光上斗牛。", "老病豈堪常作客，夢尋歸路傍西疇。"]'),
('f488c965-e90e-4167-ab74-8c93375899aa','登紫翠樓','陸游','宋','宋诗','song-poetry','','[]','水落溪聲壯，天寒山色奇。',48,'全唐诗/poet.song.129000.json','["水落溪聲壯，天寒山色奇。", "殘雲宿虚閣，馴鷺下清池。", "簿領消豪氣，功名負聖時。", "憑高不勝嘆，神武迫歸期。"]'),
('30ba6c41-c3df-43cd-9cfb-9eb7bebb6b3b','丙午十月十三夜夢過一大冢傍人爲余言此荆軻墓也按地志荆軻墓蓋在關中感嘆賦詩','陸游','宋','宋诗','song-poetry','','[]','采藥遊名山，物外富真賞。',96,'全唐诗/poet.song.129000.json','["采藥遊名山，物外富真賞。", "秋關策蹇驢，雪峽蕩孤漿。", "還鄉忽十載，高興寄遐想。", "夢行河潼間，初日照仙掌。", "坡陀荆棘冢，狐兔伏蓁莽。", "悲歌易水寒，千古見精爽。", "國讎久不復，驚覺泚吾顙。", "何時真過兹，薄酹神所饗。"]'),
('14718643-652b-411b-a727-e962387daf16','病起小飲','陸游','宋','宋诗','song-poetry','','[]','病起新霜滿鬢蓬，憑高一笑與誰同。',64,'全唐诗/poet.song.129000.json','["病起新霜滿鬢蓬，憑高一笑與誰同。", "酒如淥靜春江水，人有鴻荒太古風。", "野寺鐘来夕陽外，寒山空插亂雲中。", "一官正爾妨人樂，只合滄浪狎釣翁。"]'),
('7542c3c2-6203-4d09-afdd-8a8da02ce4a2','冬夜讀書','陸游','宋','宋诗','song-poetry','','[]','莫笑燈檠二尺餘，老来舊學要耘鉏。',64,'全唐诗/poet.song.129000.json','["莫笑燈檠二尺餘，老来舊學要耘鉏。", "寒生點滴三更雨，喜動縱横萬卷書。", "本著儒冠那免此，可因吏牘頓抛渠。", "善和舊賜今猶在，剩采芸香辟蠧魚。"]'),
('33bf2831-5c85-454e-913b-685d96ae56c8','夜坐觀小兒作擬毛詩欣然有賦','陸游','宋','宋诗','song-poetry','','[]','北風城頭鼓紞紞，徂歲崢嶸正多感。',128,'全唐诗/poet.song.129000.json','["北風城頭鼓紞紞，徂歲崢嶸正多感。", "老夫假寐角巾低，稺子高吟兩髦髧。", "衰遲笑我藏袖手，狂率憐渠滿軀膽。", "旋炊粉饐裹青箬，新煠餳枝綴紅糝。", "未言問事漸瀾翻，且賞揮毫能果敢。", "嗟予疇昔如汝年，萬卷縱横恣窺覽。", "即今見汝尚懽欣，此癖真同嗜昌歜。", "夜闌我困兒亦歸，獨與貍奴分坐毯。"]'),
('a51c4ad8-1358-4cf1-85ed-f7066604d448','郡齋偶書三首  其一','陸游','宋','宋诗','song-poetry','','[]','白首奉魚書，蕭然一事無。',48,'全唐诗/poet.song.129000.json','["白首奉魚書，蕭然一事無。", "吏閑晨已散，人醉暮相扶。", "卷野收禾黍，連江下舳艫。", "山城君勿誚，東北是皇都。"]'),
('bfd27071-9dfd-419e-9cb2-0a97bb03733e','郡齋偶書三首  其二','陸游','宋','宋诗','song-poetry','','[]','翠嶺當城起，清江擘硤流。',48,'全唐诗/poet.song.129000.json','["翠嶺當城起，清江擘硤流。", "軻峨商客艑，嘈囋酒家樓。", "豐歲人元樂，殘年我獨愁。", "秦吴環萬里，感槩故貂裘。"]'),
('f730a51b-189c-405c-9f30-9274354a868b','郡齋偶書三首  其三','陸游','宋','宋诗','song-poetry','','[]','江墮清笳月，霜嚴畫戟門。',48,'全唐诗/poet.song.129000.json','["江墮清笳月，霜嚴畫戟門。", "灘聲寒更壯，山氣旦常昏。", "揺落悲徂歲，羈遊憶故園。", "無勞空竊食，何以報君恩。"]'),
('27c9b11a-32ef-455a-8b18-4f8b8849e46b','燈下閱吏牘有感','陸游','宋','宋诗','song-poetry','','[]','老眼今年太負渠，羲經魯史頓成疏。',64,'全唐诗/poet.song.129000.json','["老眼今年太負渠，羲經魯史頓成疏。", "一爲柱後惠文吏，厭讀司空城旦書。", "正苦雁行須束縛，不言鼠輩合誅鉏。", "致君堯舜元無術，黄卷何辭飽蠧魚。"]'),
('b296a984-3d5a-4db6-b7d5-dbe7486cbbff','過放生池追懷江公民表諫議池蓋公所創也','陸游','宋','宋诗','song-poetry','','[]','釣臺先生諫大夫，建中初元起江湖。',128,'全唐诗/poet.song.129000.json','["釣臺先生諫大夫，建中初元起江湖。", "是是非非玉座側，身可死徙志不渝。", "烟汀月島二十載，白髮短䑧藏菰蒲。", "晚蒙湔洗得一障，上奏猶自稱粗疏。", "此公造處直奇特，竺乾先生分半席。", "九州看如掌中果，天不遣爲吁可惜。", "徑歸斂手築陂池，也活龜魚論萬億。", "骨冷桐山喚不聞，停車悵望春波碧。"]'),
('4ea5cce6-f5b3-4d8a-aa75-6ef94ec52dc2','園中絕句二首  其一','陸游','宋','宋诗','song-poetry','','[]','梅花重壓帽簷偏，曵杖行歌意欲仙。',32,'全唐诗/poet.song.129000.json','["梅花重壓帽簷偏，曵杖行歌意欲仙。", "後五百年君記取，斷無人似放翁顛。"]'),
('53d43659-615c-4191-ae02-2bd2ff22b131','園中絕句二首  其二','陸游','宋','宋诗','song-poetry','','[]','溪北溪南飛白鷗，夕陽明處見漁舟。',32,'全唐诗/poet.song.129000.json','["溪北溪南飛白鷗，夕陽明處見漁舟。", "憑誰爲剪機中素，畫取天涯一片秋。"]'),
('d3b45cda-4ffa-44c6-92a6-e02c33f64095','戲作','陸游','宋','宋诗','song-poetry','','[]','歸臥元知作餓夫，官遊依舊是癯儒。',32,'全唐诗/poet.song.129000.json','["歸臥元知作餓夫，官遊依舊是癯儒。", "免教妻子爭秔秫，秋稼連雲一稜無。"]'),
('ff27dd87-d9b6-4bcf-87ac-fbcf73b53ee4','縱筆三首  其一','陸游','宋','宋诗','song-poetry','','[]','閑經月下白蘋洲，半脫風前紫綺裘。',64,'全唐诗/poet.song.129000.json','["閑經月下白蘋洲，半脫風前紫綺裘。", "曾值東風謁鸞駕，却因南渡看龍舟。", "年光已付瞢騰醉，天宇誰從汗漫遊。", "莫怪又成横笛去，故人期我玉華樓。"]'),
('93ed055d-196b-4833-be5c-5a6c6903eea8','縱筆三首  其二','陸游','宋','宋诗','song-poetry','','[]','東都宫闕鬱嵯峨，忍聽胡兒敕勒歌。',64,'全唐诗/poet.song.129000.json','["東都宫闕鬱嵯峨，忍聽胡兒敕勒歌。", "雲隔江淮翔翠鳳，露霑荆棘沒銅駝。", "丹心自笑依然在，白髮將如老去何。", "安得鐵衣三萬騎，爲君王取舊山河。"]'),
('582363f0-11bd-44a9-b56b-d54c030cde17','縱筆三首  其三','陸游','宋','宋诗','song-poetry','','[]','行省當年駐隴頭，腐儒隨牒亦西遊。',64,'全唐诗/poet.song.129000.json','["行省當年駐隴頭，腐儒隨牒亦西遊。", "千艘衝雪魚關曉，萬竈連雲駱谷秋。", "天道難知羌更熾，神州未復士堪羞。", "會須瀝血書封事，請報天家九世讎。"]'),
('afa23874-fdcd-4deb-b36d-52395937abf3','病中偶得名酒小醉作此篇是夕極寒','陸游','宋','宋诗','song-poetry','','[]','一壺花露拆黄縢，醉夢酣酣喚不譍。',64,'全唐诗/poet.song.129000.json','["一壺花露拆黄縢，醉夢酣酣喚不譍。", "屏暖半銷香鴨火，窗寒初結研蟾冰。", "詩囊羞澀悲才盡，藥褁縱横覺病增。", "早挂朝衣歸去是，貴人誰記接茵憑。"]'),
('193218d9-505d-473f-b644-616e681928dc','晨讀道書','陸游','宋','宋诗','song-poetry','','[]','家貧悔嗜酒，年邁思學道。',72,'全唐诗/poet.song.129000.json','["家貧悔嗜酒，年邁思學道。", "雖云善補過，見事恨不早。", "儒生守章句，忽忽遂將老。", "巖間得奇書，足以慰華皓。", "丹液下注臍，黄雲上通腦。", "海山行當歸，白髮何足掃。"]'),
('4450a07f-d244-4566-8465-6fbb78de4697','後園獨步有懷張季長正字','陸游','宋','宋诗','song-poetry','','[]','斯世元知少賞音，道存何恨死山林。',64,'全唐诗/poet.song.129000.json','["斯世元知少賞音，道存何恨死山林。", "半生去國風埃面，一片憂時鐵石心。", "閑看斷雲成小立，偶穿修竹得幽尋。", "故人已到梁州未，尺紙東来抵萬金。"]'),
('9ad8fe1f-b0ae-41da-983b-b3ca58350c4f','老將效唐人體','陸游','宋','宋诗','song-poetry','','[]','寶劍夜長鳴，金痍老未平。',48,'全唐诗/poet.song.129000.json','["寶劍夜長鳴，金痍老未平。", "指弓誇野戰，抵掌說番情。", "已矣黑山戍，悵然青史名。", "和親不用武，教子作儒生。"]'),
('836382c1-8dec-477a-9c6d-d5da6c672bfe','書憤','陸游','宋','宋诗','song-poetry','','[]','清汴逶迤貫舊京，宫牆春草幾番生。',64,'全唐诗/poet.song.129000.json','["清汴逶迤貫舊京，宫牆春草幾番生。", "剖心莫寫孤臣憤，抉眼終看此虜平。", "天地固將容小醜，冦戎自慣瀆齊盟。", "蓬窗老抱横行略，未敢隨人說弭兵。"]'),
('4071c0f6-5230-4a44-8bbc-c5e3457d467b','晨起','陸游','宋','宋诗','song-poetry','','[]','衣潤熏籠暖，燈殘漏箭長。',48,'全唐诗/poet.song.129000.json','["衣潤熏籠暖，燈殘漏箭長。", "鳴雞带窗月，立馬怯庭霜。", "病骨陰晴覺，官身早夜忙。", "火城那復夢，愁絕軟塵香。"]'),
('554b508f-6045-41a8-b132-194c989333d9','雪','陸游','宋','宋诗','song-poetry','','[]','但苦奇寒惱病翁，豈知上瑞報年豐。',64,'全唐诗/poet.song.129000.json','["但苦奇寒惱病翁，豈知上瑞報年豐。", "一庭不掃待新月，萬壑盡平號斷鴻。", "繭紙欲書先研凍，羽觴纔舉已尊空。", "若耶溪上梅千樹，欠我今年繫短篷。"]'),
('0fcaf291-7dd1-4cba-9bf9-8beb1a124d61','歲晚書懷','陸游','宋','宋诗','song-poetry','','[]','早見龍翔上太清，即今孤宦老山城。',64,'全唐诗/poet.song.129000.json','["早見龍翔上太清，即今孤宦老山城。", "靈丹不解換凡骨，薄命枉教生太平。", "積雪樓臺增壯觀，近春鳥雀有和聲。", "如山吏牘何時了，惆悵西窗晚照明。"]'),
('f28bfefe-3ce4-4b57-bd44-0472f6e74bb2','晨過天慶','陸游','宋','宋诗','song-poetry','','[]','蘿月挂團璧，松風號急灘。',48,'全唐诗/poet.song.129000.json','["蘿月挂團璧，松風號急灘。", "孤燈經院曉，殘雪醮壇寒。", "賸欲閑扶杖，何妨醉墮冠。", "詩成興不盡，萬里跨青鸞。"]'),
('b8615a94-164e-4b63-aefb-1d717b745023','冬夜','陸游','宋','宋诗','song-poetry','','[]','翩翩殘歴不滿紙，坎坎疊鼓無停撾。',96,'全唐诗/poet.song.129000.json','["翩翩殘歴不滿紙，坎坎疊鼓無停撾。", "香殘未消古鼎火，燈暗尚結寒缸花。", "長安故人日已遠，錦江小築天之涯。", "拘攣動覺吏有責，幽獨更似僧無家。", "臥聞沙雁叫空濶，想見雪谷森谽谺。", "起提一筆掃疋紙，入卷颯颯奔龍蛇。"]'),
('b1d6078f-e85d-4e54-a0eb-1d61b53e0341','比得朋舊書多索近詩戲作長句','陸游','宋','宋诗','song-poetry','','[]','庭下訟訴如堵牆，案上文書海茫茫。',101,'全唐诗/poet.song.129000.json','["庭下訟訴如堵牆，案上文書海茫茫。", "酒酸{炙火=肉}冷不得嘗，椎床大叫欲發狂。", "故人書来索文章，豈知吏責終歲忙。", "寒龜但欲事縮藏，病驥敢望重騰驤。", "日曛稍退鳬鶩行，小山樷竹堂東廂。", "呼兒深炷銅爐香，楚騷爲我祓不祥。"]'),
('efd0a797-6415-4a1e-8bb7-70fef8df5e4f','休日感興','陸游','宋','宋诗','song-poetry','','[]','宦海風波實飽經，久將人世寄郵亭。',64,'全唐诗/poet.song.129000.json','["宦海風波實飽經，久將人世寄郵亭。", "家無釵澤窮馮衍，身著襦裙老管寧。", "藥圃按行新蔓綠，書樓徙倚暮山青。", "偶然得句悲誰屬，零落交朋比曉星。"]'),
('5e9daadc-63f8-41f4-8caf-c19632b7e7ff','病中偶書','陸游','宋','宋诗','song-poetry','','[]','燈火青熒古屋深，挂冠境界已駸駸。',64,'全唐诗/poet.song.129000.json','["燈火青熒古屋深，挂冠境界已駸駸。", "竹枝影瘦横殘月，藥杵聲寒續暮砧。", "病覺死生真大事，老知道德愧初心。", "經龕禪版殊當勉，懶學莎蛩事苦吟。"]'),
('4f2da4ea-c794-49ab-bf07-da0d3ab41961','寒夜','陸游','宋','宋诗','song-poetry','','[]','脫葉爭辭木，寒雲巧護霜。',48,'全唐诗/poet.song.129000.json','["脫葉爭辭木，寒雲巧護霜。", "羈遊少歡樂，短景極怱忙。", "吟苦蟲催織，鳴哀雁斷行。", "幽懷誰晤語，惆悵此燈光。"]'),
('b81720d8-1103-4194-8ffd-7237ed01e2a3','雪中獨酌','陸游','宋','宋诗','song-poetry','','[]','金尊玉瀣有何好，不堪生世匆匆老。',96,'全唐诗/poet.song.129000.json','["金尊玉瀣有何好，不堪生世匆匆老。", "朱顔忽已謝晨鏡，白骨行看閉秋草。", "駭浪嵯峨風作之，蛟龍血人以爲嬉。", "畏塗寄命三十載，賴有痛飲紓吾悲。", "莫驚醉眼炯如電，假鉞猶堪行督戰。", "指麾突騎取遼陽，雪灑轅門夜傳箭。"]'),
('b0b7d0cb-0454-4b1b-8c40-ada824d5b5c7','送客','陸游','宋','宋诗','song-poetry','','[]','長亭柳漸柔，送客當閑遊。',48,'全唐诗/poet.song.129000.json','["長亭柳漸柔，送客當閑遊。", "江近聞津鼓，雲開見戍樓。", "簿書来衮衮，歲月去悠悠。", "閉眼尋歸路，春蕪滿故疇。"]'),
('6e718768-b8b3-4e68-9b6a-d537bb18b840','新晴','陸游','宋','宋诗','song-poetry','','[]','宿雨解殘雪，新春侵故年。',48,'全唐诗/poet.song.129000.json','["宿雨解殘雪，新春侵故年。", "和風拆冰罅，淡日弄窗妍。", "心事綠尊裏，歲華烏帽邊。", "今朝我病减，隨處一欣然。"]'),
('ff51d8bd-3a2e-4738-885b-fc5244e0154b','出城','陸游','宋','宋诗','song-poetry','','[]','翩翻烏帽出林坰，掠面風微酒半醒。',64,'全唐诗/poet.song.129000.json','["翩翻烏帽出林坰，掠面風微酒半醒。", "戍火難尋玉關夢，衣塵空愧草堂靈。", "天晴山雪明城郭，水漲江流近驛亭。", "客鬢不如堤上柳，數枝春動又青青。"]'),
('ad3bbd64-5086-442a-a0a6-99c6e057c668','立春日送客郊外','陸游','宋','宋诗','song-poetry','','[]','短鬢那禁歲月催，勝邊花底又春回。',64,'全唐诗/poet.song.129000.json','["短鬢那禁歲月催，勝邊花底又春回。", "雪消漸暖青鴛日，冰解初横玉鑑梅。", "江驛軒窗臨古道，市樓弦管賣新醅。", "自憐病守無歡意，一笑常因送客来。"]'),
('1bec628e-fbae-4b81-9b8a-4ade12b447ec','大雪自夜至旦欲午始晴','陸游','宋','宋诗','song-poetry','','[]','薄暮雪雲低，清宵氣慘悽。',48,'全唐诗/poet.song.129000.json','["薄暮雪雲低，清宵氣慘悽。", "方聽打窗急，已報與階齊。", "疏箔穿飛蝶，空庭聚戲猊。", "新晴思訪客，愁絕滿城泥。"]'),
('4674e728-8a60-4524-9f3b-2fc717d38e4e','雪夜有感','陸游','宋','宋诗','song-poetry','','[]','狂膽輪囷欲滿軀，一麾誰憫滯江湖。',64,'全唐诗/poet.song.129000.json','["狂膽輪囷欲滿軀，一麾誰憫滯江湖。", "青衫曾奏三千牘，白首猶思丈二殳。", "龍虎翔空瞻王氣，羌戎度漠避天誅。", "何時冒雪趨行殿，香案前頭進陣圖。"]'),
('fe5cc7cf-be0f-4919-bda9-16f2e3c4372c','雪中忽起從戎之興戲作四首  其一','陸游','宋','宋诗','song-poetry','','[]','狐裘臥載錦駝車，酒醒冰髭結亂珠。',32,'全唐诗/poet.song.129000.json','["狐裘臥載錦駝車，酒醒冰髭結亂珠。", "三尺馬鞭裝白玉，雪中畫字草軍書。"]'),
('28adbe3d-aa6b-4636-8f8b-2239e2226b1b','雪中忽起從戎之興戲作四首  其二','陸游','宋','宋诗','song-poetry','','[]','鐵馬渡河風破肉，雲梯攻壘雪平壕。',32,'全唐诗/poet.song.129000.json','["鐵馬渡河風破肉，雲梯攻壘雪平壕。", "獸奔鳥散何勞逐，直斬單于釁寶刀。"]'),
('2024f8ac-d882-4653-a5c2-f1a311566764','雪中忽起從戎之興戲作四首  其三','陸游','宋','宋诗','song-poetry','','[]','十萬貔貅出羽林，横空殺氣結層陰。',32,'全唐诗/poet.song.129000.json','["十萬貔貅出羽林，横空殺氣結層陰。", "桑乾沙土初飛雪，未到幽州一丈深。"]'),
('4b39d5e1-5ce6-4adb-868e-15502d180a07','雪中忽起從戎之興戲作四首  其四','陸游','宋','宋诗','song-poetry','','[]','群胡束手仗天亡，棄甲縱横滿戰塲。',32,'全唐诗/poet.song.129000.json','["群胡束手仗天亡，棄甲縱横滿戰塲。", "雪上急追奔馬迹，官軍夜半入邊荒。"]'),
('5d978036-f857-4b37-85d5-bb62bf431f0e','十二月二十七日祭風師歸道中作','陸游','宋','宋诗','song-poetry','','[]','虎豹生憎上九關，諸公衮衮遂難攀。',64,'全唐诗/poet.song.129000.json','["虎豹生憎上九關，諸公衮衮遂難攀。", "面顔已老塵埃裏，精力虛捐簿領間。", "束带敢言趨玉陛，横戈猶憶戍天山。", "新春自笑摧頹甚，鼓吹東風拜胙還。"]'),
('280b67cf-a909-4cec-ac81-f794eb3e6c11','春晴','陸游','宋','宋诗','song-poetry','','[]','南陌爭牛事已非，綵山又近放燈期。',64,'全唐诗/poet.song.129000.json','["南陌爭牛事已非，綵山又近放燈期。", "風和已染柳千縷，山冷未開茶一旗。", "酒病況當人别後，春光偏在雪晴時。", "道傍笑我清狂在，馬上看山細詠詩。"]'),
('30b0fed1-00ea-4acc-a881-0796bce2e5e6','丁未正月春色已粲然露坐高風堂北觀種花','陸游','宋','宋诗','song-poetry','','[]','苦寒不觧歲崢嶸，病守兀坐憂疲氓。',128,'全唐诗/poet.song.129000.json','["苦寒不觧歲崢嶸，病守兀坐憂疲氓。", "天風誰遣撼斗柄，便覺春色来江城。", "北山賽廟見殘雪，東津送客聞新鶯。", "衣裘漸減體殊健，簾幙乍捲眼爲明。", "今朝天氣更佳絕，淡日微漏雲徐行。", "我移胡床坐庭下，幅巾半脫笻枝横。", "散關旌旗掃昨夢，少城絲竹真前生。", "數株桃杏亦漫種，未去與汝聊逢迎。"]'),
('0a68ea6a-7534-4532-871e-113b3c166fc9','燕堂春夜','陸游','宋','宋诗','song-poetry','','[]','南樓紞紞下疏更，一點紗籠滿院明。',64,'全唐诗/poet.song.129000.json','["南樓紞紞下疏更，一點紗籠滿院明。", "映月疏梅入簾影，讀書稺子隔窗聲。", "呻吟藥褁身寧久，汛掃邊塵意未平。", "草檄北征今二紀，山城仍是老書生。"]'),
('67829f4d-77f7-4d8a-86d7-90745e4e7f42','早春池上作','陸游','宋','宋诗','song-poetry','','[]','疏懶元當與世辭，殘年況近乞身期。',64,'全唐诗/poet.song.129000.json','["疏懶元當與世辭，殘年況近乞身期。", "一官空作讀書祟，五斗不供沽酒資。", "冰拆野塘初灧灧，雪殘芳草已離離。", "物華似有平生舊，不待招呼盡入詩。"]'),
('863e68db-cd25-4cd7-83a4-2d62ae6659f3','感興','陸游','宋','宋诗','song-poetry','','[]','文章天所秘，賦予均功名。',144,'全唐诗/poet.song.129000.json','["文章天所秘，賦予均功名。", "吾嘗考在昔，頗見造物情。", "離堆太史公，青蓮老先生。", "悲鳴伏櫪驥，蹭蹬失水鯨。", "飽以五車讀，勞以萬里行。", "險艱外備嘗，憤鬱中不平。", "山川與風俗，雜錯而交并。", "邦家志忠孝，人鬼參幽明。", "感概發奇節，涵養出正聲。", "故其所述作，浩浩河流傾。", "豈惟配詩書，自足齊韺鬴。", "我衰敢議此，長歌涕縱横。"]'),
('060db8b9-f7b6-4ed8-acc5-286e7d21ca16','東齋偶書','陸游','宋','宋诗','song-poetry','','[]','華髮蕭蕭不滿簪，強扶衰病著朝衫。',64,'全唐诗/poet.song.129000.json','["華髮蕭蕭不滿簪，強扶衰病著朝衫。", "寒廳靜似阿蘭若，佳客少于優缽曇。", "詩酒放懷窮亦樂，文移肆罵老難堪。", "棄官若遂飄然計，不死揚州死劍南。"]'),
('be807f56-af58-4426-a342-2c0dced419f9','丁未上元月色達曉如晝予齋居屬貳車領客','陸游','宋','宋诗','song-poetry','','[]','此夕幾年無此情，碧天萬里月徐行。',64,'全唐诗/poet.song.129000.json','["此夕幾年無此情，碧天萬里月徐行。", "官壚賣酒傾千斛，市里行歌徹五更。", "潼酪獨烹僧缽美，瑠璃閑照佛龕明。", "頽然坐睡君無笑，寶馬香車事隔生。"]'),
('ddf9f033-0a73-421f-a2c1-0a14239564e7','自郊外歸北望譙樓','陸游','宋','宋诗','song-poetry','','[]','天上何年墮翠虬，屈蟠爪尾護吾州。',64,'全唐诗/poet.song.129000.json','["天上何年墮翠虬，屈蟠爪尾護吾州。", "重門雨細旌旗濕，危堞風高鼓角遒。", "漠漠川雲昏佛塔，涓涓野水入農疇。", "曠懷不耐微官縛，擬脫朝衫換釣舟。"]'),
('b3315494-6b00-4f68-9317-7e42d27b2718','馬上作','陸游','宋','宋诗','song-poetry','','[]','平橋小陌雨初收，淡日穿雲翠靄浮。',32,'全唐诗/poet.song.129000.json','["平橋小陌雨初收，淡日穿雲翠靄浮。", "楊柳不遮春色斷，一枝紅杏出牆頭。"]'),
('ce627f9e-4e1d-4b5e-87ce-73d2a9429e1f','還舍','陸游','宋','宋诗','song-poetry','','[]','剩欲衘杯樂太平，新愁還續舊愁生。',32,'全唐诗/poet.song.129000.json','["剩欲衘杯樂太平，新愁還續舊愁生。", "出門始覺春来早，處處簾櫳笑語聲。"]'),
('fb72be3c-6321-42d7-88ab-6386127d8d5a','杏花','陸游','宋','宋诗','song-poetry','','[]','江城開歲風雨頻，閉閤不出俄經旬。',96,'全唐诗/poet.song.129000.json','["江城開歲風雨頻，閉閤不出俄經旬。", "忽逢國豔带卯酒，坐覺天地無餘春。", "芳敷正當晨露重，盛麗欲擅年華新。", "數株欹斜傍山驛，一簇深淺臨烟津。", "徘徊跋馬不忍去，只恐飄墮隨車塵。", "念當載酒醉花下，破曉啼鶯先喚人。"]'),
('6f6c1fa7-68cd-47ed-a739-fe5e86ef2a9c','兩京','陸游','宋','宋诗','song-poetry','','[]','兩京烟柳厭邊塵，又見淳熙十四春。',64,'全唐诗/poet.song.129000.json','["兩京烟柳厭邊塵，又見淳熙十四春。", "薄命邅回猶許國，孤忠懇欵欲忘身。", "蘇君落魄黄金盡，褚令悲傷白髮新。", "曾向延和隨仗入，至今殿檻夢嶙峋。"]'),
('7b9722d6-19bf-4949-aa6a-11a7a9c8934c','贈表弟江參議','陸游','宋','宋诗','song-poetry','','[]','襄州參議真豪傑，熟視華途懶著鞭。',64,'全唐诗/poet.song.129000.json','["襄州參議真豪傑，熟視華途懶著鞭。", "奪得鸞箆花裏活，皎如玉樹酒中仙。", "才高狗監無人薦，句好雞林有客傳。", "老去眼邊親舊少，津亭少爲繫歸船。"]'),
('157756e0-fba4-40cf-b6d0-4a4a8caea444','讀書','陸游','宋','宋诗','song-poetry','','[]','束髮論交一世豪，暮年憔悴困蓬蒿。',64,'全唐诗/poet.song.129000.json','["束髮論交一世豪，暮年憔悴困蓬蒿。", "文辭博士書驢劵，職事參軍判馬曹。", "病裏猶須看周易，醉中亦復讀離騷。", "若爲可奈功名念，試覓并州快剪刀。"]'),
('22bb8bef-d6d6-4864-af32-6c08300ee05b','夜登千峰榭','陸游','宋','宋诗','song-poetry','','[]','夷甫諸人骨作塵，至今黄屋尚東巡。',64,'全唐诗/poet.song.129000.json','["夷甫諸人骨作塵，至今黄屋尚東巡。", "度兵大峴非無策，收泣新亭要有人。", "薄釀不澆胸壘塊，壯圖空負膽輪囷。", "危樓插斗山衘月，徙倚長歌一愴神。"]'),
('283a4770-3d00-44ad-8c92-7b1937240530','旬日公事頗簡喜而有賦','陸游','宋','宋诗','song-poetry','','[]','社近樓臺晝已長，豐年頗減簿書忙。',64,'全唐诗/poet.song.129000.json','["社近樓臺晝已長，豐年頗減簿書忙。", "雨催樹緑吹簫陌，日射塵紅擊鞠場。", "農事漸興初浸種，吏衙早退獨焚香。", "晚来别有歡然處，檢教兒書又一箱。"]'),
('981abbb4-0c77-4cc8-b9c6-0c9aac281001','聞鼓角感懷','陸游','宋','宋诗','song-poetry','','[]','鼓坎坎，角嗚嗚，四鼓欲盡五鼓初。',144,'全唐诗/poet.song.129000.json','["鼓坎坎，角嗚嗚，四鼓欲盡五鼓初。", "老眼不寐如鰥魚，撫枕起坐涕泗濡。", "平生空讀萬卷書，白首不識承明廬。", "時多通材臣腐儒，妄懷孤忠策則疏。", "欲剖丹心奏公車，論罪萬死尚有餘。", "雷霆願復寛須臾，許臣指陳輿地圖。", "億萬遺民望来蘇，藝祖有命行天誅。", "皇明如日詎敢誣，拜手乞賜丈二殳。", "中原烟塵一掃除，龍舟泝汴還東都。"]'),
('f18a80e0-78c9-4fbd-8925-323f783ea637','社日小飲二首  其一','陸游','宋','宋诗','song-poetry','','[]','催花初過社公雨，對酒喜烹溪友魚。',32,'全唐诗/poet.song.129000.json','["催花初過社公雨，對酒喜烹溪友魚。", "儘道亂山窮絕處，年華未覺異吾廬。"]'),
('4ec99576-54af-431f-8ba2-87ba7329c379','社日小飲二首  其二','陸游','宋','宋诗','song-poetry','','[]','社雨霏霏濕杏花，農家分喜到州家。',32,'全唐诗/poet.song.129000.json','["社雨霏霏濕杏花，農家分喜到州家。", "蒼鵝戲處塘初滿，黄犢歸時日欲斜。"]'),
('b5d3e67d-6811-4c6f-ba42-8ee606651280','昔日','陸游','宋','宋诗','song-poetry','','[]','昔日從戎日，身由許國輕。',48,'全唐诗/poet.song.129000.json','["昔日從戎日，身由許國輕。", "陣如新月偃，箭作餓鴟鳴。", "堅壁臨關守，連營竝渭畊。", "至今悲義士，書帛報番情。"]'),
('fd1e2aec-8ce8-49a7-9b59-85fbd62eafaf','新晴','陸游','宋','宋诗','song-poetry','','[]','雨斷歸雲急，沙乾步屧輕。',48,'全唐诗/poet.song.129000.json','["雨斷歸雲急，沙乾步屧輕。", "風花嬌作態，野水細無聲。", "社酒家家醉，春蕪處處耕。", "今朝公事少，一笑賦新晴。"]'),
('e867fa63-c068-46ff-99f0-d571e578fe15','倚欄','陸游','宋','宋诗','song-poetry','','[]','閑岸紗巾小倚欄，吳中三月尚春寒。',64,'全唐诗/poet.song.129000.json','["閑岸紗巾小倚欄，吳中三月尚春寒。", "蜂脾蜜滿花初過，燕觜泥新雨未乾。", "老厭簿書思屏迹，病逢節物強追歡。", "一樽又動流年感，城上斜陽畫角殘。"]'),
('b9c3a56b-9b90-438e-9b8a-13fd121a059f','寄徑山印禪師','陸游','宋','宋诗','song-poetry','','[]','市朝聲利戰方酣，眼看紛紛每不堪。',64,'全唐诗/poet.song.129000.json','["市朝聲利戰方酣，眼看紛紛每不堪。", "但有客誇車九九，了無人問衆三三。", "會當身返東西蜀，要與公分上下庵。", "春枕悠然夢何許，兩枝笻杖喚魚潭。"]'),
('ce2ad84f-0e57-41e0-a14f-eaf720a8b9d7','園中歸戲作','陸游','宋','宋诗','song-poetry','','[]','醉裏来尋澗上花，已飄殘雪散餘霞。',64,'全唐诗/poet.song.129000.json','["醉裏来尋澗上花，已飄殘雪散餘霞。", "麯生也解欺人老，風伯無端妬物華。", "不恨童心伴蜂蝶，但愁病眼厭風沙。", "歸来隱几東窗下，一卷黄庭送日斜。"]'),
('31243fc4-4a34-4ff5-96ec-81c19e42ce35','春曉東郊送客','陸游','宋','宋诗','song-poetry','','[]','雨餘氣清潤，迨我送客時。',72,'全唐诗/poet.song.129000.json','["雨餘氣清潤，迨我送客時。", "翻翻車蓋風，五里城東陂。", "初旭斂花房，晨露流桐枝。", "南山卷濕翠，更覺光景奇。", "澄潭集魚艇，村路亞酒旗。", "欲歸且復留，造物成吾詩。"]'),
('dba4855a-f189-41f7-8fb9-12f196df8afe','暮春嘆','陸游','宋','宋诗','song-poetry','','[]','春深桃李爭時節，千團紅雲萬堆雪。',64,'全唐诗/poet.song.129000.json','["春深桃李爭時節，千團紅雲萬堆雪。", "東風一夜吹欲空，曲徑平池爛如纈。", "城門獵獵雙青旗，羲和促轡西南馳。", "中原未有澄清日，志士虛捐少壯時。"]'),
('a31477b3-936b-4078-a6fe-2681e725e7c3','曉雨二首  其一','陸游','宋','宋诗','song-poetry','','[]','平明小雨壓香塵，遶舍扶疏綠漸勻。',32,'全唐诗/poet.song.129000.json','["平明小雨壓香塵，遶舍扶疏綠漸勻。", "睡過花時慵著句，老来春事不關身。"]'),
('8795e172-9b7d-4a97-93fd-611692a2f118','曉雨二首  其二','陸游','宋','宋诗','song-poetry','','[]','東風吹雨送殘春，冉冉年光次第新。',32,'全唐诗/poet.song.129000.json','["東風吹雨送殘春，冉冉年光次第新。", "君看枝頭如許綠，爭教桃李不成塵。"]'),
('27c71a2a-46be-4751-b663-7042be80b5ef','登千峰榭','陸游','宋','宋诗','song-poetry','','[]','飛觀危欄縹緲中，聊將醉眼送歸鴻。',64,'全唐诗/poet.song.129000.json','["飛觀危欄縹緲中，聊將醉眼送歸鴻。", "一生未售屠龍技，萬里猶思汗馬功。", "王衍諸人寧足責，姜維豎子自應窮。", "他年吊古憑高處，想見清伊照碧嵩。"]'),
('1138b485-eada-448f-842a-8978966b04bc','晚春園中作','陸游','宋','宋诗','song-poetry','','[]','少逢春歸未解悲，千篇曾賦傷春詩。',96,'全唐诗/poet.song.129000.json','["少逢春歸未解悲，千篇曾賦傷春詩。", "可堪霜點鬢鬚後，更值綠暗園林時。", "楊花輕墮簷外影，杏子重壓闌邊枝。", "毬塲立馬漏聲靜，綺窗語燕簷陰移。", "向来春事渺何許，長空鳥跡何由追。", "鞦韆未折已寥寞，日暮東風吹綵旗。"]'),
('94f93faa-be82-4187-9162-f0930927f45b','北窗','陸游','宋','宋诗','song-poetry','','[]','小雨霏霏旋作晴，北窗清潤緑陰成。',32,'全唐诗/poet.song.129000.json','["小雨霏霏旋作晴，北窗清潤緑陰成。", "却緣政拙文書少，臥聽簾櫳燕子聲。"]'),
('181734e2-acda-4115-8cac-e9cfc00b51cf','浮生','陸游','宋','宋诗','song-poetry','','[]','浮生過六十，百念已頽然。',48,'全唐诗/poet.song.129000.json','["浮生過六十，百念已頽然。", "獨有躭書癖，猶同總角年。", "横陳糲飯側，朗誦短檠前。", "不用嘲癡絕，兒曹尚可傳。"]'),
('53e0478d-947d-490a-8381-ab35e722fd54','小壘','陸游','宋','宋诗','song-poetry','','[]','小壘荒寒外，高齋寂寞中。',48,'全唐诗/poet.song.129000.json','["小壘荒寒外，高齋寂寞中。", "貧妨挂冠快，病減讀書功。", "橋斷春江白，雲穿夕照紅。", "悠然扶杖處，歲月嘆匆匆。"]'),
('3177ae96-a9cf-4015-bc4e-faf232769f97','大閱後一日作假','陸游','宋','宋诗','song-poetry','','[]','小院鈎簾掃落花，公餘蕭散似山家。',64,'全唐诗/poet.song.129000.json','["小院鈎簾掃落花，公餘蕭散似山家。", "下巖紫壁臨章草，正焙蒼龍試貢茶。", "塞上遠遊心尚壯，車中深閉髮先華。", "老来日月真堪惜，愁聽高城咽暮笳。"]'),
('f852e468-95e6-4195-8c31-14da723071aa','自嘲','陸游','宋','宋诗','song-poetry','','[]','貪禄忘歸秪自羞，一窗且復送悠悠。',64,'全唐诗/poet.song.129000.json','["貪禄忘歸秪自羞，一窗且復送悠悠。", "鏡明不爲人藏老，酒薄難供客散愁。", "正得虚名真畫餅，元非大噐愧函牛。", "年来事業君知否，高束詩書學問囚。"]'),
('f088d441-c7d6-4e72-a029-d1a7d6ad5086','曉出東城','陸游','宋','宋诗','song-poetry','','[]','聽徹清笳聽曉鐘，據鞍漏鼓尚鼕鼕。',64,'全唐诗/poet.song.129000.json','["聽徹清笳聽曉鐘，據鞍漏鼓尚鼕鼕。", "西樓落日徑三尺，北嶺亂雲生半峰。", "蒼磴幽尋過古寺，緑疇小駐勞春農。", "烟村已遠猶回首，恐有鵷雛與伏龍。"]'),
('dd406842-e236-4ab6-9fa4-1618da6714de','初夏遇休日園中閑賦','陸游','宋','宋诗','song-poetry','','[]','青山圍女牆，細草滿毬場。',96,'全唐诗/poet.song.129000.json','["青山圍女牆，細草滿毬場。", "虚簷揺水影，曲檻吹蘋香。", "房櫳寂無人，雙燕說曉涼。", "賜休無公事，蕭散寄一床。", "久苦吏役拘，更知閑味長。", "桑空繭綴簇，陂滿稻吐秧。", "良時動人懷，東望一慨慷。", "寧當戀微祿，如鼠死太倉。"]'),
('183b4f6d-f9d1-4025-9bdf-154d7158bac6','小雨出西門五里至東嶽廟','陸游','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','埋沒文書每自憐，偷閑出郭一欣然。',64,'全唐诗/poet.song.129000.json','["埋沒文書每自憐，偷閑出郭一欣然。", "稻陂雨細豐年候，槐陌風清嫩暑天。", "心似春鴻寧久住，身如秋扇合長捐。", "平生士雅今亡恙，老病何由共著鞭。"]'),
('0d9fa6a3-69b3-4fb6-aece-d41749e4bcf5','初夏燕堂睡起','陸游','宋','宋诗','song-poetry','','[]','歌鳯平生類楚狂，山城遲暮得深藏。',64,'全唐诗/poet.song.129000.json','["歌鳯平生類楚狂，山城遲暮得深藏。", "洗春雨過清陰合，掠水風生綠藻涼。", "晨几硯凹涵墨色，午窗杯面聚茶香。", "功名到手渾閑事，此興他年未易忘。"]'),
('df9f5a44-a53b-4e58-a625-0699cf11d347','晡後領客僅見燭而罷戲作短歌','陸游','宋','宋诗','song-poetry','','[]','忍睡出坐衙，扶病起觴客。',72,'全唐诗/poet.song.129000.json','["忍睡出坐衙，扶病起觴客。", "本来世味薄，況復酒户迮。", "譫諄時強語，嵬昻已頹幘。", "燒燭不盈寸，歸臥弄書冊。", "我来未穫稻，客裏今食麥。", "悵望稽山雲，飛去無六翮。"]'),
('d9f5e803-ea39-48cb-b51b-3b18010d3191','讀宛陵先生詩','陸游','宋','宋诗','song-poetry','','[]','歐尹追還六籍醇，先生詩律擅雄渾。',64,'全唐诗/poet.song.129000.json','["歐尹追還六籍醇，先生詩律擅雄渾。", "導河積石源流正，維嶽崧高氣象尊。", "玉磬漻漻非俗好，霜松鬱鬱有春溫。", "向来不導無譏評，敢保諸人未及門。"]'),
('2c78d109-ea5f-443a-a79a-6aa045e9268d','書嘆','陸游','宋','宋诗','song-poetry','','[]','人生如春蠶，作繭自纏褁。',72,'全唐诗/poet.song.129000.json','["人生如春蠶，作繭自纏褁。", "一朝眉羽成，鑽破亦在我。", "少年不自珍，妄念然烈火。", "眼亂舞腰輕，心醉笑齒瑳。", "餘齡幸早悟，世味無一可。", "但憶喚山僧，煎茶陳餅果。"]'),
('25c8b0ac-9b94-4698-b98d-c821f3e02924','曉出南山','陸游','宋','宋诗','song-poetry','','[]','久向人間觸駭機，斂收孤迹早宜歸。',64,'全唐诗/poet.song.129000.json','["久向人間觸駭機，斂收孤迹早宜歸。", "亡羊未恨補牢晚，搏虎深知攘臂非。", "明月長庚天欲曉，新桐清露暑猶微。", "扁舟蓑笠平生事，莫羨黄金带十圍。"]'),
('cf7fc3af-3833-4c23-bf19-48c76e5c1da5','聞韓无咎下世','陸游','宋','宋诗','song-poetry','','[]','書劍飄然去國時，南蘭陵郡日題詩。',64,'全唐诗/poet.song.129000.json','["書劍飄然去國時，南蘭陵郡日題詩。", "吳波漲綠迎桃葉，穰燭堆紅按柘枝。", "故友去爲山下土，衰翁何恨鬢邊絲。", "憑高老泪無揮處，神武衣冠挂已遲。"]'),
('ddb89aba-f7cf-47df-8d68-2400fa0e72a4','官居書事二首  其一','陸游','宋','宋诗','song-poetry','','[]','早涉人間足畏塗，一麾投老向江湖。',64,'全唐诗/poet.song.129000.json','["早涉人間足畏塗，一麾投老向江湖。", "年光已上星星鬢，日力猶供急急符。", "本自陽狂無藉在，更堪羸病不枝梧。", "籌邊意氣嗟誰許，泪盡神州赤縣圖。"]'),
('24b4b21f-e73c-49e5-8950-6ecedbdc57a0','官居書事二首  其二','陸游','宋','宋诗','song-poetry','','[]','走遍人間老更窮，強尋一笑與誰同。',64,'全唐诗/poet.song.129000.json','["走遍人間老更窮，強尋一笑與誰同。", "簿書衮衮呻吟裡，歌舞紛紛困睡中。", "手版倒持悲末路，寒江獨釣愧高風。", "知心賴有譚夫子，時遣書来問放翁。"]'),
('acc6aeab-e44b-4531-8902-d20b445419d4','夏日北榭賦詩奕棋欣然有作','陸游','宋','宋诗','song-poetry','','[]','異事嚴州省見稀，幅巾闌角立多時。',64,'全唐诗/poet.song.129000.json','["異事嚴州省見稀，幅巾闌角立多時。", "青林白鳥自成畫，急雨好風當有詩。", "酷信醫方逢酒怯，強驅吏牘坐衙遲。", "悠然笑向山僧說，又得浮生一局棋。"]'),
('dd36f92e-c681-4750-b366-06b517126086','謁告歸臥晚登子城','陸游','宋','宋诗','song-poetry','','[]','此身真是抱官囚，厭見長空赤日流。',64,'全唐诗/poet.song.129000.json','["此身真是抱官囚，厭見長空赤日流。", "齋壁曉山千嶂雪，扇紈新雁一汀秋。", "繫船空作清湘夢，御氣難尋太華遊。", "菱角藕絲還恨少，強攜玉瀣醉高樓。"]'),
('6a5d85a1-0c03-4f57-a007-a7b2fed77998','迓使客出郊夜歸過市樓','陸游','宋','宋诗','song-poetry','','[]','山川慘澹作秋霖，雲物徘徊結夕陰。',64,'全唐诗/poet.song.129000.json','["山川慘澹作秋霖，雲物徘徊結夕陰。", "手版向人慚老大，肩輿出郭當登臨。", "二年雪瀨饒羈思，萬里冰河歇壯心。", "却羨喧呼樓上客，隔簾紅燭醉更深。"]'),
('0d7e2815-856d-417e-9a85-51b7e11ee4fc','秋夜登千峰榭待曉','陸游','宋','宋诗','song-poetry','','[]','萬里秋風夜艾時，剡川孤客不勝悲。',64,'全唐诗/poet.song.129000.json','["萬里秋風夜艾時，剡川孤客不勝悲。", "讀書眼暗定誰許，憂國涕零空自知。", "欲墜高梧先策策，漸低北斗正離離。", "倚闌不覺雞號曉，剪燭題詩寄所思。"]'),
('b033134b-c5cf-4d0d-bbe3-777b7d239731','九月初郊行','陸游','宋','宋诗','song-poetry','','[]','九月吳中尚裌衣，江郊策馬踏斜暉。',64,'全唐诗/poet.song.129000.json','["九月吳中尚裌衣，江郊策馬踏斜暉。", "蕎花漫漫連山路，豆莢離離映版扉。", "蒼兔避鷹投磵去，黄鵪脫網傍人飛。", "農家光景關心事，不爲無才也合歸。"]'),
('b030ec5e-258c-460d-9e8e-05c5c8d25cf7','衰病','陸游','宋','宋诗','song-poetry','','[]','衰病龍鍾己要扶，誰憐猶作折腰趨。',64,'全唐诗/poet.song.129000.json','["衰病龍鍾己要扶，誰憐猶作折腰趨。", "世無魯國真男子，心憶高陽舊酒徒。", "萬里秋風吹鬢髮，百年世事嘆頭顱。", "桐江久客無奇句，孤負君王乞左符。"]'),
('d1e76671-b46f-40ea-80ae-0db5a69a868b','書意','陸游','宋','宋诗','song-poetry','','[]','一鳴輒斥不鳴烹，禍福元知未易評。',64,'全唐诗/poet.song.129000.json','["一鳴輒斥不鳴烹，禍福元知未易評。", "湖海凄涼身跌宕，杯觴豪舉筆縱横。", "敢希二頃成高臥，但願諸公致太平。", "波暖龍舟泝清汴，道邊扶杖眼猶明。"]'),
('6847e1c8-af34-4023-becc-9bac77ec3478','秋懷','陸游','宋','宋诗','song-poetry','','[]','策策桐葉風，濛濛菊花雨。',96,'全唐诗/poet.song.129000.json','["策策桐葉風，濛濛菊花雨。", "空堂一燈青，幽壁百蟲語。", "嗟余豈願仕，老病歸無所。", "屈指計歲年，強半墮羈旅。", "荷戈北戍秦，挂席西適楚。", "名慚垂竹帛，文不諧律呂。", "所餘惟一死，忍復類兒女。", "金丹或可成，青霄渺輕舉。"]'),
('a6c7e048-e31e-4163-bfaf-377b1dbb0a21','過村店有感','陸游','宋','宋诗','song-poetry','','[]','細篾絡丹柿，枯籬懸碧花。',48,'全唐诗/poet.song.129000.json','["細篾絡丹柿，枯籬懸碧花。", "炊烟生旅竈，野水漱寒沙。", "棲鳥爭投樹，歸牛自識家。", "恍然遊蜀路，搔首憶天涯。"]'),
('5f0c38f7-bfdf-4efa-96a2-108145f72454','嚴州大閱','陸游','宋','宋诗','song-poetry','','[]','鐵騎森森帕首紅，角聲旗影夕陽中。',64,'全唐诗/poet.song.129000.json','["鐵騎森森帕首紅，角聲旗影夕陽中。", "雖慚江左繁雄郡，且看人間矍鑠翁。", "清渭十年真昨夢，玉關萬里又秋風。", "憑鞍撩動功名意，未恨猿驚蕙帳空。"]'),
('fa019ab3-72c6-4c62-bc6e-af36f3c2b008','後園閑步','陸游','宋','宋诗','song-poetry','','[]','木葉勾萌喜小春，鬢毛蕭颯愧陳人。',64,'全唐诗/poet.song.129000.json','["木葉勾萌喜小春，鬢毛蕭颯愧陳人。", "今朝忽破簿書夢，此地暫還風月身。", "閑岸綸巾照清淺，却扶藤杖上嶙峋。", "人生要是便疏豁，金馬銀臺莫問津。"]'),
('33c0dd94-20e2-40d2-b812-76257a525183','照潺湲閣下池水','陸游','宋','宋诗','song-poetry','','[]','平生不鑷白，霜雪滿鬢眉。',96,'全唐诗/poet.song.129000.json','["平生不鑷白，霜雪滿鬢眉。", "照水默自笑，已迫溝壑期。", "慨然念歸休，不計妻子饑。", "渠饑亦有命，我節詎可移。", "自我来桐江，實無負惸嫠。", "讒波如崩山，孤迹則己危。", "陸子定何人，正恐君未知。", "午枕夢剡曲，秋風吹釣絲。"]'),
('ed1d91fc-dec6-4ded-8d92-2ed4d35bd93f','秋郊有懷四首  其一','陸游','宋','宋诗','song-poetry','','[]','漫漫蕎麥花，如雪覆平野。',96,'全唐诗/poet.song.129000.json','["漫漫蕎麥花，如雪覆平野。", "離離豆子莢，數枝忽堪把。", "頗憶故鄉時，屏迹謝車馬。", "水宿依蟹舍，泥行沒牛骻。", "作勞歸薄暮，濁酒傾老瓦。", "縷飛綠鯽膾，花簇頳鯉鮓。", "棄官雖未決，世念亦已且。", "浩歌續楚狂，幽懷欣獨寫。"]'),
('8d15bc12-a037-4785-a5b1-44999dfe9861','秋郊有懷四首  其二','陸游','宋','宋诗','song-poetry','','[]','檐頭買雙兔，市店取斗酒。',96,'全唐诗/poet.song.129000.json','["檐頭買雙兔，市店取斗酒。", "還家掃北窗，歡言酌親友。", "家貧氣未餒，禮薄情更厚。", "高吟金石裂，健筆龍蛇走。", "酒闌起出門，孤月挂衰柳。", "大笑各散歸，吾輩可不朽。", "官身縛簡書，此樂寧復有。", "悵望秦稽雲，憑高一搔首。"]'),
('6f50646a-656c-47c7-b8da-8599ee215eff','秋郊有懷四首  其三','陸游','宋','宋诗','song-poetry','','[]','楚人固多孱，妄謂秋可悲。',96,'全唐诗/poet.song.129000.json','["楚人固多孱，妄謂秋可悲。", "寧知河嶽間，氣俗樂此時。", "壯士鳴雕弓，健馬嚼枯萁。", "日馳三百里，榆關赴戰期。", "陣雲壓龍庭，殺氣揺參旗。", "熾火燎狐兔，倒瀉黄金巵。", "勒銘燕然石，千載鎮邊垂。", "安能空山裏，凍研哦清詩。"]'),
('9dc05941-5ebd-4d45-96ad-1151a9b899a8','秋郊有懷四首  其四','陸游','宋','宋诗','song-poetry','','[]','秋山瘦益奇，秋水淺可涉。',96,'全唐诗/poet.song.129000.json','["秋山瘦益奇，秋水淺可涉。", "出城西風勁，拂帽吹脫葉。", "新霜拆栗罅，宿雨飽豆莢。", "枯柳無鳴蜩，寒花有穿蝶。", "郊行得幽曠，頗覺耳目愜。", "斷雲北山来，欣然與之接。", "挂冠易事爾，看鏡嘆勛業。", "永懷桑乾河，夜渡擁馬鬛。"]'),
('1a9a71c8-f5ac-42a7-97da-4d0546115723','夙興','陸游','宋','宋诗','song-poetry','','[]','喔喔老雞催落月，丁丁殘漏伴斜河。',32,'全唐诗/poet.song.129000.json','["喔喔老雞催落月，丁丁殘漏伴斜河。", "一杯淡粥寒燈下，還與山僧不校多。"]'),
('8e774117-2d3c-41f9-8f1d-259680395ce0','聽事望馬目山','陸游','宋','宋诗','song-poetry','','[]','官身早暮不容閑，塵土堆胸愧滿顔。',32,'全唐诗/poet.song.129000.json','["官身早暮不容閑，塵土堆胸愧滿顔。", "也有向人誇說處，坐衙常對水南山。"]'),
('d00bed3f-45eb-40e3-b6d2-9793a658238f','秋興二首  其一','陸游','宋','宋诗','song-poetry','','[]','滿簪白髮不勝繁，竊祿偷安愧主恩。',64,'全唐诗/poet.song.129000.json','["滿簪白髮不勝繁，竊祿偷安愧主恩。", "東館烟波秋漸瘦，北山霧雨晝多昏。", "功名蹭蹬身長棄，籌策瀾翻舌幸存。", "堪笑此生虚過盡，一秋閉閤聽啼猿。"]'),
('783da7b6-bb3d-49e9-8b61-8d6857425c76','秋興二首  其二','陸游','宋','宋诗','song-poetry','','[]','孤城寂寞近江干，處處疏碪送早寒。',64,'全唐诗/poet.song.129000.json','["孤城寂寞近江干，處處疏碪送早寒。", "水落纔餘半篙綠，霜高初染一林丹。", "民租屢減追胥少，吏責全輕法令寛。", "偶有一樽聊獨醉，強挼黄菊助清歡。"]'),
('645bd2a5-66cb-4d5a-acde-32cc84be9b25','久無暇近書卷慨然有作','陸游','宋','宋诗','song-poetry','','[]','少年喜讀書，事業期不朽。',120,'全唐诗/poet.song.129000.json','["少年喜讀書，事業期不朽。", "致君頗自許，書卷常在手。", "白頭乞鍾釜，坐使此心負。", "朝衙有達午，夕坐或過酉。", "文符苦酬對，迎餞厭奔走。", "直憂先狗馬，豈但凋蒲柳。", "永懷簡編香，更覺冠冕醜。", "饑餐一簞飯，悶酌一巵酒。", "吟哦從所好，貧賤亦何有。", "余悔已莫追，寄謝故山友。"]'),
('50d2d3fb-d803-438b-9887-7e3e6ced8322','嚴州多菊然率過重陽方開或舉東坡先生菊花開時即重陽之語余謂此猶是未忘重陽者恐此花不肯也戲作一絕','陸游','宋','宋诗','song-poetry','','[]','無人喚醒賦歸翁，滿把清香誰與同。',32,'全唐诗/poet.song.129000.json','["無人喚醒賦歸翁，滿把清香誰與同。", "但辦對花頻舉酒，莫横重九在胸中。"]'),
('b9b6801a-c117-4df9-a0f8-1bad7929b63a','地僻','陸游','宋','宋诗','song-poetry','','[]','地僻天教養散材，流年况著鬢毛催。',64,'全唐诗/poet.song.129000.json','["地僻天教養散材，流年况著鬢毛催。", "青山自繞孤城去，畫角常隨晚照来。", "几淨雙鈎摹古帖，甕香小啜試新醅。", "乘槎不是英纏遠，無奈先生興盡回。"]'),
('7fc1c5a2-c0f8-49d1-bac6-bcfa58c030ac','吏責','陸游','宋','宋诗','song-poetry','','[]','吏責何時得暫停，年来減盡鬢邊青。',64,'全唐诗/poet.song.129000.json','["吏責何時得暫停，年来減盡鬢邊青。", "高談正樂催迎客，美睡方酣報掣鈴。", "安得雲山長在眼，便從樵牧與忘形。", "詩成不用頻怊悵，自古籠禽例翦翎。"]'),
('57c3f36f-71b0-4272-af52-f0051170b2b1','張時可直閣書報巳得請奉祠雲臺作長句賀之','陸游','宋','宋诗','song-poetry','','[]','燈前一笑拆書開，喜見冰衘洗俗埃。',64,'全唐诗/poet.song.129000.json','["燈前一笑拆書開，喜見冰衘洗俗埃。", "丞相苦留猶不住，諸公欲挽固難回。", "玩鷗有約間何濶，斂版無聊歸去来。", "千載伏波應太息，輸君談笑上雲臺。"]'),
('7073a7b7-33b7-438f-9621-ff8552bbf0ee','送鈐轄館使王公','黄垍','宋','宋诗','song-poetry','','[]','四年軍法表巴邛，歸騎俄乘紫漢風。',64,'全唐诗/poet.song.13000.json','["四年軍法表巴邛，歸騎俄乘紫漢風。", "家緒舊傳三棨貴，將材元藴萬人雄。", "錦城離思雲容斂，山國行章旆影紅。", "到日定知新渥重，主寮今是黑頭公。"]'),
('729f6b20-8433-4ea2-b84c-b0613be24805','暮春游火星巖同尹瞻聯句','柳拱辰','宋','宋诗','song-poetry','','[]','千里熙醇政，靈岩喜訪尋。',120,'全唐诗/poet.song.13000.json','["千里熙醇政，靈岩喜訪尋。", "登臨雲擁座，穿徑筍成林。", "樂逐天風遠，塵隨宿霧沈。", "綺羅紅作隊，冠蓋綠交陰。", "下顧關河小，寒知洞壑深。", "松枯存舊節，花老見初心。", "旌棨嵐光潤，罇罍野氣侵。", "朋游敦雅契，吏隠共知音。", "□愧翁歸拙，難攀子厚吟。", "城樓傳晚角，綺陌騎駸駸。"]'),
('ae9944d8-8001-4ce0-b3ab-8cf4dacfcba0','答曾進士','周銓','宋','宋诗','song-poetry','','[]','死易程嬰豈不知，十年後死不爲非。',64,'全唐诗/poet.song.13000.json','["死易程嬰豈不知，十年後死不爲非。", "文辭未便改秦館，敲朴徒能抱御衣。", "無志何須悲廟黍，得仁便不食山薇。", "儒冠有愧一廝養，何忍葵心對落暉。"]'),
('36c4f6c3-ddc0-46b2-9421-52d2d1104838','大雲洞','周燮','宋','宋诗','song-poetry','','[]','西出州城五里餘，大雲仙洞最清虛。',32,'全唐诗/poet.song.13000.json','["西出州城五里餘，大雲仙洞最清虛。", "近來選得禪師住，是處精藍盡不如。"]'),
('7d273351-2b40-41f3-a312-dd9b26bbd55a','如歸亭','葉綱','宋','宋诗','song-poetry','','[]','拍天煙浪接滄溟，識盡歸舟是此亭。',64,'全唐诗/poet.song.13000.json','["拍天煙浪接滄溟，識盡歸舟是此亭。", "風遞秋香來橘社，水資春味驗茶經。", "捲簾江樹差差綠，入坐湖山隠隠青。", "魯望幽居在何處，白鷗無主滿閑汀。"]'),
('700660d9-3020-4e96-82d1-79a970726afc','辭顯禪師題壁','釋善暹','宋','宋诗','song-poetry','','[]','不是無心繼祖燈，道慚未厠嶺南能。',32,'全唐诗/poet.song.13000.json','["不是無心繼祖燈，道慚未厠嶺南能。", "三更月下離巖竇，眷眷無言戀碧層。"]'),
('90d27bed-036d-4f0c-92e9-f8c1981cfd66','送僧歸天甯萬年禪院','孫旦','宋','宋诗','song-poetry','','[]','詔到禪關日，願言高古今。',48,'全唐诗/poet.song.13000.json','["詔到禪關日，願言高古今。", "幾生傳佛法，方得契君心。", "結坐觀宗社，恩容返道林。", "立身名了也，何處更追尋。"]'),
('98375d6c-6e91-4cae-ab09-46a4cb0f15a8','憶故鄉  其一','淳于震先','宋','宋诗','song-poetry','','[]','何時歸到望仙鄉，故舊相迎興味長。',32,'全唐诗/poet.song.13000.json','["何時歸到望仙鄉，故舊相迎興味長。", "六月海風吹溽暑，瓜田白酒稔清香。"]'),
('565af13b-d834-4546-8595-4ea080110fa4','憶故鄉  其二','淳于震先','宋','宋诗','song-poetry','','[]','蔚陽山下祖塋居，巍嶺崇高畫不如。',32,'全唐诗/poet.song.13000.json','["蔚陽山下祖塋居，巍嶺崇高畫不如。", "離亂不堪回首顧，春秋誰爲掃墳廬。"]'),
('a1be6894-039a-497a-88ac-f5ae99f4a869','憶故鄉  其三','淳于震先','宋','宋诗','song-poetry','','[]','積年祖宅隠黄山，門外槐根出地盤。',32,'全唐诗/poet.song.13000.json','["積年祖宅隠黄山，門外槐根出地盤。", "幼子孤遺音信斷，常時思憶倍辛酸。"]'),
('30c6dbea-f990-485b-bf67-28a7a8007009','皇雅十首  其一','尹洙','宋','宋诗','song-poetry','','[]','天監下民，亂靡有定。',40,'全唐诗/poet.song.13000.json','["天監下民，亂靡有定。", "甚武且仁，祚厥真聖。", "仁實懷徠，武以執競。", "匪虔匪劉，拯我大命。"]'),
('ea2b5412-f88b-4d71-a106-6a6a814051a9','皇雅十首  其二','尹洙','宋','宋诗','song-poetry','','[]','自昔外禪，曰經曰營。',40,'全唐诗/poet.song.13000.json','["自昔外禪，曰經曰營。", "令以挾制，政以陰傾。", "帝初治兵，志勤于征。", "奄受神器，匪謀而成。"]'),
('4d596a23-0bf7-4d97-a040-513bd797b733','皇雅十首  其三','尹洙','宋','宋诗','song-poetry','','[]','淮潞弗虔，卒汙叛迹。',40,'全唐诗/poet.song.13000.json','["淮潞弗虔，卒汙叛迹。", "戎輅戒嚴，皇威有赫。", "彼寇詿民，吾勇其百。", "殄厥渠魁，貸其反側。"]'),
('3b35a188-ccb9-4152-ae48-df5891c310a4','皇雅十首  其四','尹洙','宋','宋诗','song-poetry','','[]','帝朝法宮，左右宗公。',40,'全唐诗/poet.song.13000.json','["帝朝法宮，左右宗公。", "忮夫悍士，以雍以容。", "爾居爾室，爾工爾農。", "既息既養，惟天子功。"]'),
('3906bd2d-c2c4-4e23-b97b-0b6e90ce60e3','皇雅十首  其五','尹洙','宋','宋诗','song-poetry','','[]','主用西師，岷梁弗賓。',40,'全唐诗/poet.song.13000.json','["主用西師，岷梁弗賓。", "匪曰負固，實交晉人。", "予訓予誓，合我將臣。", "正厥有罪，無庸傷民。"]'),
('ca1acbc9-0832-4e8f-b824-c4970965ae60','皇雅十首  其六','尹洙','宋','宋诗','song-poetry','','[]','矯矯虎士，載摧其壁。',40,'全唐诗/poet.song.13000.json','["矯矯虎士，載摧其壁。", "于嗟孟侯，亦果其策。", "迎師而降，靡抗鋒鏑。", "豈獨身謀，完是宗國。"]'),
('3efbbeaa-2ca1-4d2f-acd0-d4417cfe5276','皇雅十首  其七','尹洙','宋','宋诗','song-poetry','','[]','蜀都既平，將臣失律。',40,'全唐诗/poet.song.13000.json','["蜀都既平，將臣失律。", "此衆悍驕，彼民危慄。", "當塗叫呶，合萬爲一。", "匪懷則威，帝心是恤。"]'),
('89b6a5be-0032-454c-94c1-6e42cb0a14ef','皇雅十首  其八','尹洙','宋','宋诗','song-poetry','','[]','帝曰將臣，予嘉乃庸。',40,'全唐诗/poet.song.13000.json','["帝曰將臣，予嘉乃庸。", "廢命毒民，爾弗有終。", "邦典用疑，惟罪惟功。", "靡殛而削，協于厥中。"]'),
('7d63ae07-815f-4f5c-a136-4a6c7073c787','皇雅十首  其九','尹洙','宋','宋诗','song-poetry','','[]','帝曰孟侯，受封于楚。',40,'全唐诗/poet.song.13000.json','["帝曰孟侯，受封于楚。", "淑旂琱戈，備物異數。", "俾爾族姻，及乃文武。", "服在王庭，靡不有序。"]'),
('d09a698e-731e-463a-a853-d402314a3c8f','皇雅十首  其一○','尹洙','宋','宋诗','song-poetry','','[]','蜀民呼歌，天子威靈。',40,'全唐诗/poet.song.13000.json','["蜀民呼歌，天子威靈。", "保我者封，暴我者刑。", "匪功是私，匪弱是陵。", "天子惠民，疇敢不承。"]'),
('a9916014-0cc1-4a22-9af0-512d3b3938d0','皇雅十首  其一一','尹洙','宋','宋诗','song-poetry','','[]','耆武定功，時惟二方。',40,'全唐诗/poet.song.13000.json','["耆武定功，時惟二方。", "淮服其乂，海南遂荒。", "孰孱而盭，孰暴而猖。", "自底不譓，乃終滅亡。"]'),
('e713b1d0-24b4-4c6d-87c6-498ce99a127a','皇雅十首  其一二','尹洙','宋','宋诗','song-poetry','','[]','帝戒二俘，同即爾誅。',31,'全唐诗/poet.song.13000.json','["帝戒二俘，同即爾誅。", "予惟民無辜，休息是圖。", "時其輯矣，寧威獨夫。"]'),
('5e22ebdd-e129-45f6-b320-a7c5ef51871a','皇雅十首  其一三','尹洙','宋','宋诗','song-poetry','','[]','帝嗟汙邦，久罹于兵。',42,'全唐诗/poet.song.13000.json','["帝嗟汙邦，久罹于兵。", "或暴下以征，或敷虐以刑。", "予命中典，協于圖經。", "民服德音，室家以寧。"]'),
('05276a3e-1d66-44a2-9284-5bf7782c908b','皇雅十首  其一四','尹洙','宋','宋诗','song-poetry','','[]','帝懷永圖，治古是憲。',80,'全唐诗/poet.song.13000.json','["帝懷永圖，治古是憲。", "四方守臣，惟屏惟翰。", "在昔艱難，弗惠訓典。", "跨都連城，高牙以建。", "有土有民，肆乃征繕。", "以息以容，終焉叛渙。", "凡今帥臣，狃厥聞見。", "匪革亂原，曷清多難。"]'),
('667d2f02-1440-4b60-bef2-7d74879cc2d4','皇雅十首  其一五','尹洙','宋','宋诗','song-poetry','','[]','帝告庶邦，式是典彝。',81,'全唐诗/poet.song.13000.json','["帝告庶邦，式是典彝。", "元侯顯父，戚臣宗支。", "正乃封圻，予一人是毗。", "凡曰附城，罔爾俾之。", "畜兵厚賦，靡爾得私。", "毋凶而國，作福作威。", "天子有命，疇敢不祗。", "子孫承承，唯萬世規。"]'),
('fc32dbfd-29b1-4a50-b1eb-03cdaa96fa69','皇雅十首  其一六','尹洙','宋','宋诗','song-poetry','','[]','冀州之疆，粵惟大鹵。',110,'全唐诗/poet.song.13000.json','["冀州之疆，粵惟大鹵。", "俗忮而專，地扼而固。", "協比幽都，蕩摇邊圉。", "三垂既夷，兇威弗沮。", "帝御六師，百萬貔虎。", "剪其附庸，至于城下。", "鋒鏑始交，梯衝如舞。", "蠢爾孱王，請附降虜。", "我士奮揚，願究吾武。", "皇帝曰吁，念彼黎庶。", "匪鯨匪鯢，復爲王土。"]'),
('5905ec5a-7fef-48a7-96c3-00949f9b0544','皇雅十首  其一七','尹洙','宋','宋诗','song-poetry','','[]','晉郊既平，九區以寧。',70,'全唐诗/poet.song.13000.json','["晉郊既平，九區以寧。", "陳功太廟，告假威靈。", "在昔武王，于商觀兵。", "維我藝祖，亦勤于征。", "匪貸晉罪，俟厥貫盈。", "聖作聖繼，巍巍相承。", "皇矣二后，功莫與京。"]'),
('56438896-1f4b-4935-bef5-8a8aa7fefdca','皇雅十首  其一八','尹洙','宋','宋诗','song-poetry','','[]','帝籍于郊，典儀具陳。',70,'全唐诗/poet.song.13000.json','["帝籍于郊，典儀具陳。", "務農以訓，供祀以勤。", "祀在于誠，匪勤于人。", "訓農以實，匪訓以文。", "帝謹二物，乃躬乃親。", "公侯卿士，暨厥庶民。", "千甸有制，飭哉惟寅。"]'),
('9d9c9baf-be58-4233-953f-9a72ec5f2448','皇雅十首  其一九','尹洙','宋','宋诗','song-poetry','','[]','帝賚高年，式宴且喜。',70,'全唐诗/poet.song.13000.json','["帝賚高年，式宴且喜。", "種種黄髮，族立而議。", "我生艱難，暴亂以繼。", "耳狃金鼓，目狎戎器。", "皇其我圖，親講農事。", "有子有孫，力田孝悌。", "鼓舞至仁，薰焉如醉。"]'),
('a48233a0-44ee-489f-90d0-1da18c13522d','皇雅十首  其二○','尹洙','宋','宋诗','song-poetry','','[]','帝咨庶工，疇其輔予。',40,'全唐诗/poet.song.13000.json','["帝咨庶工，疇其輔予。", "俊乂以登，厥勞乃圖。", "匪忘舊勳，非賢勿俞。", "巍巍衮台，盛德以居。"]'),
('182e7a3a-46ce-4870-a82a-02dbcbb4a8b7','皇雅十首  其二一','尹洙','宋','宋诗','song-poetry','','[]','任賢伊何，昌言是庸。',40,'全唐诗/poet.song.13000.json','["任賢伊何，昌言是庸。", "勉告爾猷，罔恤迺躬。", "豈無狷辭，怫于予衷。", "予不爾疵，爾無面從。"]'),
('75e907c5-6521-4aed-bab1-7ab45c00817b','皇雅十首  其二二','尹洙','宋','宋诗','song-poetry','','[]','始時從官，戎容揚揚。',40,'全唐诗/poet.song.13000.json','["始時從官，戎容揚揚。", "今帝左右，儒冠煌煌。", "朝廷以尊，文物典章。", "得人之盛，奕世重光。"]'),
('cdb30875-501c-4336-8009-006ec21c081e','皇雅十首  其二三','尹洙','宋','宋诗','song-poetry','','[]','帝制萬邦，罔有弗賓。',40,'全唐诗/poet.song.13000.json','["帝制萬邦，罔有弗賓。", "蠻夷戎狄，羈而勿臣。", "威格三方，稽顙獻珍。", "單于革心，願交使人。"]'),
('642e23c0-acf4-4a83-936f-23866d5ac4f0','皇雅十首  其二四','尹洙','宋','宋诗','song-poetry','','[]','帝謀公卿，列侯庶校。',40,'全唐诗/poet.song.13000.json','["帝謀公卿，列侯庶校。", "咸曰彼心，暴戾陰狡。", "既擾我疆，復利吾寶。", "無若勵兵，襲其還道。"]'),
('546f6d10-ee24-460c-ad78-a0709f9828da','皇雅十首  其二五','尹洙','宋','宋诗','song-poetry','','[]','皇曰有衆，予實念茲。',50,'全唐诗/poet.song.13000.json','["皇曰有衆，予實念茲。", "戰無必勝，矧其歸師。", "借曰大獲，疇能盡之。", "益俾餘醜，毒吾朔陲。", "乃愈其盟，北州以綏。"]'),
('4eb304e6-d16e-4eff-a27c-39172c279561','皇雅十首  其二六','尹洙','宋','宋诗','song-poetry','','[]','在漢世宗，抗威北戎。',40,'全唐诗/poet.song.13000.json','["在漢世宗，抗威北戎。", "暴農算商，經用弗充。", "中土震騷，漢南始空。", "降及後世，猶稱厥功。"]'),
('0b642a10-5ac7-4598-bf44-494e111b1709','皇雅十首  其二七','尹洙','宋','宋诗','song-poetry','','[]','於穆聖考，德無與偕。',40,'全唐诗/poet.song.13000.json','["於穆聖考，德無與偕。", "匪勤于兵，北人遂來。", "逮是三紀，遠俗以懷。", "生民休息，嗚呼仁哉。"]'),
('07f9c2fd-921f-4649-aac9-9b83b1f368fe','皇雅十首  其二八','尹洙','宋','宋诗','song-poetry','','[]','皇底其治，欽哉惟刑。',40,'全唐诗/poet.song.13000.json','["皇底其治，欽哉惟刑。", "在疑而宥，罔察爲明。", "愛怒弗肆，孰爲重輕。", "毋一弗辜，惟典之平。"]'),
('6a1e0140-2edb-4e90-9332-3208215c1e81','皇雅十首  其二九','尹洙','宋','宋诗','song-poetry','','[]','前世理官，倚法以刻。',40,'全唐诗/poet.song.13000.json','["前世理官，倚法以刻。", "匪彼爲仇，蓋曰任職。", "今之蔽獄，務正其辟。", "鑒于前人，繄我仁德。"]'),
('50e25bbb-f074-4541-adc9-e513867c7a10','皇雅十首  其三○','尹洙','宋','宋诗','song-poetry','','[]','皇德在仁，寖而成風。',40,'全唐诗/poet.song.13000.json','["皇德在仁，寖而成風。", "公侯卿士，靡不率從。", "麛卵萌生，咸保厥終。", "不鄙不夭，樂哉融融。"]'),
('79fc8278-4dde-4a06-ab53-1cd3e61da477','皇雅十首  其三一','尹洙','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','噫！太平無象兮世烏得而知，維盛德可迹兮其封祀之儀。',78,'全唐诗/poet.song.13000.json','["噫！太平無象兮世烏得而知，維盛德可迹兮其封祀之儀。", "東岱宗兮西汾脽，禮上帝兮賓地祇。", "皇有征兮吾民以嬉，皇有祈兮吾民是私。", "天敷佑兮俾皇之釐，永世億寧兮無疆之基。"]'),
('64da9725-1626-49d4-93c1-29e519655fc5','贈三鄉浮圖智聰一首','尹洙','宋','宋诗','song-poetry','','[]','伊昔相逢日，于今二十年。',48,'全唐诗/poet.song.13000.json','["伊昔相逢日，于今二十年。", "師隨安樂住，我豈利名牽。", "自笑真徒爾，何如養浩然。", "西門女几路，未得賦歸田。"]'),
('01186a79-5bcf-497c-b756-373b7f48008f','和人過韓柱國廟一首','尹洙','宋','宋诗','song-poetry','','[]','隋氏一宇內，三將皆勇夫。',60,'全唐诗/poet.song.13000.json','["隋氏一宇內，三將皆勇夫。", "賀公活以累，楊素死有誅。", "賢哉韓柱國，身與功名俱。", "廟食垂後世，祀典誠有諸。", "荒忽臨終言，遂此惑庸愚。"]'),
('3f8af340-1aaa-4169-bd0b-3c595eed938f','過興平哭耿傅諫議喪呈經略韓密學','尹洙','宋','宋诗','song-poetry','','[]','去年使旆西征日，一見稱君膽氣豪。',64,'全唐诗/poet.song.13000.json','["去年使旆西征日，一見稱君膽氣豪。", "始信推心待國士，能令視死如鴻毛。", "從來投筆輕文吏，自此橫尸貴爾曹。", "槐里今朝逢輤旐，依然舊館一長號。"]'),
('2281eaed-32f8-459c-905e-26f0966204d6','舟次壽州寄濠州江鈞少卿','尹洙','宋','宋诗','song-poetry','','[]','雨漲灘頭沙已空，一帆西上快清風。',32,'全唐诗/poet.song.13000.json','["雨漲灘頭沙已空，一帆西上快清風。", "誰知去郡遲遲意，猶逐淮波日夜東。"]'),
('43a3f06b-07d5-4b69-b0a8-11e6ab05b538','和河東施待制二首  其一','尹洙','宋','宋诗','song-poetry','','[]','已成沈約難并恨，且奉陶公有限盃。',32,'全唐诗/poet.song.13000.json','["已成沈約難并恨，且奉陶公有限盃。", "感事傷春多少意，星星漸入鬢中來。"]'),
('698a2187-09f3-4293-98d4-b46b9a935af3','和河東施待制二首  其二','尹洙','宋','宋诗','song-poetry','','[]','千里觀風使節來，百城舒慘繫行臺。',32,'全唐诗/poet.song.13000.json','["千里觀風使節來，百城舒慘繫行臺。", "威嚴少霽猶知幸，誰信芳罇鎮日開。"]'),
('420dd40f-4525-4980-91d3-4a24bfade10d','隨州聞劉易入終南山','尹洙','宋','宋诗','song-poetry','','["\u7ec8\u5357\u5c71"]','神驥渴死追無蹤，離婁眩目迷虛空。',64,'全唐诗/poet.song.13000.json','["神驥渴死追無蹤，離婁眩目迷虛空。", "九衢懽游尚故處，一日忽在終南峰。", "附勢趨權徒擾擾，生歌死哭何匆匆。", "人間萬事既能了，莫教聲譽過關東。"]'),
('c2ec2c93-5ac3-4fb3-9cdf-fac314c7797c','淥波亭','向傳式','宋','宋诗','song-poetry','','[]','我愛東南郡，恩容守會稽。',144,'全唐诗/poet.song.13000.json','["我愛東南郡，恩容守會稽。", "府當秦望北，園枕卧龍西。", "水爲流觴引，亭因正俗題。", "松篁清有韵，桃李密成蹊。", "一沼開方鑑，雙橋亙采霓。", "曉波平漾漾，春草碧萋萋。", "城上興崇構，林端露半梯。", "登疑青漢近，坐與白雲齊。", "山色回頭是，湖光照眼迷。", "笙歌隨分有，樽斝逐歡携。", "月夜宜飛蓋，花時醉似泥。", "蓬萊風景異，此地好長棲。"]'),
('bec8cb25-7133-4a69-8e92-8c474c5c861f','寄成都蔣密學','向傳式','宋','宋诗','song-poetry','','[]','欽聞宥密綴榮班，西顧分憂輟鉅賢。',64,'全唐诗/poet.song.13000.json','["欽聞宥密綴榮班，西顧分憂輟鉅賢。", "乍領蜀都新印綬，應懷越國舊風烟。", "流觴雅趣人多羨，正俗佳名世永傳。", "聖主倚毗閒未得，重來遊賞是何年。"]'),
('8162ae73-c14e-416b-937e-63f880602ca7','句','釋允堪','宋','宋诗','song-poetry','','[]','始生巖谷畔，早有月中香。',12,'全唐诗/poet.song.13000.json','["始生巖谷畔，早有月中香。"]'),
('174ed77c-7008-40ac-bb35-a805e789d8c8','贈劉諷','蘇渙','宋','宋诗','song-poetry','','[]','林下人歸少，君歸不待年。',24,'全唐诗/poet.song.13000.json','["林下人歸少，君歸不待年。", "能令兩蜀士，歎甚二疏賢。"]'),
('01e1ab5d-51ed-4d14-bc45-aea6efb07f46','句','蘇渙','宋','宋诗','song-poetry','','[]','雲臺勝景壓蒼溪，東漢遺名冠蜀西。',16,'全唐诗/poet.song.13000.json','["雲臺勝景壓蒼溪，東漢遺名冠蜀西。"]'),
('932111de-0d09-4c14-8eae-b91f924978f4','長樂臺','曹穎叔','宋','宋诗','song-poetry','','[]','藍挼水谷與秋輝，疑作危稜磴翠微。',32,'全唐诗/poet.song.13000.json','["藍挼水谷與秋輝，疑作危稜磴翠微。", "向晚山僧苦留我，層層寒牖亂雲歸。"]'),
('89c4948f-d4df-45ba-82ca-c5da3b25e451','萊公泉','崔嶧','宋','宋诗','song-poetry','','[]','二相南行至道初，記名留詠在精廬。',32,'全唐诗/poet.song.13000.json','["二相南行至道初，記名留詠在精廬。", "甘泉不洗天崖恨，留與行人鑒覆車。"]'),
('d554dea1-2741-4a0f-a151-bbe8be7e5a35','自陳詩','劉三嘏','宋','宋诗','song-poetry','','[]','雖慙涔勺赴滄溟，仰訴丹衷不爲名。',64,'全唐诗/poet.song.13000.json','["雖慙涔勺赴滄溟，仰訴丹衷不爲名。", "寅分星辰將降禍，兌方疆宇即交兵。", "春秋大義惟觀釁，王者雄師但有征。", "救得燕民歸舊主，免于戎膚自稱兄。"]'),
('15acb72b-aadb-45a2-a543-1335e2ecaca4','題興龍寺老柏院','張在','宋','宋诗','song-poetry','','[]','南鄰北舍牡丹開，年少尋芳日幾回。',32,'全唐诗/poet.song.13000.json','["南鄰北舍牡丹開，年少尋芳日幾回。", "惟有君家老柏樹，春風來似不曾來。"]'),
('7d7dc440-4f75-42af-9222-698b4df48c94','紫微山','富臨','宋','宋诗','song-poetry','','[]','鑿石誅茅四十年，稜層寶構出諸天。',64,'全唐诗/poet.song.13000.json','["鑿石誅茅四十年，稜層寶構出諸天。", "更逢地勝驚遊客，不負身披壞衲田。", "別郡坐看雲散後，平湖下壓鳥飛前。", "還知老令忘歸否，爲惜難移近縣廛。"]'),
('d477d3b8-bff7-4bcc-a5d7-c581d196e9e2','春集東園詩','李淑','宋','宋诗','song-poetry','','[]','東城桃李春，結客玩珍蘤。',72,'全唐诗/poet.song.13000.json','["東城桃李春，結客玩珍蘤。", "試過辟疆園，兼屈中郎屣。", "筠苞煙蔽虧，柳带風眠起。", "岸幘藉芳艿，銜杯嗅新蕊。", "留連魚鳥適，放曠山林喜。", "意賞殊未闌，更作櫻厨擬。"]'),
('bf9e9ceb-3c5e-43c2-8ed9-1a35637daeee','題滑州廨','李淑','宋','宋诗','song-poetry','','[]','滑守如今是世官，阿戎出守自金鑾。',32,'全唐诗/poet.song.13000.json','["滑守如今是世官，阿戎出守自金鑾。", "郡人莫訝留題別，孫息期同住此看。"]'),
('22011286-dcea-49bf-bad0-44ac4ee0e5d3','題周恭帝陵','李淑','宋','宋诗','song-poetry','','[]','弄楯牽車挽鼓催，不知門外倒戈迴。',32,'全唐诗/poet.song.13000.json','["弄楯牽車挽鼓催，不知門外倒戈迴。", "荒墳斷隴纔三尺，猶認房陵半仗來。"]'),
('12ba30e3-f273-4e35-bb09-fbcf80bac252','峴山詩','李淑','宋','宋诗','song-poetry','','[]','峴山如闖襄廬南，鉅平躋賞留愛談。',160,'全唐诗/poet.song.13000.json','["峴山如闖襄廬南，鉅平躋賞留愛談。", "官邪俗淪祭不屋，君來懷古茵憑慚。", "孤峰嶔嶇漢之曲，雲梁月臯萬螺矗。", "輕裘四眺風物佳，賓客文章歡意促。", "酒酣嘅涕邀靈期，金碑揭然民哭遺。", "斧薪弗翦召棠樹，簫鼓相傳欒社祠。", "使君籍在華光省，秩廢諏新剡章請。", "篆楹舄采神宴娭，比故鑱堅詩播永。", "我嘗學史稱君伐，又感先賢祀無歇。", "德名信與蒼崖俱，曠貴紛紛煨壤滅。"]'),
('88f20f67-2173-4fad-8edd-727cd38f31e0','詩一首','李淑','宋','宋诗','song-poetry','','[]','多羅四十年，偶未識摩氈。',24,'全唐诗/poet.song.13000.json','["多羅四十年，偶未識摩氈。", "近有王宣政，時時與紙錢。"]'),
('f910e952-bb62-4522-889d-3829d97f3048','句  其一','李淑','宋','宋诗','song-poetry','','[]','纔及春羔鼎祚移。',8,'全唐诗/poet.song.13000.json','["纔及春羔鼎祚移。"]'),
('ac30df74-758d-4b7b-81da-90920d3f5a17','句  其二','李淑','宋','宋诗','song-poetry','','[]','王貌閑知鶴，黄吟苦似猿。',12,'全唐诗/poet.song.13000.json','["王貌閑知鶴，黄吟苦似猿。"]'),
('7dc09858-dbc0-4f9f-a770-5cd4014e06b1','和謝希深會聖宮','梅堯臣','宋','宋诗','song-poetry','','[]','三后威靈遠，層巒棟宇興。',144,'全唐诗/poet.song.13000.json','["三后威靈遠，層巒棟宇興。", "衣冠漢原廟，歌舞魏西陵。", "日月融光盛，山河王氣增。", "叢楹琢文石，連網絡朱繩。", "碧瓦寒鋪玉，重欄瑩鏤冰。", "粹儀神霧擁，法衮繡龍升。", "星斗羅容衛，軒墀侍股肱。", "宸蹤耀璇牓，瑞羽集觚稜。", "閟殿深珠箔，雕垣界綺縢。", "笙從緱嶺咽，雲傍帝鄉凝。", "龜組恭來詣，貂璫肅奉承。", "欲知歸厚意，孝德自烝烝。"]'),
('8c3072ca-ca1c-4ed1-88b8-1bb5bd0ed888','右丞李相公自洛移鎮河陽','梅堯臣','宋','宋诗','song-poetry','','[]','侯服齊三輔，天臺聳百僚。',96,'全唐诗/poet.song.13000.json','["侯服齊三輔，天臺聳百僚。", "新章刻銅虎，舊德冠金貂。", "已作歌襦化，方期執玉朝。", "雙鞬辭洛宅，千騎向河橋。", "鼓角春城暮，鶑花故苑遥。", "瓜亭猶接軫，棠茇自敷條。", "夾道都人擁，迎風駟牡驕。", "莫隨文學乘，空望旆旌飄。"]'),
('a24e7633-2f77-4b03-a326-c9609847605b','上巳日午橋石瀨中得雙鱖魚','梅堯臣','宋','宋诗','song-poetry','','[]','脩禊洛之濱，湍流得素鱗。',48,'全唐诗/poet.song.13000.json','["脩禊洛之濱，湍流得素鱗。", "多慙折腰吏，來作食魚人。", "水髮黏篙綠，溪毛映渚春。", "風沙暫時遠，紫線憶江蓴。"]'),
('e3208c1d-0ec6-49e2-be8a-861b3910665c','寒食前一日陪希深遠遊大字院','梅堯臣','宋','宋诗','song-poetry','','[]','一百五將近，千門煙火微。',48,'全唐诗/poet.song.13000.json','["一百五將近，千門煙火微。", "閑過少傅宅，喜見老萊衣。", "晚雨竹間霽，春禽花上飛。", "禪庭清溜滿，幽興自忘歸。"]'),
('332dafcc-8227-40a8-99c4-63bd9520be77','遊龍門自潛溪過寶應精舍','梅堯臣','宋','宋诗','song-poetry','','[]','遥愛夏景佳，行行清興屬。',72,'全唐诗/poet.song.13000.json','["遥愛夏景佳，行行清興屬。", "安知轉迴溪，始覺來平谷。", "古殿藏竹間，香菴遍巖曲。", "雲霞弄霽暉，草樹含新綠。", "時鳥自綿蠻，山花競紛縟。", "莫言歸路賒，明月還相續。"]'),
('487cf10e-b4b4-43f6-86b3-350fe16b9d0f','依韻和希深遊大字院','梅堯臣','宋','宋诗','song-poetry','','[]','夫君康樂裔，顧我子真派。',120,'全唐诗/poet.song.13000.json','["夫君康樂裔，顧我子真派。", "湛然懷清機，越爾尋虛界。", "暫來香園中，共憩寒松大。", "先生醉復吟，長老言不壞。", "信與賞心符，寧同俗士愛。", "杖屨恣遊遨，池塘仍感槩。", "焚香露蓮泣，聞磬霜鷗邁。", "青板今已空，濁醪誰許載。", "軟草當熊絪，低篁挂纓带。", "不覺月明歸，候門僮僕怪。"]'),
('ff09fab7-cd03-4e83-9820-c2d3912987f0','傷白雞','梅堯臣','宋','宋诗','song-poetry','','[]','我庭有素雞，翎羽白如脂。',240,'全唐诗/poet.song.13000.json','["我庭有素雞，翎羽白如脂。", "日所慮狂犬，未嘗憂孽貍。", "暝棲向簷隙，朝啄循階基。", "每先烏鳥鳴，不失風雨時。", "雖吾囷廩薄，尚汝稻粱遺。", "昨宵天氣黑，陰物恣所窺。", "潛來銜搏去，但覺聲音悲。", "開門俾馳救，已過牆東陲。", "呵叱不敢食，奪然留在茲。", "湧血被其頸，嗋呷氣甚危。", "皓臆變丹赤，霜翅兩離披。", "憫心欲之活，碎腦安能治。", "委瘞從爾命，孰忍薑桂爲。", "猶看零落毛，蕩漾隨風吹。", "念始託茲地，蒙幸信可知。", "充庖豈云患，度日無苦饑。", "如何遇兇獸，毒汝曾不疑。", "斯事義雖小，得以深理推。", "鄧生賜山鑄，未免終餒而。", "人道尚乃爾，愴焉聊俛眉。"]'),
('01e78a2a-b589-45b8-9694-909c40b56f9c','尹師魯治第伐樗','梅堯臣','宋','宋诗','song-poetry','','[]','伊人利營構，思欲新其居。',156,'全唐诗/poet.song.13000.json','["伊人利營構，思欲新其居。", "匠築經舊址，簷楹礙高樗。", "且云忍不伐，何以成吾廬。", "人言此樹古，百怪所憑依。", "獨秉一定議，自將羣俗違。", "乃俾執柯者，丁丁霜刃揮。", "殲殞條百尺，橫朴株數圍。", "從茲朝夕間，不聞鳥雀喧。", "既能考子室，而復高其門。", "周也昔騁辯，得以不材論。", "工今誠匪度，敬害安可存。", "舟檝且非藉，薪爨聊用燔。", "莫比溝中斷，區區望犧樽。"]'),
('c6ab6eed-b637-408a-ac54-76fac7e8bdc8','尹陽尉耿傳惠新栗','梅堯臣','宋','宋诗','song-poetry','','[]','金行氣已勁，霜實繁林梢。',72,'全唐诗/poet.song.13000.json','["金行氣已勁，霜實繁林梢。", "尺素走下隸，一奩來遠郊。", "中黄比玉質，外刺同芡苞。", "野人寒齋會，山爐夜火炮。", "梨慚小兒嗜，茗憶麤官拋。", "此焉真可貺，遽爾及衡茅。"]'),
('931c8774-be61-4235-9373-4e3cfa92a808','和楊子聰會董尉家','梅堯臣','宋','宋诗','song-poetry','','[]','董生方好雅，茲日爲掃扉。',144,'全唐诗/poet.song.13000.json','["董生方好雅，茲日爲掃扉。", "森爾延嘉賓，歡然去塵機。", "有客振雙袂，敢言陽春暉。", "聊停玉麈尾，爲歌金縷衣。", "古辭何稠疊，無乃惜芳菲。", "三閭不餔糟，二子自採薇。", "雖留千載清，未免當時饑。", "吾愛曹公詩，古來不敢非。", "人生若朝露，捨醉當何歸。", "四座驚此語，未厭翠觴飛。", "胡能後天地，何可恃輕肥。", "沉酣且長詠，白首空歔欷。"]'),
('0839e4ea-36c9-4772-9f31-231cb40e3d10','嶺雲','梅堯臣','宋','宋诗','song-poetry','','[]','片雨過青天，山雲歸絕嶺。',36,'全唐诗/poet.song.13000.json','["片雨過青天，山雲歸絕嶺。", "林際隠微虹，溪中落行影。", "還看隴首飛，復愛山間靜。"]'),
('0233b12e-b1ce-431f-9b12-fd0e8464395e','垂澗藤','梅堯臣','宋','宋诗','song-poetry','','[]','寒松偃澗濱，弱蔓垂纓綠。',36,'全唐诗/poet.song.13000.json','["寒松偃澗濱，弱蔓垂纓綠。", "波縈翠带長，水濺低花馥。", "終日採蘋人，攀條映巖曲。"]'),
('f6e898d3-6c26-4a9e-b509-a99e5860d1e4','林翠','梅堯臣','宋','宋诗','song-poetry','','[]','鬰鬰長條抽，林間翠堪翦。',24,'全唐诗/poet.song.13000.json','["鬰鬰長條抽，林間翠堪翦。", "背嶺山氣濃，幽人趣不淺。"]'),
('4967218a-a045-4bca-89b7-8321a5016806','舟中遇雪','梅堯臣','宋','宋诗','song-poetry','','[]','曉風鳴大澤，春雪下長河。',48,'全唐诗/poet.song.13000.json','["曉風鳴大澤，春雪下長河。", "沙草緣堤沒，楊花拂水多。", "驚鷗不知遠，候雁幾聞過。", "欲問耶溪轉，今朝奈興何。"]'),
('19d39687-acbf-4b84-9480-150fb330d9b0','田家  其一','梅堯臣','宋','宋诗','song-poetry','','[]','昨夜春雷作，荷鋤理南陂。',48,'全唐诗/poet.song.13000.json','["昨夜春雷作，荷鋤理南陂。", "杏花將及候，農事不可遲。", "蠶女亦自念，牧童仍我隨。", "田中逢老父，荷杖獨熙熙。"]'),
('e950be5b-d2c0-4e0a-910d-3ce571ffa7d8','田家  其二','梅堯臣','宋','宋诗','song-poetry','','[]','草木遶籬盛，田園向郭斜。',48,'全唐诗/poet.song.13000.json','["草木遶籬盛，田園向郭斜。", "去鋤南山豆，歸灌東園瓜。", "白水照茅屋，清風生稻花。", "前陂日已晚，聒聒競鳴蛙。"]'),
('ae990fd0-d0c6-40da-89e1-63846a87feda','田家  其三','梅堯臣','宋','宋诗','song-poetry','','[]','荒村人自樂，頗足平生心。',48,'全唐诗/poet.song.13000.json','["荒村人自樂，頗足平生心。", "朝飯露葵熟，夜舂雲谷深。", "採山持野斧，射鳥入煙林。", "誰見秋成事，愁蟬復怨碪。"]'),
('fafff46c-94f4-433e-b120-555a3be409c9','田家  其四','梅堯臣','宋','宋诗','song-poetry','','[]','今朝田事畢，野老立門前。',48,'全唐诗/poet.song.13000.json','["今朝田事畢，野老立門前。", "拊頸望飛鳥，負暄話餘年。", "自從備丁壯，及此常苦煎。", "卒歲豈堪念，鶉衣著更穿。"]'),
('4108b74f-b380-413d-b064-7e2dda02118f','塗中遇雪寄希深','梅堯臣','宋','宋诗','song-poetry','','[]','方爲郡邑吏，日與故人違。',48,'全唐诗/poet.song.13000.json','["方爲郡邑吏，日與故人違。", "極目千山碧，馳心一鳥飛。", "岸傍村杳杳，波上雪霏霏。", "欲寄洛陽信，泝流行客稀。"]'),
('3ff0bc69-aaa3-4fcb-bbe3-38db0c4cbe78','妾薄命','梅堯臣','宋','宋诗','song-poetry','','[]','昔是波底沙，今爲陌上塵。',84,'全唐诗/poet.song.13000.json','["昔是波底沙，今爲陌上塵。", "曾聞清泠混金屑，誰謂飄揚逐路人。", "悠悠萬物難自保，朝看穠華暮衰老。", "須知鉛黛不足論，何必芳心競春草。", "草有再三榮，顔無一定好。", "曩恩寧重持，徒能亂懷抱。"]'),
('7df473e2-096c-4dc5-9ff7-86dedaa10346','秋日同希深昆仲遊龍門香山晚泛伊川觴詠久之席上各賦古詩以極一時之娛','梅堯臣','宋','宋诗','song-poetry','','[]','落日川上好，徘徊弄孤舟。',168,'全唐诗/poet.song.13000.json','["落日川上好，徘徊弄孤舟。", "鳴桹進山口，清唱發渡頭。", "淺瀨不可泝，停橈信中流。", "山樽對蒼翠，溪鳥自沉浮。", "濯足破嵐影，采菱臨芳洲。", "千龕晚煙寂，雙壁紅樹秋。", "細細石澗泉，摇摇波際樓。", "澄潭若瀉鑑，萬象已盈眸。", "康樂足清尚，惠連仍此遊。", "摘景固無遺，揮筆曾未休。", "醉來同淵明，興盡殊子猷。", "歸傍漁梁靜，行看夜火幽。", "露華初滴滴，夜吹何颼颼。", "不犯嚴城漏，誰言憐近丘。"]'),
('9ffb1427-dffc-4e64-9b5a-54459554dfa9','依韻和希深雨後見過小池','梅堯臣','宋','宋诗','song-poetry','','[]','碧池新雨後，清興一何賒。',48,'全唐诗/poet.song.13000.json','["碧池新雨後，清興一何賒。", "有客過顔巷，無貧似阮家。", "白醪聊泛蟻，黄菊未開花。", "既至休辭醉，君其奈歲華。"]'),
('4ab12e4f-3d05-456e-b9e6-ecdcf8222f20','依韻和子聰夜雨','梅堯臣','宋','宋诗','song-poetry','','[]','窗燈光更迥，宿霧晦層簷。',48,'全唐诗/poet.song.13000.json','["窗燈光更迥，宿霧晦層簷。", "寒氣微生席，輕風欲度簾。", "濕螢依草沒，暗溜想池添。", "況值相如渴，無嫌魯酒甜。"]'),
('defe4d07-53ff-424e-99ab-23b3b75c79fa','和趙員外良佐趙韓王故宅','梅堯臣','宋','宋诗','song-poetry','','[]','開國勳庸大，重城邸第寬。',48,'全唐诗/poet.song.13000.json','["開國勳庸大，重城邸第寬。", "枯楊映樓角，蔓草被牆端。", "不見分香妾，空餘鬭鴨闌。", "誰來悲孔雀，金翠羽毛殘。"]'),
('07daba7f-4781-474f-8fe0-6ac3383e7313','春日遊龍門山寺','梅堯臣','宋','宋诗','song-poetry','','[]','還邀二三子，共到鑿龍遊。',48,'全唐诗/poet.song.13000.json','["還邀二三子，共到鑿龍遊。", "陰壑泉初動，春巖氣欲浮。", "竹藏深崦寺，人渡晚川舟。", "始覺山風急，歸鞍不自留。"]'),
('21ba98da-dcf8-48fb-9ff1-5fd2f6c0634d','依韻和希深遊府學','梅堯臣','宋','宋诗','song-poetry','','[]','東府尊儒日，中州進學初。',48,'全唐诗/poet.song.13000.json','["東府尊儒日，中州進學初。", "牲牢奠商後，典籍講秦餘。", "大法存無外，羣英樂自如。", "時慙遊聖末，來駕折轅車。"]'),
('0ed7793f-4c4b-41f3-83db-a2ff6f19f16b','傷桑','梅堯臣','宋','宋诗','song-poetry','','[]','柔條初變綠，春野忽飛霜。',48,'全唐诗/poet.song.13000.json','["柔條初變綠，春野忽飛霜。", "田婦搔蓬首，冰蠶絕繭腸。", "名翬依麥雊，戴勝繞枝翔。", "不見羅敷騎，金鈎自挂牆。"]'),
('ce86fadf-e41e-435a-8587-79ed216c2877','觀理稼','梅堯臣','宋','宋诗','song-poetry','','[]','稂莠日已長，怱怱芟薙初。',48,'全唐诗/poet.song.13000.json','["稂莠日已長，怱怱芟薙初。", "來時露霑屩，歸去月侵鋤。", "一腹餒猶甚，百骸勤有餘。", "吾無力耕苦，謬讀古人書。"]'),
('66579eda-8f2a-4bd4-956d-a420615c94b0','新繭','梅堯臣','宋','宋诗','song-poetry','','[]','露柘林初靜，煙梯不復收。',48,'全唐诗/poet.song.13000.json','["露柘林初靜，煙梯不復收。", "春蠶吐絲足，工女忌寒休。", "翠薄時方獻，清泉緒未抽。", "閨中能自巧，繡作玉釵頭。"]'),
('c14288d2-7384-44fc-a586-58f79574f08c','依韻和希深遊樂園懷主人登封令','梅堯臣','宋','宋诗','song-poetry','','[]','竹映紅蕖水榭開，門閑乳雀下青苔。',32,'全唐诗/poet.song.13000.json','["竹映紅蕖水榭開，門閑乳雀下青苔。", "伊人何戀五斗粟，不作淵明歸去來。"]'),
('4f581dc9-142c-4eae-aadd-fd045d51938e','錦竹','梅堯臣','宋','宋诗','song-poetry','','[]','雖作湘竹紋，還非楚筠質。',36,'全唐诗/poet.song.13000.json','["雖作湘竹紋，還非楚筠質。", "化龍徒有期，待鳳曾無實。", "本與凡草俱，偶親君子室。"]'),
('178f0a04-1fa3-471d-89bc-cb8222a193a8','廢井','梅堯臣','宋','宋诗','song-poetry','','[]','陻廢不知年，石欄蒼蘚澀。',36,'全唐诗/poet.song.13000.json','["陻廢不知年，石欄蒼蘚澀。", "渴心空自煩，長綆曾誰汲。", "無復語滄波，坎蛙奚所及。"]'),
('9468765e-627a-4a72-8c9a-4293ceeb070a','茶竈','梅堯臣','宋','宋诗','song-poetry','','[]','山寺碧溪頭，幽人綠巖畔。',36,'全唐诗/poet.song.13000.json','["山寺碧溪頭，幽人綠巖畔。", "夜火竹聲乾，春甌茗花亂。", "茲無雅趣兼，薪桂煩燃爨。"]'),
('d86b0061-f5c7-4b9e-8953-a4e8e3e2514f','緱山子晉祠','梅堯臣','宋','宋诗','song-poetry','','[]','王子居玉京，故山空寂寞。',48,'全唐诗/poet.song.13000.json','["王子居玉京，故山空寂寞。", "猶聞遡月笙，尚想賓天鶴。", "翠柏深古壇，丹霞留迥壑。", "芝庭誰款扉，旌旗穿林薄。"]'),
('764be64b-95f9-4551-9c04-749039976064','緱山子晉祠 少林寺','梅堯臣','宋','宋诗','song-poetry','','[]','紅旌過翠岑，林際瞻蓮宇。',48,'全唐诗/poet.song.13000.json','["紅旌過翠岑，林際瞻蓮宇。", "門對幾千巖，花開第一祖。", "禪庭松色寒，石室苔痕古。", "寂寂不逢人，空簷燕方乳。"]'),
('d6a6e568-7c79-489d-9cfb-d6214a0fc12d','緱山子晉祠 少姨廟','梅堯臣','宋','宋诗','song-poetry','','[]','靈祠古殿深，少室羣峯碧。',48,'全唐诗/poet.song.13000.json','["靈祠古殿深，少室羣峯碧。", "行雨欲隨車，望巖非化石。", "常聞蘭氣蒸，誰奠椒香液。", "寄謝洛川妃，淩波定何益。"]'),
('76952790-7874-4870-8526-ba37c98712e5','緱山子晉祠 天封觀','梅堯臣','宋','宋诗','song-poetry','','[]','車馬雲外來，衣霑半山雨。',48,'全唐诗/poet.song.13000.json','["車馬雲外來，衣霑半山雨。", "弭節扣真居，捫蘿笑塵矩。", "迴溪響石叢，靈茹抽巖塢。", "玉檻刻年華，應無愧前古。"]'),
('489573e3-049a-4c73-b6d8-cd4b5eee6da2','緱山子晉祠 會善寺','梅堯臣','宋','宋诗','song-poetry','','[]','杳藹隨龍節，縈紆歷寶山。',48,'全唐诗/poet.song.13000.json','["杳藹隨龍節，縈紆歷寶山。", "瑠璃開浄界，薜荔啟禪關。", "煮茗石泉上，清吟雲壑間。", "峯端生片雨，稍促畫輪還。"]'),
('1755be0b-5f77-4450-b200-109952ea64c3','緱山子晉祠 啟母石','梅堯臣','宋','宋诗','song-poetry','','[]','曠哉嵩室陽，神怪所棲宅。',48,'全唐诗/poet.song.13000.json','["曠哉嵩室陽，神怪所棲宅。", "蒼石不知年，靈熊去無迹。", "煙巖想桂宮，苔壁疑椒掖。", "不學舜娥悲，瀟湘竹枝碧。"]'),
('8bd17594-4b39-4c34-acc3-2122630f5835','緱山子晉祠 轘轅道','梅堯臣','宋','宋诗','song-poetry','','[]','險絕稱漢關，晨躋瞻一室。',48,'全唐诗/poet.song.13000.json','["險絕稱漢關，晨躋瞻一室。", "盤紆石路回，迤邐雲峰出。", "古壁挂青蒼，天風起蕭瑟。", "洛城西首時，望望平煙密。"]'),
('2dd7cf47-bd22-4c43-8c61-c74cd969e7c0','中伏日陪二通判妙覺寺避暑','梅堯臣','宋','宋诗','song-poetry','','[]','紺宇迎凉日，方床御綌衣。',48,'全唐诗/poet.song.13000.json','["紺宇迎凉日，方床御綌衣。", "清談停玉麈，雅曲弄金徽。", "高樹秋聲早，長廊暑氣微。", "不須河朔飲，煮茗自忘歸。"]'),
('bc452d70-c768-464d-8fd8-4ea477c7a0cd','元政上人遊終南','梅堯臣','宋','宋诗','song-poetry','','[]','雉節居杜陵，南山常在目。',72,'全唐诗/poet.song.13000.json','["雉節居杜陵，南山常在目。", "今茲羨行遊，因以謝巖谷。", "環錫恣探勝，椶綦方踐陸。", "五門嵐翠橫，八水秋陰覆。", "雲峰多隠見，林嶺乍回復。", "若見採芝人，余非戀微祿。"]'),
('19147df5-fe02-4b72-8503-3292d1b25db1','寄河陽簽判富彥國','梅堯臣','宋','宋诗','song-poetry','','[]','籍籍名方遠，人知第一流。',48,'全唐诗/poet.song.13000.json','["籍籍名方遠，人知第一流。", "翻同貴公子，來事外諸侯。", "地險長河急，天高畫角秋。", "仲宣應自樂，寧復賦登樓。"]'),
('ebca5659-5190-4294-b9ff-6382f250f60b','河南受代前一日希深示詩','梅堯臣','宋','宋诗','song-poetry','','[]','我昔在桐鄉，伊人頗欣戴。',72,'全唐诗/poet.song.13000.json','["我昔在桐鄉，伊人頗欣戴。", "今來佐洛南，事事爲時背。", "自愧居下流，無能謝前輩。", "固乏橫草功，當蒙及瓜代。", "且遺牒訴還，何用吏民愛。", "洗眼看舊書，怡然忘宇內。"]'),
('c98e370f-c6f4-4220-90aa-7685e9e2ff96','秋雨','梅堯臣','宋','宋诗','song-poetry','','[]','雨後秋氣早，凉歸室廬清。',48,'全唐诗/poet.song.13000.json','["雨後秋氣早，凉歸室廬清。", "既摧蚊蠅勢，任壯蛩蟬聲。", "石榴墜枝熟，蒼蘚緣階生。", "閉門且高卧，畏向泥涂行。"]'),
('1a1a6096-6d15-4416-a50d-407c84e78717','白雲和子聰','梅堯臣','宋','宋诗','song-poetry','','[]','長憶江海間，龍鳴向寒水。',60,'全唐诗/poet.song.13000.json','["長憶江海間，龍鳴向寒水。", "藹藹蒼渚空，悠悠白雲起。", "是時在漁舟，放溜看未已。", "今來居洛陽，埃壒生蹄軌。", "羨君茲日心，怊悵聊徙倚。"]'),
('5de5edd3-c220-4249-b93e-2880e8a0f71d','同尹子漸王幾道訪郭生別墅不遇','梅堯臣','宋','宋诗','song-poetry','','[]','秋野已澄曠，偶來幽興多。',48,'全唐诗/poet.song.13000.json','["秋野已澄曠，偶來幽興多。", "茨居隔寒水，柴戶蔭喬柯。", "看竹曾留鳳，携朋不爲鵝。", "人歸碧苔徑，應識履痕過。"]'),
('1c088e61-203f-4e0f-8165-ef5bf4de8ce7','水葒','梅堯臣','宋','宋诗','song-poetry','','[]','灼灼有芳豔，本生江漢濱。',48,'全唐诗/poet.song.13000.json','["灼灼有芳豔，本生江漢濱。", "臨風輕笑久，隔浦淡粧新。", "白鷺煙中客，紅蕖水上鄰。", "無香結珠穗，秋露浥羅巾。"]'),
('f87b4112-aa3b-4db7-955f-511e7c3240cd','黄河','梅堯臣','宋','宋诗','song-poetry','','[]','積石導淵源，沄沄瀉崑閬。',120,'全唐诗/poet.song.13000.json','["積石導淵源，沄沄瀉崑閬。", "龍門自吞險，鯨海終涵量。", "怒洑生萬渦，驚流非一狀。", "淺深殊可測，激射無時壯。", "常苦事隄防，何曾息波浪。", "川氣迷遠山，沙痕落秋漲。", "槎沫夜浮光，舟人朝發唱。", "洪梁畫鷁連，古戍蒼崖向。", "浴鳥不知清，夕陽空在望。", "誰當大雪天，走馬堅冰上。"]'),
('b57df8b6-a85d-4d82-97ec-53bf64b6eb01','王氏昆仲歸寧','梅堯臣','宋','宋诗','song-poetry','','[]','昨夜雪霏霏，梁山吟未歸。',48,'全唐诗/poet.song.13000.json','["昨夜雪霏霏，梁山吟未歸。", "關河誰道遠，鴻雁自相依。", "落日人煙少，寒雲驛路微。", "共將彭澤酒，稱壽向庭闈。"]'),
('84eee604-5cbd-4906-8398-87f09cccb3ca','子聰惠書備言行路及遊王屋物趣因以答','梅堯臣','宋','宋诗','song-poetry','','[]','自我河橋來，清話殊未已。',240,'全唐诗/poet.song.13000.json','["自我河橋來，清話殊未已。", "亟言閱通疇，晨駕遂遵彼。", "尺書忽見遺，經由皆可紀。", "草草始辭家，怱怱渡河水。", "前村客心速，入暮陰風起。", "脩路隘且長，疲驂未能止。", "茅居聒夜舂，寒犬吠墟里。", "明發西北行，崗巒踰迤邐。", "叢蓁但蒙密，未見山中美。", "谷開逢邑閭，豈謂連都鄙。", "冠带一二同，麏麋左右比。", "問子奚所之，俛眉聊啟齒。", "瞥往登天壇，煙雲隨步趾。", "傍臨日觀低，却望嵩丘邇。", "屑屑視塵埃，紛紛若螻蟻。", "便有林壑心，期將榮宦委。", "我昔愛青蒼，無時常徙倚。", "今朝羨君遊，勝事空聳企。", "徒嗟黄綬身，莫接青霞軌。", "安得憑羽翰，幽懷寄如此。"]'),
('c121ca58-c500-4dff-bdd0-7dd200b16cb6','環州通判張殿丞','梅堯臣','宋','宋诗','song-poetry','','[]','欲向蕭關外，窮陰雪暗沙。',48,'全唐诗/poet.song.13000.json','["欲向蕭關外，窮陰雪暗沙。", "磧寒鴻雁少，冰合水泉賒。", "自有從軍樂，應無去國嗟。", "春風曾不到，吹角寄梅花。"]'),
('ba221b67-f621-4b75-a53f-be917c456ca8','張太素之邠幕','梅堯臣','宋','宋诗','song-poetry','','[]','應幕向豳郊，晨裝辭郟鄏。',72,'全唐诗/poet.song.13000.json','["應幕向豳郊，晨裝辭郟鄏。", "長亭欲少留，飛鵠初成曲。", "魯酒上離顔，行塵生驥足。", "悠悠關戍遥，黤黤煙雲屬。", "塞邑多苦寒，國風遺舊俗。", "寄音文醼餘，莫待霜條綠。"]'),
('e475eb5b-75d4-4e72-a3fd-ded1c8cd237b','孫屯田召爲御史','梅堯臣','宋','宋诗','song-poetry','','[]','薦牘交車府，恩書下建章。',72,'全唐诗/poet.song.13000.json','["薦牘交車府，恩書下建章。", "輕軒辭瑞翟，危弁學神羊。", "祖酌方滋桂，行威欲犯霜。", "鳳毛仍襲慶，雞舌更含香。", "氣鬰翔龍闕，風清振鷺行。", "今朝洛民思，東陌盛壺漿。"]'),
('a6cac8c1-1a33-4e54-899e-a823f8518af5','與諸友普明院亭納凉分題','梅堯臣','宋','宋诗','song-poetry','','[]','岸幘清凉地，翛然樂未窮。',48,'全唐诗/poet.song.13000.json','["岸幘清凉地，翛然樂未窮。", "竹陰過晚雨，林表見殘虹。", "花影平波上，經聲小塢東。", "還思醉吟者，寧與此時同。"]'),
('3e2145a3-3e4d-4b1d-ac9a-91114d3d9b0d','梅花','梅堯臣','宋','宋诗','song-poetry','','[]','似畏羣芳妬，先春發故林。',48,'全唐诗/poet.song.13000.json','["似畏羣芳妬，先春發故林。", "曾無鶑蝶戀，空被雪霜侵。", "不道東風遠，應悲上苑深。", "南枝已零落，羌笛寄餘音。"]'),
('ca672585-6dbc-4da1-9151-5133fff5be3a','依韻和希深立春後祀風伯雨師畢過午橋莊','梅堯臣','宋','宋诗','song-poetry','','[]','青郊誰駐馬，謝客思池塘。',48,'全唐诗/poet.song.13000.json','["青郊誰駐馬，謝客思池塘。", "野水微波綠，江梅嫩蘂黄。", "初從奠風雨，遂此樂壺觴。", "已愛幽禽語，園林即日芳。"]'),
('ba213caa-bb2a-443f-883f-4250b6accdbd','尹子漸歸華産茯苓若人形者賦以贈行','梅堯臣','宋','宋诗','song-poetry','','[]','因歸話茯苓，久著桐君籍。',96,'全唐诗/poet.song.13000.json','["因歸話茯苓，久著桐君籍。", "成形得人物，具體存標格。", "神岳畜粹和，寒松化膏液。", "外凝石稜紫，內藴瓊腴白。", "千載忽旦暮，一朝成琥珀。", "既瑩毫芒分，不與蚊蚋隔。", "拾芥曾未難，爲器期增飾。", "至珍行處稀，美價定多益。"]'),
('05a55235-95a9-441e-928f-1266cfbf28ad','初見杏花','梅堯臣','宋','宋诗','song-poetry','','[]','不待春風徧，煙林獨早開。',24,'全唐诗/poet.song.13000.json','["不待春風徧，煙林獨早開。", "淺紅欺醉粉，肯信有江梅。"]'),
('66d44f72-bb84-4e9c-b373-51a079b01ed6','依韻和載陽登廣福寺閣','梅堯臣','宋','宋诗','song-poetry','','[]','過聞聯騎出，登覽思踰清。',48,'全唐诗/poet.song.13000.json','["過聞聯騎出，登覽思踰清。", "曉漲林煙重，春歸野水平。", "始看僊杏發，已愛裌衣輕。", "誰見吟餘處，殘陽上古城。"]'),
('e11ae019-5ef0-47a7-ac60-e3aceb0ccfea','依韻和歐陽永叔同遊近郊','梅堯臣','宋','宋诗','song-poetry','','[]','洛水橋邊春已迴，柳條葱蒨眼初開。',64,'全唐诗/poet.song.13000.json','["洛水橋邊春已迴，柳條葱蒨眼初開。", "無人拾翠過幽渚，有客尋芳上古臺。", "林邃珍禽時一囀，酒酣紅日未西頹。", "知君最是憐風物，更約偷閑取次來。"]'),
('26917772-ba6f-48d2-ab19-6811c194cafc','依韻和永叔同遊上林院後亭見櫻桃花悉已披謝','梅堯臣','宋','宋诗','song-poetry','','[]','去年君到見春遲，今日尋芳是夙期。',64,'全唐诗/poet.song.13000.json','["去年君到見春遲，今日尋芳是夙期。", "祇道朱櫻纔弄蘂，及來幽圃已殘枝。", "飄英尚有遊蜂戀，著子唯應谷鳥知。", "把酒聊能慰餘景，乘歡不厭夕陽時。"]'),
('ac9ad190-1353-4ee7-bc71-03490c3babc4','依韻和王幾道塗次杏花有感','梅堯臣','宋','宋诗','song-poetry','','[]','馬上逢丹杏，芳條拂眼過。',48,'全唐诗/poet.song.13000.json','["馬上逢丹杏，芳條拂眼過。", "可憐荒徑少，不道故園多。", "豔萼黏紅蠟，僊葩縐薄羅。", "客心知易感，路遠奈愁何。"]'),
('7b1c7ed2-9402-436e-9722-2e81c2268c5e','遊園晚歸馬上希深命賦','梅堯臣','宋','宋诗','song-poetry','','[]','興盡夕陽天，言歸躍杏韉。',48,'全唐诗/poet.song.13000.json','["興盡夕陽天，言歸躍杏韉。", "新陰六街樹，遠目萬家煙。", "歌咽樓千尺，吟餘月一弦。", "花間有遊妓，醉去墮金鈿。"]'),
('1e37bb22-b0ad-41f6-8141-5b189d83c56c','留題希深美檜亭','梅堯臣','宋','宋诗','song-poetry','','[]','幽深有佳趣，曾不減林泉。',48,'全唐诗/poet.song.13000.json','["幽深有佳趣，曾不減林泉。", "衆綠經新雨，殘紅墮夕煙。", "栽萱北堂近，夢草故池連。", "乘月時來往，清歌思浩然。"]'),
('a50fe87e-73b1-4282-9458-a6a30fbed2b1','留守相公新剏雙桂樓','梅堯臣','宋','宋诗','song-poetry','','[]','藻棟起霄間，芳條俯可攀。',48,'全唐诗/poet.song.13000.json','["藻棟起霄間，芳條俯可攀。", "晚雲談次改，高鳥坐中還。", "日映城邊樹，虹明雨外山。", "唯應謝池月，來照衮衣閑。"]'),
('ad0651be-c95d-4bad-a614-79cf652d1240','和希深避暑香山寺','梅堯臣','宋','宋诗','song-poetry','','[]','有客乘新霽，雲林共扣扃。',48,'全唐诗/poet.song.13000.json','["有客乘新霽，雲林共扣扃。", "輕舟過下渡，遠水漲前汀。", "原隰含幽藹，岑嵐入杳冥。", "誰知得深趣，履齒石苔青。"]'),
('bfa5f2d4-625f-44bc-9806-f8a024e9b22a','和希深晚泛伊川','梅堯臣','宋','宋诗','song-poetry','','[]','放溜下平波，舟移不知遠。',48,'全唐诗/poet.song.13000.json','["放溜下平波，舟移不知遠。", "稍迴溪口風，恣愛雲中巘。", "水鳥靜相依，蘆洲藹將晚。", "歸路莫言賒，何妨乘月返。"]'),
('3a4439ff-b998-40c8-862b-f8c3e3627927','路中月夕登霽景臺與唐英話別','梅堯臣','宋','宋诗','song-poetry','','[]','風枝不動月光午，况是高臺過新雨。',80,'全唐诗/poet.song.13000.json','["風枝不動月光午，况是高臺過新雨。", "吳客方思千里歸，不負洛陽塵與土。", "到時水落鱖鱸肥，香稻初炊鱠紅縷。", "休言羊酪敵蓴羹，我亦長吟念東楚。", "平胡馬嘶誰可留，去去相望富春渚。"]'),
('2203762e-12d6-4ae4-8a87-d9339b89bdf9','張侍郎中隠堂','梅堯臣','宋','宋诗','song-poetry','','[]','疇昔人歸老，於茲望白雲。',48,'全唐诗/poet.song.13000.json','["疇昔人歸老，於茲望白雲。", "門高知後慶，賓至誦先芬。", "草樹中園秀，衣冠舊里聞。", "寧同江令宅，寂寞向淮濆。"]'),
('ba80ab55-2e40-43fc-8007-26ecadfffa84','太尉相公中伏日池亭宴會','梅堯臣','宋','宋诗','song-poetry','','[]','何言避徂暑，清宴水軒閑。',72,'全唐诗/poet.song.13000.json','["何言避徂暑，清宴水軒閑。", "竹氣陰池鳳，雲峰照衮山。", "玳簪方映座，綵服亦承顔。", "樂奏寒波上，杯香綠芰間。", "瓜浮五色爛，簾捲半鈎彎。", "今日賓裾盛，袁劉豈足攀。"]'),
('828c3fd2-f964-4188-a769-3d8392607421','送臧尉','梅堯臣','宋','宋诗','song-poetry','','[]','藹藹神僊尉，西風躍馬歸。',48,'全唐诗/poet.song.13000.json','["藹藹神僊尉，西風躍馬歸。", "離羣賦黄鵠，拜慶著斑衣。", "雨氣連關黑，槐花上路飛。", "同爲洛陽客，今日故人稀。"]'),
('b63965e0-2fa7-4c61-a4ea-e135870b33ed','新秋普明院竹林小飲得高樹早凉歸  其一','梅堯臣','宋','宋诗','song-poetry','','[]','翻然思何苦，昨夜秋風高。',24,'全唐诗/poet.song.13000.json','["翻然思何苦，昨夜秋風高。", "良友念將別，幅巾邀此遨。"]'),
('cfd6e6c3-8f54-4a9f-b538-16281c6672de','新秋普明院竹林小飲得高樹早凉歸  其二','梅堯臣','宋','宋诗','song-poetry','','[]','清梵隔寒流，亂蟬鳴古樹。',24,'全唐诗/poet.song.13000.json','["清梵隔寒流，亂蟬鳴古樹。", "誰知林下遊，復得盃中趣。"]'),
('5f748f93-681f-460b-ad0c-5d0085917820','新秋普明院竹林小飲得高樹早凉歸  其三','梅堯臣','宋','宋诗','song-poetry','','[]','池上暑風收，竹間秋氣早。',24,'全唐诗/poet.song.13000.json','["池上暑風收，竹間秋氣早。", "回塘莫苦留，已變王孫草。"]'),
('5dfde51e-c16f-4ba9-9a12-b7e10737c425','新秋普明院竹林小飲得高樹早凉歸  其四','梅堯臣','宋','宋诗','song-poetry','','[]','未墜高梧葉，初生玉井凉。',24,'全唐诗/poet.song.13000.json','["未墜高梧葉，初生玉井凉。", "愁心異潘岳，獨自向河陽。"]'),
('5b9afcb9-d57d-4b21-8160-a71c2a1f97b1','新秋普明院竹林小飲得高樹早凉歸  其五','梅堯臣','宋','宋诗','song-poetry','','[]','不減阮家會，所嗟當北歸。',24,'全唐诗/poet.song.13000.json','["不減阮家會，所嗟當北歸。", "厭厭敢辭醉，明發此歡非。"]'),
('fa73a330-21e2-431c-a312-01b7da99ae97','新秋雨夜西齋文會','梅堯臣','宋','宋诗','song-poetry','','[]','夜色際陰霾，燈青謝客齋。',48,'全唐诗/poet.song.13000.json','["夜色際陰霾，燈青謝客齋。", "梧桐生靜思，絡緯動秋懷。", "小酌寧辭醉，清言不厭諧。", "誰憐何水部，吟苦怨空階。"]'),
('09788ba0-60d4-434b-8c89-3fd549c5558b','秋陰','梅堯臣','宋','宋诗','song-poetry','','[]','已過蕭蕭雨，猶成黯黯陰。',48,'全唐诗/poet.song.13000.json','["已過蕭蕭雨，猶成黯黯陰。", "登臨潘岳思，憀慄楚臣心。", "遠吹鳴高樹，低雲冒晚岑。", "久爲關外客，不忍聽疎砧。"]'),
('a7df42c3-ae62-4354-afc9-07c6b5cf8e6b','雨中移竹','梅堯臣','宋','宋诗','song-poetry','','[]','荷鍤冒秋霖，怱怱移翠竹。',48,'全唐诗/poet.song.13000.json','["荷鍤冒秋霖，怱怱移翠竹。", "欲分溪上陰，聊助池邊綠。", "中散林未開，子猷心已足。", "青青謝栽培，豈愧凡草木。"]'),
('05022e27-67f2-469d-a981-7df59ea0c071','希深所居官舍新得相府蔬圃以廣西園','梅堯臣','宋','宋诗','song-poetry','','[]','楚相拔葵後，蕭條三畝餘。',48,'全唐诗/poet.song.13000.json','["楚相拔葵後，蕭條三畝餘。", "煙畦偶連軫，蕙圃得增墟。", "便欲開春沼，何妨薙野蔬。", "始添臺榭美，况近子雲居。"]'),
('f82c4534-561b-4c11-a406-f71dffa9d783','和永叔柘枝歌','梅堯臣','宋','宋诗','song-poetry','','[]','漁陽三疊音隆隆，紅蕖亂坼當秋風。',192,'全唐诗/poet.song.13000.json','["漁陽三疊音隆隆，紅蕖亂坼當秋風。", "披香擁霧出妖嫮，嫵眉壯髮翩驚鴻。", "鏘鏘雜珮離芳渚，珠帽紅靴振金縷。", "相迎垂手勢如傾，障袂倚歌詞欲吐。", "最憐應節乍低昂，便轉疾徐皆可覩。", "飄揚初認雪迴風，躑躅還看繭縈緒。", "小小寧聞怨曲長，盈盈自解依儔侶。", "藝奇體妙按者誰，金貂大尹宴清池。", "綺茵繡幄粲輝映，玳簪珠履何委蛇。", "是時郊原新退暑，天清氣爽過林墅。", "淮王載酒昔嘗聞，謝公携妓那能數。", "始知事簡樂民和，不厭來觀柘枝舞。"]'),
('4e831361-8b02-42cf-b53a-06fc90d36dcc','依韻和載陽郊外','梅堯臣','宋','宋诗','song-poetry','','[]','近隰葱蘢曙，驚烏睥睨啼。',48,'全唐诗/poet.song.13000.json','["近隰葱蘢曙，驚烏睥睨啼。", "日光林杪動，吹騎管中嘶。", "路遶寒原古，煙橫遠戍迷。", "今來異賓孟，誰復嘆雄雞。"]'),
('199fb73e-e516-4a71-8d3f-a40a72e44c10','奉和永叔得辛判官伊陽所寄山桂數本封殖之後遂成雅韻以見貺','梅堯臣','宋','宋诗','song-poetry','','[]','團團綠桂叢，本自幽巖得。',48,'全唐诗/poet.song.13000.json','["團團綠桂叢，本自幽巖得。", "惠好知不忘，青葱寧改色。", "香生蓮幕間，花白萱堂側。", "月露夜偏滋，瓊枝相翕赫。"]'),
('b19b33f5-8035-4b63-8780-6cebfd0952e0','河陽秋夕夢與永叔遊嵩避雨於峻極院賦詩及覺猶能憶記俄而僕夫自洛來云永叔諸君陪希深祠岳因足成短韻','梅堯臣','宋','宋诗','song-poetry','','[]','夕寢北窗下，青山夢與尋。',48,'全唐诗/poet.song.13000.json','["夕寢北窗下，青山夢與尋。", "相歡不異昔，勝事却疑今。", "風雨幽林靜，雲煙古寺深。", "攬衣方有感，還喜問來音。"]'),
('b83a2c74-bd40-41db-9812-bd7236714c3c','希深惠書言與師魯永叔子聰幾道遊嵩因誦而韻之','梅堯臣','宋','宋诗','song-poetry','','[]','聞君奉宸詔，瑞祝疑靈岫。',288,'全唐诗/poet.song.13000.json','["聞君奉宸詔，瑞祝疑靈岫。", "山水聊得游，志願庶可就。", "豈無朋從俱，况此一二秀。", "方蘄建春陌，十刻殘晝漏。", "初經緱氏嶺，古柏尚鬰茂。", "却過轘轅關，巨石相撐鬭。", "夕齋禮神祠，法衮被藻繡。", "畢事登山椒，常服更短後。", "從者十數人，輕齎不爲陋。", "是時天清陰，力氣勇奔驟。", "雲巖杳虧蔽，花草藏澗竇。", "傍林有珍禽，驚聒若避彀。", "盤石暫憩休，泓泉助吞漱。", "上窺玉女窗，嶄絕非可構。", "下玩搗衣碪，焜耀金紋透。", "尹子體雄恔，攀緣愈習狃。", "歐陽稱壯齡，疲軟屢顛踣。", "競歡相扶持，芒屩恣踐蹂。", "八僊存故壇，三醉孰云謬。", "鄙哉封禪碑，數字昔鎸鏤。", "偶誌一時事，曷虞來者詬。", "絕頂瞰諸峯，隘然輕宇宙。", "遥思謝塵煩，欲知羣鳥獸。", "韓公傳石室，聞之固已舊。"]'),
('6a2fb414-39ac-4358-88bf-9c6280cf5e16','送河清賈主簿歸任','梅堯臣','宋','宋诗','song-poetry','','[]','不遠水雲間，悠悠泝鷁還。',48,'全唐诗/poet.song.13000.json','["不遠水雲間，悠悠泝鷁還。", "分亭接雞犬，舉酒對河山。", "殘雪依荒磧，寒煙入暝灣。", "昔人鸞枳歎，一併在離顔。"]'),
('f4b039d4-c5a2-47c4-99c2-97a792f2498b','依韻和永叔雪後見寄兼云自尹家兄弟及幾道散後子聰下縣久不得歸頗有離索之歎','梅堯臣','宋','宋诗','song-poetry','','[]','常欲登芒嶺，無由見洛橋。',72,'全唐诗/poet.song.13000.json','["常欲登芒嶺，無由見洛橋。", "雪飛關戍迥，人憶剡溪遥。", "廣隰嘶征雁，長河起怒飈。", "遽言歡友散，能使去魂銷。", "晚日窮幽藹，愁雲暝泬寥。", "縱令佳約在，載酒定何邀。"]'),
('ab1dfb6e-374f-4644-8d43-85e3d2ffacf7','依韻和歐陽永叔黄河八韻','梅堯臣','宋','宋诗','song-poetry','','[]','少本江南客，今爲河曲遊。',96,'全唐诗/poet.song.13000.json','["少本江南客，今爲河曲遊。", "歲時憂漾溢，日夕見奔流。", "齧岸侵民壤，飄槎閣雁洲。", "峻門波作箭，古郡鐵爲牛。", "目極高飛鳥，身輕不及舟。", "寒冰狐自聽，源水使嘗求。", "密樹隨灣轉，長罾刮浪收。", "如何貴沈玉，川興是諸侯。"]'),
('4beb9a10-3b87-483e-b751-693de3e682c8','季父知并州','梅堯臣','宋','宋诗','song-poetry','','[]','捧詔出明光，飛軒陟太行。',72,'全唐诗/poet.song.13000.json','["捧詔出明光，飛軒陟太行。", "玉墀分近侍，虎綬給新章。", "笳吹喧行陌，旌旗卷夜霜。", "雁歸汾水綠，城壓代雲黄。", "土屋春風峭，氊裘牧騎狂。", "關山寧久駐，剩宴柳溪傍。"]'),
('06c51e6c-8302-4ad9-a930-beae97c68407','河陰中寨寒食','梅堯臣','宋','宋诗','song-poetry','','[]','擊柝聲初絕，爲魚夢已殘。',48,'全唐诗/poet.song.13000.json','["擊柝聲初絕，爲魚夢已殘。", "幽禽哢清曉，宿雨度餘寒。", "爨火明千竈，風旗展一竿。", "歸心慙社燕，自歎此微官。"]'),
('38aca6ae-e1ca-4e8d-9cfe-49895a98f914','再至洛中寒食','梅堯臣','宋','宋诗','song-poetry','','[]','西洛逢寒食，依依似昔年。',48,'全唐诗/poet.song.13000.json','["西洛逢寒食，依依似昔年。", "千門方禁火，九野自生煙。", "飄泊梨花雨，追隨杏葉韉。", "遊人莫惜醉，風景滿伊川。"]'),
('7ba3da00-93ce-4196-8a7d-8f983c946561','同永叔子聰遊嵩山賦十二題 公路澗','梅堯臣','宋','宋诗','song-poetry','','[]','我來袁公溪，斷岸猶殘壘。',48,'全唐诗/poet.song.13000.json','["我來袁公溪，斷岸猶殘壘。", "僵柳遠臨灣，新蒲初出水。", "行行古臺近，兩兩驚禽起。", "雞犬何處聞，人家深塢裏。"]'),
('3f0071d9-9a9d-42cb-9937-ca8cc4d909f9','同永叔子聰遊嵩山賦十二題 拜馬澗','梅堯臣','宋','宋诗','song-poetry','','[]','王子昔凌霓，國人茲拜馬。',36,'全唐诗/poet.song.13000.json','["王子昔凌霓，國人茲拜馬。", "依稀日夜笙，聲入寒泉瀉。", "空傳七日期，飛鶴何時下。"]'),
('b26483db-0560-4a6e-91c9-10fe8fb9937e','同永叔子聰遊嵩山賦十二題 二室道','梅堯臣','宋','宋诗','song-poetry','','[]','度嶺失羣山，千峯出天際。',36,'全唐诗/poet.song.13000.json','["度嶺失羣山，千峯出天際。", "方欣左右看，屢改縈迴勢。", "勝事誰與同，芬然有蘭蕙。"]'),
('b87db055-b021-4f19-aa16-5622fed30deb','同永叔子聰遊嵩山賦十二題 自峻極中院步登太室中峯','梅堯臣','宋','宋诗','song-poetry','','[]','稅駕綠巖前，攀蘿不知倦。',36,'全唐诗/poet.song.13000.json','["稅駕綠巖前，攀蘿不知倦。", "人從樹杪來，路向雲端轉。", "忽覺在煙霓，回看峯嶺變。"]'),
('5ee9a0c0-d72a-41f5-bc6e-93ca602c5181','同永叔子聰遊嵩山賦十二題 玉女窗','梅堯臣','宋','宋诗','song-poetry','','[]','玉洞倚霞壁，天窗露微明。',36,'全唐诗/poet.song.13000.json','["玉洞倚霞壁，天窗露微明。", "驂鸞去不返，啼鳥空相驚。", "萬木自虧蔽，捫蘿復誰情。"]'),
('7c35a079-4a07-421b-bd86-71fcb7143d34','同永叔子聰遊嵩山賦十二題 玉女擣衣石','梅堯臣','宋','宋诗','song-poetry','','[]','幽石稱擣衣，擣衣人不見。',36,'全唐诗/poet.song.13000.json','["幽石稱擣衣，擣衣人不見。", "雲纓白飄颻，巖樹長葱蒨。", "猶應寒夜中，山月來鋪練。"]'),
('b1c73eef-c6df-4dc6-b388-a0af1f81d9bf','同永叔子聰遊嵩山賦十二題 天門','梅堯臣','宋','宋诗','song-poetry','','[]','古壁何蒼蒼，穿雲玉梯出。',36,'全唐诗/poet.song.13000.json','["古壁何蒼蒼，穿雲玉梯出。", "歘然起青冥，却立觀少室。", "前巖復後峯，陰晴狀非一。"]'),
('9c31fb43-1c1a-4970-8a4d-eab11970196e','同永叔子聰遊嵩山賦十二題 天門泉','梅堯臣','宋','宋诗','song-poetry','','[]','泠泠雲外泉，的的巖光入。',36,'全唐诗/poet.song.13000.json','["泠泠雲外泉，的的巖光入。", "靜若僊鑑開，寒疑玉龍蟄。", "時應下鹿羣，跡印青苔濕。"]'),
('59dafba8-3438-4f5e-82c3-3663b92bd010','同永叔子聰遊嵩山賦十二題 天池','梅堯臣','宋','宋诗','song-poetry','','[]','安知最高頂，清淺水池開。',36,'全唐诗/poet.song.13000.json','["安知最高頂，清淺水池開。", "有時片雲出，倏忽生風雷。", "誰羨雙黄鵠，刷羽來徘徊。"]'),
('2acd5647-4309-42ce-9380-616ee57e5ff1','同永叔子聰遊嵩山賦十二題 三醉石','梅堯臣','宋','宋诗','song-poetry','','[]','相期物外遊，共醉僊壇石。',36,'全唐诗/poet.song.13000.json','["相期物外遊，共醉僊壇石。", "舉手薄高穹，清風生兩腋。", "都忘塵世煩，笑傲聊爲適。"]'),
('44b30fd3-5879-44aa-968f-8fe8617cc093','同永叔子聰遊嵩山賦十二題 登太室中峯','梅堯臣','宋','宋诗','song-poetry','','[]','日夕望蒼崖，嶄嶄在天外。',36,'全唐诗/poet.song.13000.json','["日夕望蒼崖，嶄嶄在天外。", "及來步其巔，下見河如带。", "半壁雲樹昏，山根已霶霈。"]'),
('a6ebca86-f7b0-4cdc-924d-bf6ea7632a9d','同永叔子聰遊嵩山賦十二題 峻極寺','梅堯臣','宋','宋诗','song-poetry','','[]','山高路已窮，倏爾逢蘭若。',36,'全唐诗/poet.song.13000.json','["山高路已窮，倏爾逢蘭若。", "落日老僧閑，支頤古松下。", "緩步入禪庭，苔蒼但蕭灑。"]'),
('c0f79312-f64c-4f6d-a428-941c23be6809','擬玉臺體七首 欲眠','梅堯臣','宋','宋诗','song-poetry','','[]','鴛鴦羅薦開，翡翠香幃寂。',24,'全唐诗/poet.song.13000.json','["鴛鴦羅薦開，翡翠香幃寂。", "解带竟羞明，移燈向東壁。"]'),
('03c71c25-2c55-4b25-a5c4-07d7a7527b77','擬玉臺體七首 携手曲','梅堯臣','宋','宋诗','song-poetry','','[]','携手出中閨，殷勤尅密期。',24,'全唐诗/poet.song.13000.json','["携手出中閨，殷勤尅密期。", "密期雖不遠，迴顧步遲遲。"]'),
('42c6652f-608a-458b-8d6d-63b6ad36a387','擬玉臺體七首 雨中歸','梅堯臣','宋','宋诗','song-poetry','','[]','來時雲冉冉，去值雨霏霏。',24,'全唐诗/poet.song.13000.json','["來時雲冉冉，去值雨霏霏。", "莫怪羅衣濕，荆王夢罷歸。"]'),
('4dadf8a9-46dd-42c8-8e98-073d0adc1010','擬玉臺體七首 別後','梅堯臣','宋','宋诗','song-poetry','','[]','昨日日暮別，今日日暮愁。',24,'全唐诗/poet.song.13000.json','["昨日日暮別，今日日暮愁。", "猶認縱裙色，依依在石榴。"]'),
('eeced826-ca0c-4a1a-ae05-bf75a48d218a','擬玉臺體七首 夜夜曲','梅堯臣','宋','宋诗','song-poetry','','[]','情來不自理，明月生南樓。',24,'全唐诗/poet.song.13000.json','["情來不自理，明月生南樓。", "坐感昔時樂，飜成此夜愁。"]'),
('4584fe61-7df7-4c5c-8c90-ab62d93ef758','擬玉臺體七首 落日窗中坐','梅堯臣','宋','宋诗','song-poetry','','[]','含情獨不語，落日窗中時。',24,'全唐诗/poet.song.13000.json','["含情獨不語，落日窗中時。", "妾意與君意，相思只自知。"]'),
('3d3f9889-8195-4e80-a372-3f9f442bacb4','擬玉臺體七首 領邊繡','梅堯臣','宋','宋诗','song-poetry','','[]','出門重新製，纖手行自整。',24,'全唐诗/poet.song.13000.json','["出門重新製，纖手行自整。", "願作花工兒，長年承素頸。"]'),
('f40291aa-5a69-40f5-966a-b4cd8752b7d6','無題','梅堯臣','宋','宋诗','song-poetry','','[]','斗覺瓊枝瘦，慵開寶鑑粧。',48,'全唐诗/poet.song.13000.json','["斗覺瓊枝瘦，慵開寶鑑粧。", "臨風恐僊去，倚扇怯歌長。", "綠桂薰輕服，靈符佩縹囊。", "西鄰空自賦，不解到君傍。"]'),
('bdabaebf-03f9-4819-af5e-d385f01013be','聯句附','梅堯臣','宋','宋诗','song-poetry','','[]','古木含清吹，池上增晚凉。',96,'全唐诗/poet.song.13000.json','["古木含清吹，池上增晚凉。", "余懷本達曠，聯此傲羲皇。", "孤鷗可以狎，幽岸足以觴。", "幸有彭澤酒，便同永嘉堂。", "潘生起爲壽，王子齊陳章。", "林端見新月，草際聞寒螿。", "照水螢影亂，拂筵蓼花香。", "徘徊戀嘉境，坐使歸興忘。"]'),
('e9c56082-f2a4-4d1a-ae95-bd108ac436a5','希深洛中冬夕道話有懷善慧大士因探得江字韻聯句','梅堯臣','宋','宋诗','song-poetry','','[]','彼有上人者，妙談心所降。',72,'全唐诗/poet.song.13000.json','["彼有上人者，妙談心所降。", "達空知不二，觀行本無雙。", "久阻飄花席，因思響雪窗。", "社中雖得遠，方外自非龐。", "夢幻慙他刼，風塵厭此邦。", "終期親道樹，何必憶重江。"]'),
('38ab8496-0543-47ea-9610-31b7c891e713','希深本約遊西溪信馬不覺行過據鞍聯句','梅堯臣','宋','宋诗','song-poetry','','[]','有意訪西溪，順途吟思迷。',48,'全唐诗/poet.song.13000.json','["有意訪西溪，順途吟思迷。", "及茲詢野老，已恨過芳蹊。", "醉客但多興，幽禽空自啼。", "無由駐金勒，林表日光低。"]'),
('51ca8b5b-d596-4f81-977c-10d605580742','同希深馬上口占送九舅入京成親聯句','梅堯臣','宋','宋诗','song-poetry','','[]','之子洛中來，芳罇喜暫開。',48,'全唐诗/poet.song.13000.json','["之子洛中來，芳罇喜暫開。", "人誇阿連少，吾愧士衡才。", "丹闕鳳皇去，清川鴻雁迴。", "都門春色美，相送思悠哉。"]'),
('1045b4af-ba98-4324-a3df-55545307a94b','玉麈尾寄傅尉越石聯句','梅堯臣','宋','宋诗','song-poetry','','[]','齋中獨何物，持之想見君。',96,'全唐诗/poet.song.13000.json','["齋中獨何物，持之想見君。", "惟茲玉麈尾，信美而有文。", "夫子善談道，亹亹詞如雲。", "在握昔同色，傾坐今離羣。", "况託懷袖好，曾親蕙蘭薰。", "嘗許助閑放，於焉探典墳。", "既乃阻清燕，復屈驅蝱蚊。", "自殊白團扇，未畏秋葉紛。"]'),
('fbe50343-6b0d-4e23-b4ee-d99caadcab7f','風瑟聯句','梅堯臣','宋','宋诗','song-poetry','','[]','竅竹漏天風，張絃擬嶧桐。',48,'全唐诗/poet.song.13000.json','["竅竹漏天風，張絃擬嶧桐。", "佳名從此得，妙響未曾窮。", "夜靜危臺上，人閑皎月中。", "依依聽不足，秋露滿蘭叢。"]'),
('153ae283-eda0-4c18-85c9-52d65d814881','問答  其一','梅堯臣','宋','宋诗','song-poetry','','[]','金鑿落，留贈行人須滿酌。',28,'全唐诗/poet.song.13000.json','["金鑿落，留贈行人須滿酌。", "銀缾况有宜城醪，及取春風花照灼。"]'),
('769fabfb-f9a4-49db-bbdf-1963e314c532','問答  其二','梅堯臣','宋','宋诗','song-poetry','','[]','小屏風，座隔流塵素影融。',28,'全唐诗/poet.song.13000.json','["小屏風，座隔流塵素影融。", "方牀六尺偃清晝，慙無玉枕名通中。"]'),
('43664e2a-b298-4912-81c4-ebc8f7bebda5','問答  其三','梅堯臣','宋','宋诗','song-poetry','','[]','玉蟾蜍，厠君筆硯誠有諸。',28,'全唐诗/poet.song.13000.json','["玉蟾蜍，厠君筆硯誠有諸。", "可愛亭亭寒月照，瑩然四座凝冰壺。"]'),
('1e515943-71d2-4f93-ae7c-b83c3b30716e','問答  其四','梅堯臣','宋','宋诗','song-poetry','','[]','金錯刀，連環交刃吹風毛。',28,'全唐诗/poet.song.13000.json','["金錯刀，連環交刃吹風毛。", "美人贈我萬錢貴，何必翦犀誇孟勞。"]'),
('b17ff5d0-02d2-4781-9a87-bbe72f6e270a','問答  其五','梅堯臣','宋','宋诗','song-poetry','','[]','青雲梯，尺木爲階行忽迷。',28,'全唐诗/poet.song.13000.json','["青雲梯，尺木爲階行忽迷。", "勤修道業生羽翼，天門九襲須攀隮。"]'),
('1edb3521-90ad-4ffa-857d-52cf26051dc3','問答  其六','梅堯臣','宋','宋诗','song-poetry','','[]','鳳于飛，差差粹羽今逢時。',28,'全唐诗/poet.song.13000.json','["鳳于飛，差差粹羽今逢時。", "桐花正美矞雪亂，家庭玉樹須來儀。"]'),
('bd384efb-6b67-4df2-b437-80c12467e8b1','依韻和希深新秋會東堂','梅堯臣','宋','宋诗','song-poetry','','[]','何必水周堂，翛然萬木凉。',120,'全唐诗/poet.song.13000.json','["何必水周堂，翛然萬木凉。", "朋簪茲共樂，節物自迎商。", "巧笑承歡劇，新詞度曲長。", "驂鸞悲霧扇，泛蟻釂雲漿。", "並蒂榴房熟，連叢桂蘂香。", "人初投轄醉，客甚摻撾狂。", "鬢約寒鴉碧，衣輕舞蝶黄。", "流波閑任注，錯席豈依行。", "亹亹談寧倦，厭厭夜未央。", "良時誠可惜，清燕此無荒。"]'),
('e6a86758-2c2f-406a-a060-d61a471ff49b','客鄭遇曇穎自洛中東歸','梅堯臣','宋','宋诗','song-poetry','','[]','禪衣本壞色，不化洛陽塵。',48,'全唐诗/poet.song.13000.json','["禪衣本壞色，不化洛陽塵。", "獨有煙霞染，况將山水親。", "西風入關戍，宿雨過城闉。", "誰羨飄然跡，吾車亦已巾。"]'),
('37e4d94d-54de-4e98-9150-ec796da5df85','馬判官歸闕','梅堯臣','宋','宋诗','song-poetry','','[]','與君歸洛陽，仕宦頗相偶。',48,'全唐诗/poet.song.13000.json','["與君歸洛陽，仕宦頗相偶。", "荏苒遷歲時，徘徊樂文酒。", "今歸已及瓜，爲贈聊折柳。", "亦將隨計書，慘別寧嗟久。"]'),
('82869246-001c-401e-8622-4c66009ac31b','餞彭城公赴隨州龍門道上作','梅堯臣','宋','宋诗','song-poetry','','[]','零雨送車輪，初清遠陌塵。',48,'全唐诗/poet.song.13000.json','["零雨送車輪，初清遠陌塵。", "歸藩漢東國，遮道洛陽人。", "伊水照虹斾，楚山懷玉麟。", "征軒不可戀，梗淚返城闉。"]'),
('765dac46-3dce-40ed-8c23-a2c3e2e1d8b7','早行道中相逢','梅堯臣','宋','宋诗','song-poetry','','[]','黯黯雨雲晦，駸駸車馬繁。',24,'全唐诗/poet.song.13000.json','["黯黯雨雲晦，駸駸車馬繁。", "唯憂不及見，及見反無言。"]'),
('b40f83fe-0498-4dad-bf53-dc7c88a0d891','古意','梅堯臣','宋','宋诗','song-poetry','','[]','故人留雅曲，今與新人彈。',24,'全唐诗/poet.song.13000.json','["故人留雅曲，今與新人彈。", "新人聽不足，復使後人歡。"]'),
('6d467017-3d24-41df-a6b7-50a3e3db81d1','送弟良臣歸宣城','梅堯臣','宋','宋诗','song-poetry','','[]','喬木句溪邊，秋光幾曲連。',48,'全唐诗/poet.song.13000.json','["喬木句溪邊，秋光幾曲連。", "將歸三畝宅，遠寄下江船。", "伴爾唯征雁，悲余有暮蟬。", "親朋如見問，貧外似當年。"]');
